// DASHBOARD REFRESH TOP POSITION FIX - HR STEP 1
// Browser refresh can restore the previous scroll position before the dashboard
// finishes restoring the active workspace. Keep browser restoration manual so
// refresh always lands at the top of the restored HR workspace.
try {
  if ("scrollRestoration" in window.history) {
    window.history.scrollRestoration = "manual";
  }
} catch (error) {
  console.warn("Browser scroll restoration could not be set to manual.", error);
}
document.addEventListener("DOMContentLoaded", async () => {
  try {
    cacheDomElements();

    bindEvents();

    // PAYROLL WORKSPACE LAYOUT - HR/PAYROLL STANDARD STEP 2A
    // Keep the Payroll workspace in the correct operational order:
    // Payroll Overview first, then Create Payroll Record / Create Payroll Batch.
    // This avoids manually cutting a large HTML card and keeps existing IDs/events intact.
    alignPayrollWorkspaceCardOrder();

    // EMPLOYEE WORKSPACE LAYOUT - HR/PAYROLL STANDARD STEP 2C
    // Keep the People workspace in the correct operational order:
    // Summary first, Full Employee List next, then create/import actions.
    alignEmployeeWorkspaceCardOrder();

    // SETUP WORKSPACE FUNCTIONAL GROUPING - STEP 1A
    // Creates a lightweight visual header inside Setup.
    // These headers group existing cards by HR/payroll function without
    // recreating cards or changing any existing form IDs, events, or save/edit logic.
    function createSetupWorkspaceGroupHeader(id, title, description, iconClass) {
      let header = document.getElementById(id);

      if (!header) {
        header = document.createElement("section");
        header.id = id;
        header.className = "card dashboard-section-card mb-3";
      }

      header.innerHTML = `
    <div class="card-body p-4">
      <div class="d-flex align-items-start gap-3">
        <div class="rounded-circle bg-light border d-flex align-items-center justify-content-center flex-shrink-0"
          style="width: 40px; height: 40px;">
          <i class="${iconClass} text-primary"></i>
        </div>

        <div>
          <h2 class="section-heading h5 mb-1">${title}</h2>
          <p class="section-subtext mb-0">${description}</p>
        </div>
      </div>
    </div>
  `;

      return header;
    }

    // SETUP WORKSPACE FUNCTIONAL GROUPING - STEP 1B
    // Group Setup cards by function:
    // 1. Organization Setup
    // 2. Payroll Setup
    // 3. Payment Setup
    //
    // Existing cards are moved only. They are not recreated, so existing
    // collapse buttons, forms, event handlers, records tables, and Supabase
    // refresh logic remain intact.

    // PAYROLL WORKFLOW UX REPAIR - STEP 8A
    // Merge Statutory Deductions and Other Deductions into one visible
    // Deductions Setup card without merging their data, forms, save logic,
    // records tables, or calculation behaviour.
    //
    // HR/business behaviour:
    // - HR sees one deductions workspace.
    // - Statutory deductions remain separate from non-statutory deductions.
    // - Existing IDs remain intact, so save/edit/search/refresh/calculation
    //   logic continues to work.
    function mergePayrollDeductionSetupCards() {
      const statutoryPanel = state.dom.payrollStatutoryCardCollapse;
      const otherPanel = state.dom.payrollOtherDeductionCardCollapse;

      const statutoryCard = statutoryPanel?.closest(".dashboard-section-card");
      const otherCard = otherPanel?.closest(".dashboard-section-card");

      if (!statutoryCard || !otherCard || !statutoryPanel || !otherPanel) {
        return;
      }

      if (statutoryPanel.dataset.deductionsMerged === "true") {
        return;
      }

      const statutoryTitle = statutoryCard.querySelector(".section-heading");
      const statutorySubtext = statutoryCard.querySelector(".section-subtext");

      if (statutoryTitle) {
        statutoryTitle.textContent = "Deductions Setup";
      }

      if (statutorySubtext) {
        statutorySubtext.textContent =
          "Configure statutory and non-statutory deductions used during payroll finalisation.";
      }

      statutoryPanel.dataset.deductionsMerged = "true";

      statutoryPanel.insertAdjacentHTML(
        "afterbegin",
        `
          <!-- PAYROLL WORKFLOW UX REPAIR - STEP 8A
               Internal section label only. Existing statutory form/table IDs stay unchanged. -->
          <div class="border rounded-4 p-3 p-lg-4 bg-light-subtle mb-4">
            <div class="fw-bold">Statutory Deductions</div>
            <div class="small text-secondary">
              PAYE, WHT, employee pension, employer pension, and other statutory payroll deductions.
            </div>
          </div>
        `,
      );

      otherPanel.insertAdjacentHTML(
        "afterbegin",
        `
          <!-- PAYROLL WORKFLOW UX REPAIR - STEP 8A
               Internal section label only. Existing other deduction form/table IDs stay unchanged. -->
          <hr class="my-5" />
          <div class="border rounded-4 p-3 p-lg-4 bg-light-subtle mb-4">
            <div class="fw-bold">Other Deductions</div>
            <div class="small text-secondary">
              Union dues, cooperative deductions, salary advances, and other approved non-statutory deductions.
            </div>
          </div>
        `,
      );

      statutoryPanel.appendChild(otherPanel);

      // Remove only the old outer card shell/header. The Other Deductions
      // panel itself has already been moved into the new combined card.
      otherCard.remove();
    }

    function alignSetupWorkspaceCardOrder() {
      const setupSection = state.dom.hrSetupSection;
      const setupLandingCard = state.dom.hrSetupLandingCard;

      if (!setupSection || !setupLandingCard) return;

      const organizationSetupHeader = createSetupWorkspaceGroupHeader(
        "setupOrganizationGroupHeader",
        "Organization Setup",
        "Maintain company identity, departments, job titles, and organisation-level HR/payroll defaults.",
        "bi bi-building-gear",
      );

      const payrollSetupHeader = createSetupWorkspaceGroupHeader(
        "setupPayrollGroupHeader",
        "Payroll Rules & Deductions",
        "Maintain allowance components, statutory deductions, other deductions, and employee-specific payroll overrides.",
        "bi bi-sliders",
      );

      const paymentSetupHeader = createSetupWorkspaceGroupHeader(
        "setupPaymentGroupHeader",
        "Payment Setup",
        "Maintain approved banks and employee bank accounts used for payroll payment processing.",
        "bi bi-bank",
      );

      // HRP-85 - STEP 1E
      // Email integration configuration belongs under Setup, not Payroll operations.
      // HRP-85 - STEP 1E CLEANUP
      // Keep the Jira reference internal. The visible Setup group should use
      // business-friendly wording, not implementation or ticket labels.
      const communicationSetupHeader = createSetupWorkspaceGroupHeader(
        "setupCommunicationGroupHeader",
        "Email / Communication Setup",
        "Manage approved validation recipients and review email delivery health.",
        "bi bi-envelope-check",
      );

      const organizationCards = [
        state.dom.organizationSettingsCardCollapse?.closest(".dashboard-section-card"),
      ].filter(Boolean);

      const payrollSetupCards = [
        // PAYROLL WORKFLOW UX REPAIR - STEP 1
        // Employee salary setup is employee/payroll preparation work, so it
        // now lives in Payroll beside Run Payroll instead of inside Setup.
        // Leave allowance/deduction rule cards in Setup for now until the
        // wider payroll workflow is repaired step-by-step.
        state.dom.payrollAllowanceCardCollapse?.closest(".dashboard-section-card"),
        state.dom.payrollStatutoryCardCollapse?.closest(".dashboard-section-card"),
        state.dom.payrollOtherDeductionCardCollapse?.closest(".dashboard-section-card"),
        state.dom.payrollEmployeeOverrideCardCollapse?.closest(".dashboard-section-card"),
      ].filter(Boolean);

      const paymentSetupCards = [
        state.dom.bankDirectoryCardCollapse?.closest(".dashboard-section-card"),
        state.dom.employeeBankDetailsCardCollapse?.closest(".dashboard-section-card"),
      ].filter(Boolean);

      // HRP-85 - STEP 1E
      // Keep the Email Integration card in the final Setup group.
      const communicationSetupCards = [
        state.dom.hrp85EmailIntegrationCard,
      ].filter(Boolean);

      [
        organizationSetupHeader,
        ...organizationCards,
        payrollSetupHeader,
        ...payrollSetupCards,
        paymentSetupHeader,
        ...paymentSetupCards,
        communicationSetupHeader,
        ...communicationSetupCards,
      ].forEach((card) => {
        card.classList.add("mb-4");
        setupSection.appendChild(card);
      });

      // PAYROLL WORKFLOW UX REPAIR - STEP 8A
      // After the Setup cards have been placed in order, merge the two
      // deductions cards visually into one Deductions Setup card.
      mergePayrollDeductionSetupCards();
    }

    // WORKSPACE REARRANGEMENT - STEP 1D
    // Move setup/master-data cards into the new Setup workspace before
    // default card collapse runs, so collapse state stays consistent.
    alignSetupWorkspaceCardOrder();

    // DESCRIPTION ITEM 4 - STEP 2B
    // Start long HR/payroll working cards collapsed by default.
    // This keeps the workspace clean while preserving all existing
    // save/edit flows that reopen cards when needed.
    collapseDashboardWorkingCardsByDefault();

    const access = await window.SessionManager.protectPage("hr");

    if (!access) {
      return;
    }

    state.currentUser = access.session.user;
    state.currentProfile = access.profile;

    await loadLatestHrProfile();

    renderHrProfile(state.currentProfile, access.session.user);
    resetEmployeeForm();

    // DASHBOARD REFRESH TOP POSITION FIX - HR STEP 1
    // Restore the remembered workspace early and force the page to the top.
    // Do this before the long async HR/payroll data refreshes continue.
    restoreHrWorkspaceAfterRefresh();

    // SUBMIT PAYROLL - DESCRIPTION ITEM 1 - STEP 5
    // Build the Pay Cycle dropdown dynamically before resetting the payroll form.
    populatePayrollPayCycleOptions();

    resetPayrollForm();

    // =========================================================
    // DESCRIPTION ITEM 1
    // Initialise the new payroll master workspace as part of
    // HR payroll page load.
    // =========================================================
    // =========================================================
    // DESCRIPTION ITEM 2
    // Initialise allowance workspace as part of HR payroll load.
    // =========================================================
    await refreshEmployeeWorkspace();

    // EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
    // Load employee-submitted correction requests after employees are loaded,
    // so the queue can resolve employee names from state.employees.
    await refreshProfileCorrectionRequestsWorkspace();

    // DYNAMIC EDUCATION SUGGESTIONS - STEP 1A
    // Load saved schools/courses into the Education datalists after HR access
    // is confirmed and Supabase is available.
    await refreshEducationSuggestionLists();

    // DYNAMIC EDUCATION SUGGESTIONS - STEP 1C
    // Replace the browser-native datalist popup with a compact styled panel
    // so long school/course suggestion lists do not show a heavy scrollbar.
    bindEducationSuggestionPanels();

    // MANAGE ORGANIZATION CARD - STEP 3
    // Load the single organization settings record after HR access is confirmed.
    await refreshOrganizationSettingsWorkspace();

    // HR DASHBOARD ROLE RESTRICTIONS - STEP 2C
    // Organization Settings are now loaded, so apply read-only controls for
    // Payroll, Auditor, QA, and custom HR-routed roles.
    applyHrOrganizationSetupAccessControls();

    // ORGANIZATION HR SETUP VALUES - STEP 3
    // Load HR-managed Departments and Job Titles before employee/payroll forms
    // need dropdown values. This is read-only for now.
    await refreshOrganizationHrSetupValues();

    // HR DASHBOARD ROLE RESTRICTIONS - STEP 2C
    // Department and Job Title records are now loaded/rendered, so re-apply
    // Organization Setup restrictions after the setup tables are rebuilt.
    applyHrOrganizationSetupAccessControls();

    // DESCRIPTION ITEM 3 - STEP 2A-4
    // Load controlled Payroll Grade / Level values before Payroll Master Data,
    // so the Payroll Master dropdown and edit mode can use real setup records.
    await loadPayrollGradeLevels();

    await refreshPayrollMasterWorkspace();
    await refreshPayrollAllowanceWorkspace();

    // DESCRIPTION ITEM 3 - STEP 2C
    // Load saved statutory deductions after Payroll Master Records are available,
    // because the records table resolves employee and grade context from Payroll Master.
    await refreshPayrollStatutoryWorkspace();

    // DESCRIPTION ITEM 4 - STEP 3
    // Load saved Other Deductions after Payroll Master Records are available.
    // Other Deductions are linked to Payroll Master Data in the same standard
    // payroll setup pattern as allowances and statutory deductions.
    await refreshPayrollOtherDeductionWorkspace();

    // DESCRIPTION ITEM 5 - STEP 3
    // Load employee-specific payroll overrides after Payroll Master Records
    // are available, because overrides are linked to Payroll Master Data.
    await refreshPayrollEmployeeOverrideWorkspace();

    // HR DASHBOARD ROLE RESTRICTIONS - STEP 2D-1
    // Payroll Setup cards are now loaded/rendered, so lock setup maintenance
    // for Auditor, QA, and custom HR-routed roles.
    // Payroll and Payroll Manager remain allowed to maintain Payroll Setup.
    applyHrPayrollSetupAccessControls();

    await refreshPayrollWorkspace();

    // PAYROLL EMAIL STATUS - STEP 2F-2B
    // Load payslip email status as part of Payroll workspace startup.
    // This fixes the parked issue where the badges stayed at 0 until HR
    // manually clicked Refresh Status.
    await refreshPayslipEmailLogs();

    // HR DASHBOARD ROLE RESTRICTIONS - STEP 2E-1
    // Payroll Operations are now loaded/rendered, so lock create/edit/export/send
    // actions for Auditor, QA, and custom HR-routed roles.
    applyHrPayrollOperationsAccessControls();

    // BANK DIRECTORY - STEP 7A
    // Load saved banks from Supabase so Bank Directory records survive page refresh.
    await refreshBankDirectoryWorkspace();

    // EMPLOYEE BANK DETAILS - STEP 8A
    // Load saved employee bank details on page start after employees and banks
    // are already available, so the Employee Bank Records table is populated
    // when HR opens the payroll workspace.
    await refreshEmployeeBankDetailsWorkspace();

    // HR DASHBOARD ROLE RESTRICTIONS - STEP 2D-2
    // Payment Setup is now loaded/rendered, so lock Bank Directory and Employee
    // Bank Details maintenance for Auditor, QA, and custom HR-routed roles.
    // HR/Payroll roles remain allowed to maintain payment setup.
    applyHrPaymentSetupAccessControls();

    // HRP-85 - STEP 1E
    // Load approved Bex recipients and recent delivery logs for the
    // Email / Communication Setup card. This does not send payslips and
    // does not load salary, deduction, or bank data.
    await refreshHrp85EmailIntegrationWorkspace();
    // HR DASHBOARD ROLE RESTRICTIONS - STEP 2C
    // Email / Communication Setup is review-only for non-HR maintenance roles.
    applyHrCommunicationSetupAccessControls();

    // HR DASHBOARD ROLE RESTRICTIONS - STEP 2B
    // Keep employee editing blocked for Payroll, Auditor, QA, and custom
    // HR-routed roles. These roles may review People records but not maintain them.
    window.hrEditEmployee = (employeeId) => {
      if (!canCurrentUserMaintainPeopleData()) {
        showHrPeopleAccessDeniedMessage();
        return;
      }

      startEmployeeEdit(employeeId);
    };

    // HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 1A
    // Expose read-only filled-form review actions used by the Employee List
    // and the read-only modal. This must sit beside the other global HR row
    // action handlers because the employee table uses inline onclick handlers.
    window.hrViewEmployeeFilledForm = viewEmployeeFilledForm;
    window.hrCloseEmployeeFilledForm = closeEmployeeFilledFormModal;

    // MANAGER ROLE ASSIGNMENT
    // Expose the manager role toggle for the employee list action button.
    window.hrToggleManagerRole = (employeeId) => {
      toggleEmployeeManagerRole(employeeId);
    };

    // EMPLOYEE BIODATA COMPLETION - STEP 6C-4C
    // Expose staged education remove action for the Saved Education Records list.
    window.hrRemoveEmployeeEducationRecord = (recordIndex) => {
      removeEmployeeEducationRecordAtIndex(recordIndex);
    };

    // EMPLOYEE BIODATA COMPLETION - STEP 6D-2
    // Expose staged beneficiary/dependant remove action for the list.
    window.hrRemoveEmployeeDependantRecord = (recordIndex) => {
      removeEmployeeDependantRecordAtIndex(recordIndex);
    };

    // DESCRIPTION ITEM 9 - STEP 1
    // Expose payroll selection toggle for the checkbox column
    // in the Full Employee List table.
    window.hrToggleEmployeePayrollSelection = (employeeId, isChecked) => {
      toggleEmployeePayrollSelection(employeeId, isChecked);
    };

    // HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1B
    // Expose row checkbox selection from the Batch Payroll Review table.
    window.hrToggleBatchPayrollReviewEmployeeSelection = (employeeId, isChecked) => {
      toggleBatchPayrollReviewEmployeeSelection(employeeId, isChecked);
    };

    window.hrOpenEmployeeDocument = async (documentId) => {
      await openEmployeeDocument(documentId);
    };

    window.hrEditPayrollRecord = (payrollId) => {
      startPayrollEdit(payrollId);
    };

    // DESCRIPTION ITEM 4 - STEP 7
    // Expose payslip preview action for the Payroll Records table.
    // This only opens a review modal for finalised payroll records.
    window.hrPreviewPayslipRecord = async (payrollId) => {
      await openPayslipPreview(payrollId);
    };

    // PAYROLL EMAIL DELIVERY - STEP 2F-2E
    // Expose row checkbox selection for Payroll Records.
    // This lets HR send payslips only for deliberately selected records.
    window.hrTogglePayslipEmailPayrollRecordSelection = (payrollRecordId, isChecked) => {
      togglePayslipEmailPayrollRecordSelection(payrollRecordId, isChecked);
    };

    // =========================================================
    // DESCRIPTION ITEM 2
    // Expose allowance edit handler for table action buttons.
    // =========================================================
    window.hrEditPayrollAllowanceRecord = (allowanceId) => {
      startPayrollAllowanceEdit(allowanceId);
    };

    // DESCRIPTION ITEM 3 - STEP 2D
    // Expose statutory deduction edit handler for the records table action button.
    window.hrEditPayrollStatutoryRecord = (statutoryDeductionId) => {
      startPayrollStatutoryEdit(statutoryDeductionId);
    };

    // DESCRIPTION ITEM 4 - STEP 4
    // Expose Other Deduction edit handler for the records table action button.
    // This lets HR maintain an existing union, cooperative, salary advance,
    // or other deduction without creating duplicate deduction setup rows.
    window.hrEditPayrollOtherDeductionRecord = (otherDeductionId) => {
      startPayrollOtherDeductionEdit(otherDeductionId);
    };

    // DESCRIPTION ITEM 5 - STEP 4
    // Expose Employee Payroll Override edit handler for the records table.
    // This lets HR maintain an existing override instead of creating duplicates.
    window.hrEditPayrollEmployeeOverrideRecord = (overrideId) => {
      startPayrollEmployeeOverrideEdit(overrideId);
    };
    // =========================================================
    // DESCRIPTION ITEM 1
    // Expose payroll master edit handler for table action buttons.
    // =========================================================
    window.hrEditPayrollMasterRecord = (payrollMasterId) => {
      startPayrollMasterEdit(payrollMasterId);
    };

    // ORGANIZATION HR SETUP VALUES - STEP 4A
    // Expose Department edit action for the Department Records table.
    window.hrEditOrganizationDepartmentRecord = (departmentId) => {
      startOrganizationDepartmentEdit(departmentId);
    };

    // ORGANIZATION HR SETUP VALUES - STEP 4B-4
    // Expose Job Title edit action for the Job Title Records table.
    window.hrEditOrganizationJobTitleRecord = (jobTitleId) => {
      startOrganizationJobTitleEdit(jobTitleId);
    };

    // BANK DIRECTORY - STEP 8
    // Expose Bank Directory edit action for the table button.
    window.hrEditBankDirectoryRecord = (bankId) => {
      startBankDirectoryEdit(bankId);
    };

    // EMPLOYEE BANK DETAILS - STEP 9
    // Expose Employee Bank Details edit action for the table button.
    window.hrEditEmployeeBankDetailsRecord = (employeeBankDetailsId) => {
      startEmployeeBankDetailsEdit(employeeBankDetailsId);
    };

  } catch (error) {
    console.error("Error initialising HR dashboard:", error);

    showPageAlert(
      "danger",
      error.message ||
      "An unexpected error occurred while loading the HR dashboard.",
    );
  }
});

