function getSupabaseClient() {
  if (!window.supabaseClient) {
    throw new Error(
      "Supabase client is not available on window.supabaseClient.",
    );
  }
  return window.supabaseClient;
}

// HRP-80 - TENANT DATA SEGMENTATION - STEP 7C
// Read the logged-in user's validated tenant context from local storage.
// This is intentionally read-only here; login remains responsible for validation.
function getCurrentTenantContext() {
  try {
    const rawValue = localStorage.getItem(TENANT_CONTEXT_STORAGE_KEY);
    if (!rawValue) return null;

    const parsedValue = JSON.parse(rawValue);

    if (!parsedValue?.tenantId || !parsedValue?.tenantCode) {
      return null;
    }

    return parsedValue;
  } catch (error) {
    console.error("Invalid tenant context cache:", error);
    return null;
  }
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1
// Only these top-level HR workspaces are safe to restore after browser refresh.
function isValidHrWorkspaceKey(workspace = "") {
  return ["profile", "employees", "setup", "payroll", "selfservice"].includes(
    String(workspace || "").trim(),
  );
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1
// Build a scoped memory key so one HR user's Pinehearst workspace state
// cannot bleed into another user or company workspace.
function getHrWorkspaceMemoryKey() {
  const tenantContext = getCurrentTenantContext();

  const userId = String(state.currentUser?.id || "anonymous").trim();
  const tenantId = String(
    tenantContext?.tenantId ||
    state.currentProfile?.tenant_id ||
    "no-tenant",
  ).trim();

  return `${HR_DASHBOARD_WORKSPACE_MEMORY_PREFIX}:${userId}:${tenantId}`;
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1
// Save only the active workspace key. Do not store employee, payroll,
// bank, salary, payslip, or form data in browser storage.
// In-memory fallback — survives within the page session even when
// sessionStorage is blocked by browser tracking prevention.
let _hrWorkspaceInMemory = null;

function rememberHrWorkspace(workspace = "") {
  if (!isValidHrWorkspaceKey(workspace)) return;

  _hrWorkspaceInMemory = workspace;

  try {
    sessionStorage.setItem(getHrWorkspaceMemoryKey(), workspace);
  } catch (error) {
    console.warn("HR workspace memory could not be saved.", error);
  }
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1
// Read the last workspace for this signed-in HR user and company only.
// PAYSLIP EMAIL DEEP LINK ROUTING - STEP 1B
// Resolve only safe HR dashboard workspace requests from the URL.
// This allows payslip email login to open HR > My Self-Service without
// storing payroll IDs, salary values, bank details, or employee IDs in the URL.
function getRequestedHrWorkspaceFromUrl() {
  try {
    const params = new URLSearchParams(window.location.search || "");

    const requestedWorkspace = String(params.get("workspace") || "")
      .trim()
      .toLowerCase();

    const requestedSection = String(params.get("section") || "")
      .trim()
      .toLowerCase();

    if (requestedWorkspace === "selfservice" && requestedSection === "payroll") {
      return "selfservice";
    }

    if (isValidHrWorkspaceKey(requestedWorkspace)) {
      return requestedWorkspace;
    }
  } catch (error) {
    console.warn("HR workspace URL request could not be resolved.", error);
  }

  return "";
}

function getRememberedHrWorkspace() {
  // PAYSLIP EMAIL DEEP LINK ROUTING - STEP 1B
  // URL request takes priority over remembered workspace so an email link
  // can deliberately open HR Self-Service > Payroll after login.
  const requestedWorkspace = getRequestedHrWorkspaceFromUrl();

  if (isValidHrWorkspaceKey(requestedWorkspace)) {
    return requestedWorkspace;
  }

  // Prefer in-memory value (set when user clicks a tab this session).
  // Falls back to sessionStorage for page refreshes.
  if (isValidHrWorkspaceKey(_hrWorkspaceInMemory)) return _hrWorkspaceInMemory;

  try {
    const workspace = sessionStorage.getItem(getHrWorkspaceMemoryKey());

    return isValidHrWorkspaceKey(workspace)
      ? workspace
      : "profile";
  } catch (error) {
    console.warn("HR workspace memory could not be read.", error);
    return "profile";
  }
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1
// Clear remembered workspace on logout so the next login starts from Profile.
function clearRememberedHrWorkspace() {
  try {
    sessionStorage.removeItem(getHrWorkspaceMemoryKey());
  } catch (error) {
    console.warn("HR workspace memory could not be cleared.", error);
  }
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1B
// Hide workspace sections during startup so the browser does not briefly show
// Profile before the remembered workspace is restored after refresh.
function suppressHrWorkspaceFlashDuringStartup() {
  // DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1C
  // The HTML body now starts with hr-workspace-booting before first paint.
  // Keep this as a defensive fallback in case the body class is missing.
  document.body?.classList.add("hr-workspace-booting");

  [
    state.dom.hrProfileSection,
    state.dom.hrEmployeesSection,
    state.dom.hrSetupSection,
    state.dom.hrPayrollSection,
  ].forEach((section) => {
    section?.classList.add("d-none");
  });
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1D
// Set the remembered workspace while the restore overlay is still active.
// This prevents HR seeing the Profile tab or another tab flash during refresh.
function prepareRestoredHrWorkspaceDuringStartup() {
  restoreHrWorkspaceAfterRefresh();
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1D
// Reveal the dashboard only after startup work has had a chance to complete.
// HR sees one controlled restore state instead of tab/content flicker.
function revealRestoredHrWorkspace() {
  // DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1D CORRECTION
  // Release the first-paint gate immediately after the remembered workspace
  // has been selected. Do not wait for employee/payroll/setup data loads.
  document.body?.classList.remove("hr-workspace-booting");

  window.scrollTo({
    top: 0,
    behavior: "auto",
  });

  updateBackToTopButtonVisibility();
}

// DASHBOARD REFRESH TOP POSITION FIX - HR STEP 1
// Force the dashboard to the true page top without smooth scrolling.
// This is used only for refresh restore, not normal in-page navigation.
function forceHrDashboardToTopAfterRefresh() {
  window.scrollTo({
    top: 0,
    left: 0,
    behavior: "auto",
  });

  document.documentElement.scrollTop = 0;
  document.body.scrollTop = 0;

  updateBackToTopButtonVisibility();
}

// DASHBOARD WORKSPACE MEMORY - HR PILOT STEP 1
// Browser refresh should reopen the last workspace, then place HR at the top.
// Fresh login has no remembered key, so it naturally opens Profile.
function restoreHrWorkspaceAfterRefresh() {
  const workspace = getRememberedHrWorkspace();

  switchHrWorkspace(workspace);

  // DASHBOARD REFRESH TOP POSITION FIX - HR STEP 1
  // Run immediately and across the next paints because browsers can restore
  // scroll position after initial DOM work, especially on long HR/payroll pages.
  forceHrDashboardToTopAfterRefresh();

  window.requestAnimationFrame(() => {
    forceHrDashboardToTopAfterRefresh();

    window.requestAnimationFrame(() => {
      forceHrDashboardToTopAfterRefresh();
    });
  });

  window.setTimeout(forceHrDashboardToTopAfterRefresh, 0);
  window.setTimeout(forceHrDashboardToTopAfterRefresh, 150);
}

// HRP-80 - TENANT DATA SEGMENTATION - STEP 7C
// HR dashboard users are tenant-based users. They must have a validated
// tenant context before creating or updating tenant-owned employee records.
function getRequiredTenantIdForHrEmployeeData() {
  const tenantContext = getCurrentTenantContext();
  const tenantId = String(tenantContext?.tenantId || "").trim();

  if (!tenantId) {
    throw new Error(
      "Tenant context was not found. Please log out and sign in again with the correct Company/Tenant ID.",
    );
  }

  return tenantId;
}

// HRP-80 - TENANT DATA SEGMENTATION - STEP 7D
// Apply the logged-in tenant filter to Supabase queries that read HR employee data.
// This keeps HR users scoped to their own company workspace.
function applyCurrentTenantFilter(query) {
  const tenantId = getRequiredTenantIdForHrEmployeeData();

  return query.eq("tenant_id", tenantId);
}

// HRP-80 - SETUP TENANT SAFETY FIX
// These helpers keep Setup workspace data scoped to the signed-in company workspace.
// The Employee table is already tenant-filtered, so employee-linked setup records
// must be filtered through the current tenant's employee ids.
function getCurrentTenantEmployeeIdSetForSetupTables() {
  return new Set(
    (Array.isArray(state.employees) ? state.employees : [])
      .map((employee) => String(employee.id || "").trim())
      .filter(Boolean),
  );
}

// HRP-80 - SETUP TENANT SAFETY FIX
// Supabase .in() needs an array, while render/filter checks need a Set.
function getCurrentTenantEmployeeIdsForSetupTables() {
  return Array.from(getCurrentTenantEmployeeIdSetForSetupTables());
}

// HRP-80 - SETUP TENANT SAFETY FIX
// Allowances, statutory deductions, other deductions, and overrides are linked
// through Payroll Master Records, so they must inherit the tenant boundary from
// the already-filtered Payroll Master list.
function getCurrentTenantPayrollMasterIdSetForSetupTables() {
  return new Set(
    (Array.isArray(state.payrollMasterRecords) ? state.payrollMasterRecords : [])
      .map((record) => String(record.id || "").trim())
      .filter(Boolean),
  );
}

// HRP-80 - SETUP TENANT SAFETY FIX
// Supabase .in() needs an array version of the current workspace Payroll Master ids.
function getCurrentTenantPayrollMasterIdsForSetupTables() {
  return Array.from(getCurrentTenantPayrollMasterIdSetForSetupTables());
}

// HRP-80 - SETUP TENANT SAFETY FIX
// Email validation records are not employee-linked, so only rows explicitly tagged
// with the current tenant should be shown in this workspace.
// Untagged/global rows are hidden to prevent cross-company leakage.
function isHrp85RecordForCurrentTenant(record = {}) {
  const tenantId = getRequiredTenantIdForHrEmployeeData();

  return String(record.tenant_id || "").trim() === tenantId;
}

// HRP-80 - PAYROLL TENANT SAFETY FIX
// Payroll views/logs are tied to employees, so use the already tenant-filtered
// employee list as the safe boundary for Payroll Records and Payslip Email Status.
// This prevents one company workspace from seeing another company's payroll rows.
function getCurrentTenantEmployeeIdSet() {
  return new Set(
    (Array.isArray(state.employees) ? state.employees : [])
      .map((employee) => String(employee.id || "").trim())
      .filter(Boolean),
  );
}

function getCurrentTenantEmployeeIds() {
  return Array.from(getCurrentTenantEmployeeIdSet());
}

function isRecordForCurrentTenantEmployee(record = {}) {
  const currentTenantEmployeeIds = getCurrentTenantEmployeeIdSet();
  const employeeId = String(
    record.employee_id ||
    record.employees?.id ||
    "",
  ).trim();

  return Boolean(employeeId && currentTenantEmployeeIds.has(employeeId));
}

function getCurrentTenantIdForCompanyIdentity() {
  // ADMIN COMPANY IDENTITY WIRING - STEP 1M-B
  // Prefer the validated login tenant context, then fall back to the latest
  // signed-in profile tenant_id. This keeps HR company identity tied to Admin.
  const tenantContext = getCurrentTenantContext();

  return String(
    tenantContext?.tenantId ||
    state.currentProfile?.tenant_id ||
    "",
  ).trim();
}

async function loadCurrentTenantCompanyForHr() {
  // ADMIN COMPANY IDENTITY WIRING - STEP 1M-C FINAL
  // Admin > Companies is the source of truth for the company display name.
  // First use the safe Supabase RPC so HR does not need direct SELECT access
  // to the tenants table. Direct tenant lookup remains as a fallback only.
  const supabase = getSupabaseClient();

  const { data: rpcData, error: rpcError } = await supabase.rpc(
    "get_current_tenant_company_for_hr",
  );

  if (!rpcError) {
    const resolvedCompany = Array.isArray(rpcData) ? rpcData[0] : rpcData;

    if (resolvedCompany?.company_name) {
      state.currentTenantCompany = resolvedCompany;
      return state.currentTenantCompany;
    }
  } else {
    console.warn("Admin company identity RPC could not be used.", rpcError);
  }

  // ADMIN COMPANY IDENTITY WIRING - STEP 1M-C FINAL FALLBACK
  // Keep the previous browser-side lookup as a fallback for environments
  // where tenants are readable to the logged-in HR user.
  const tenantContext = getCurrentTenantContext();

  const uniqueCleanValues = (values = []) =>
    Array.from(
      new Set(
        values
          .map((value) => String(value || "").trim())
          .filter(Boolean),
      ),
    );

  const tenantIdCandidates = uniqueCleanValues([
    state.currentProfile?.tenant_id,
    tenantContext?.tenantId,
  ]);

  const tenantCodeCandidates = uniqueCleanValues([
    state.currentProfile?.tenant_code,
    tenantContext?.tenantCode,
  ]);

  const selectColumns = "id, company_name, tenant_code, status, updated_at";

  for (const tenantId of tenantIdCandidates) {
    const { data, error } = await supabase
      .from("tenants")
      .select(selectColumns)
      .eq("id", tenantId)
      .limit(1)
      .maybeSingle();

    if (error) {
      console.warn("Admin company lookup by tenant_id failed.", error);
      continue;
    }

    if (data?.company_name) {
      state.currentTenantCompany = data;
      return state.currentTenantCompany;
    }
  }

  for (const tenantCode of tenantCodeCandidates) {
    const { data, error } = await supabase
      .from("tenants")
      .select(selectColumns)
      .ilike("tenant_code", tenantCode)
      .limit(1)
      .maybeSingle();

    if (error) {
      console.warn("Admin company lookup by tenant_code failed.", error);
      continue;
    }

    if (data?.company_name) {
      state.currentTenantCompany = data;
      return state.currentTenantCompany;
    }
  }

  state.currentTenantCompany = null;

  console.warn("Admin company identity could not be resolved for HR.", {
    tenantIdCandidates,
    tenantCodeCandidates,
  });

  return null;
}

function getAdminControlledOrganizationName() {
  // ADMIN COMPANY IDENTITY WIRING - STEP 1M-C FINAL
  // Do not fall back to organization_settings.organization_name here.
  // That field may contain the old HR snapshot, such as Pinehearst.
  // Company display identity must come from Admin > Companies only.
  return (
    String(state.currentTenantCompany?.company_name || "").trim() ||
    "Organization not set"
  );
}

// ALPATECH TENANT BRANDING - STEP 1E
// Detect only the Alpatech tenant/company workspace.
// This must stay tenant-scoped so Alpatech branding never leaks into
// other companies renting the same HR/payroll app.
function isCurrentTenantAlpatechWorkspace() {
  const companyName = String(state.currentTenantCompany?.company_name || "")
    .trim()
    .toLowerCase();

  const tenantCode = String(
    state.currentTenantCompany?.tenant_code ||
    getCurrentTenantContext()?.tenantCode ||
    state.currentProfile?.tenant_code ||
    "",
  )
    .trim()
    .toLowerCase();

  return (
    companyName.includes("alpatech") ||
    tenantCode.includes("alpatech")
  );
}

// ALPATECH TENANT BRANDING - STEP 1E
// Browser tab icon only.
// Browsers control the rendered favicon size, so this uses a tighter,
// fuller Alpatech flame asset to make the icon appear larger inside
// the browser's fixed favicon slot.
function applyTenantFaviconBranding() {
  const favicon = document.querySelector("link[rel~='icon']");

  if (!favicon) return;

  if (isCurrentTenantAlpatechWorkspace()) {
    favicon.type = "image/png";
    favicon.href = "assets/alpatech-favicon-large.png";
    return;
  }

  favicon.type = "image/x-icon";
  favicon.href = "assets/favicon.png";
}

// ALPATECH TENANT BRANDING - STEP 1F
// Tenant-scoped workspace shell branding.
// This changes only the visible dashboard shell after the signed-in company
// has been resolved. It does not change employee data, payroll logic,
// payslip logic, CSV export, email delivery, Supabase queries, or role access.
function applyTenantWorkspaceShellBranding() {
  const sidebarBrand = document.getElementById("tenantSidebarBrand");
  const heroBrandingBlock = document.getElementById("tenantHeroBrandingBlock");

  if (isCurrentTenantAlpatechWorkspace()) {
    document.body?.classList.add("alpatech-workspace");
    document.title = "Alpatech HR & Payroll | BexHR";

    if (sidebarBrand) {
      sidebarBrand.className = "bexhr-sidebar-brand alpatech-sidebar-brand";
      sidebarBrand.innerHTML = `
        <!-- ALPATECH TENANT BRANDING - STEP 1G
             Flame icon only. CSS renders the ALPATECH wordmark beside it. -->
        <span class="alpatech-brand-mark" aria-hidden="true">
          <img src="assets/alpatech-flame.png" alt="" />
        </span>
      `;
    }

    if (heroBrandingBlock) {
      heroBrandingBlock.innerHTML = `
        <!-- ALPATECH TENANT BRANDING - STEP 1G
             Brand only the signed-in Alpatech workspace shell.
             The top row gives the logo and workspace badge breathing room. -->
        <div class="alpatech-hero-content">
          <div class="alpatech-hero-kicker-row">
            <div class="alpatech-hero-brand" aria-label="Alpatech HR and Payroll Workspace">
              <span class="alpatech-brand-mark alpatech-hero-mark" aria-hidden="true">
                <img src="assets/alpatech-flame.png" alt="" />
              </span>
              <span class="alpatech-brand-wordmark">ALPATECH</span>
            </div>

            <div class="hero-badge alpatech-hero-badge">
              <i class="bi bi-truck"></i>
              HR & Payroll Workspace
            </div>
          </div>

          <h1 class="display-6 fw-bold mb-2">People Operations Dashboard</h1>
          <p class="mb-0 alpatech-hero-copy">
            Manage Alpatech employee records, supporting documents, payroll processing, payslips, and payment exports in one place.
          </p>
        </div>
      `;
    }

    // ALPATECH TENANT BRANDING - STEP 1G
    // Reveal the tenant-specific brand once the real Alpatech shell has been applied.
    document.body?.classList.remove("alpatech-branding-resolving");
    return;
  }

  // ALPATECH TENANT BRANDING - STEP 1F
  // Reset shared app branding for every non-Alpatech tenant.
  document.body?.classList.remove("alpatech-workspace", "alpatech-branding-resolving");
  document.title = "HR Dashboard | BexHR";

  if (sidebarBrand) {
    sidebarBrand.className = "bexhr-sidebar-brand";
    sidebarBrand.innerHTML = `
      <span class="hr-brand-mark" style="width:34px;height:34px;font-size:0.8rem;">HR</span>
    `;
  }

  if (heroBrandingBlock) {
    heroBrandingBlock.innerHTML = `
      <div class="hero-badge">
        <i class="bi bi-people"></i>
        HR Workspace
      </div>
      <h1 class="display-6 fw-bold mb-2">HR Dashboard</h1>
      <p class="mb-0" style="max-width: 760px">
        Manage your HR profile, employee records, supporting documents, and payroll records in one place.
      </p>
    `;
  }
}


