// DESCRIPTION ITEM 1 - STEP 5
// Simple reusable collapse toggle for HR dashboard cards.
// Uses d-none so we do not depend on external collapse plugins.
function bindCardCollapseToggle(button, panel) {
  if (!button || !panel) return;

  button.addEventListener("click", () => {
    const isNowHidden = panel.classList.toggle("d-none");
    button.setAttribute("aria-expanded", String(!isNowHidden));

    const icon = button.querySelector("i");
    const label = button.querySelector("span");

    if (icon) {
      icon.className = isNowHidden
        ? "bi bi-chevron-down me-2"
        : "bi bi-chevron-up me-2";
    }

    if (label) {
      label.textContent = isNowHidden ? "Expand" : "Collapse";
    }
  });
}

// REMOVE GRADE LEVEL FIELD FROM EMPLOYEE DATA - STEP 3
// Programmatic version of the existing card collapse behaviour.
// This lets save/edit flows open or close cards without duplicating UI logic.
function setDashboardCardExpanded(button, panel, shouldExpand) {
  if (!button || !panel) return;

  panel.classList.toggle("d-none", !shouldExpand);
  button.setAttribute("aria-expanded", String(shouldExpand));

  const icon = button.querySelector("i");
  const label = button.querySelector("span");

  if (icon) {
    icon.className = shouldExpand
      ? "bi bi-chevron-up me-2"
      : "bi bi-chevron-down me-2";
  }

  if (label) {
    label.textContent = shouldExpand ? "Collapse" : "Expand";
  }
}

// DESCRIPTION ITEM 4 - STEP 2B
// Central list of long HR/payroll working cards that can collapse.
// Keeping the pairs in one place prevents duplicate collapse logic
// and keeps the dashboard behaviour consistent.
function getDashboardWorkingCardPairs() {
  return [
    [state.dom.toggleOrganizationSettingsCardBtn, state.dom.organizationSettingsCardCollapse],
    [state.dom.toggleEmployeeListCardBtn, state.dom.employeeListCardCollapse],

    // HR PROFILE CORRECTION REQUESTS UX - STEP 1B
    // Add Profile Correction Requests to the shared HR card behaviour.
    // Double-click works on the card shell/summary/blank space, but the existing
    // double-click guard ignores table content, buttons, links, selects, inputs,
    // labels, and textareas so HR does not accidentally collapse while reviewing
    // or saving a request decision.
    [state.dom.toggleProfileCorrectionRequestsBtn, state.dom.profileCorrectionRequestsCollapse],
    [state.dom.toggleEmployeeFormCardBtn, state.dom.employeeFormCardCollapse],
    [state.dom.toggleBankDirectoryCardBtn, state.dom.bankDirectoryCardCollapse],
    [state.dom.toggleEmployeeBankDetailsCardBtn, state.dom.employeeBankDetailsCardCollapse],
    [state.dom.togglePayrollMasterCardBtn, state.dom.payrollMasterCardCollapse],
    [state.dom.togglePayrollAllowanceCardBtn, state.dom.payrollAllowanceCardCollapse],
    [state.dom.togglePayrollStatutoryCardBtn, state.dom.payrollStatutoryCardCollapse],

    // PAYROLL WORKFLOW UX REPAIR - STEP 8A
    // Other Deductions now lives inside the combined Deductions Setup card.
    // Do not collapse it separately, otherwise HR would expand Deductions Setup
    // but still find the non-statutory section hidden inside it.

    // DESCRIPTION ITEM 5 - STEP 2
    // Employee Payroll Overrides is another long payroll setup card,
    // so it should collapse by default and support double-click collapse.
    [state.dom.togglePayrollEmployeeOverrideCardBtn, state.dom.payrollEmployeeOverrideCardCollapse],

    [state.dom.togglePayrollRecordCardBtn, state.dom.payrollRecordCardCollapse],
    // DESCRIPTION ITEM 4 - STEP 2C
    // Payroll Records can become long, so it should collapse by default
    // and support the same double-click collapse shortcut.
    [state.dom.togglePayrollRecordsCardBtn, state.dom.payrollRecordsCardCollapse],

    // HRP-85 - STEP 1E
    // Email / Communication Setup is a real setup card and should follow
    // the same collapse behaviour as other long HR setup cards.
    [state.dom.toggleHrp85EmailIntegrationCardBtn, state.dom.hrp85EmailIntegrationCardCollapse],
  ];
}

// DESCRIPTION ITEM 4 - STEP 2B
// Collapse long working cards by default so HR lands on a clean,
// scan-friendly workspace and expands only the card they need.
function collapseDashboardWorkingCardsByDefault() {
  getDashboardWorkingCardPairs().forEach(([button, panel]) => {
    setDashboardCardExpanded(button, panel, false);
  });
}

// DESCRIPTION ITEM 4 - STEP 2B
// Allow HR to double-click inside an open card to collapse it.
// Ignore form fields, buttons, links, and tables so normal data entry
// and record actions are not interrupted.
function bindDashboardCardDoubleClickCollapse(button, panel) {
  if (!button || !panel) return;

  const card = panel.closest(".dashboard-section-card");
  if (!card) return;

  card.addEventListener("dblclick", (event) => {
    const ignoredTarget = event.target.closest(
      "button, a, input, select, textarea, label, table, [contenteditable='true']",
    );

    if (ignoredTarget) return;

    const isExpanded = !panel.classList.contains("d-none");
    if (!isExpanded) return;

    setDashboardCardExpanded(button, panel, false);
  });
}

// DESCRIPTION ITEM 4 - STEP 2B
// Bind double-click collapse to all long HR/payroll working cards.
function bindDashboardCardDoubleClickCollapseShortcuts() {
  getDashboardWorkingCardPairs().forEach(([button, panel]) => {
    bindDashboardCardDoubleClickCollapse(button, panel);
  });
}

// REMOVE GRADE LEVEL FIELD FROM EMPLOYEE DATA - STEP 3
// Scroll with an offset so card headings remain visible after redirect.
function scrollToDashboardTarget(target, offset = 96) {
  if (!target) return;

  const targetTop =
    target.getBoundingClientRect().top + window.pageYOffset - offset;

  window.scrollTo({
    top: Math.max(targetTop, 0),
    behavior: "smooth",
  });
}
// BATCH PAYROLL DEFAULT - STEP 6D
// Show the Back to Top button only after HR has scrolled down.
// This keeps the page clean near the top but helpful on long HR/payroll screens.
function updateBackToTopButtonVisibility() {
  const button = state.dom.backToTopBtn;
  if (!button) return;

  const shouldShow = window.scrollY > 420;
  button.classList.toggle("d-none", !shouldShow);
}

// BATCH PAYROLL DEFAULT - STEP 8A
// Shows a bottom-right notification for important messages that HR must
// see immediately, even when the normal page alert is outside the viewport.
function showDashboardToast(type = "warning", title = "Notification", message = "") {
  const toast = state.dom.dashboardToast;
  if (!toast) return;

  const accent = state.dom.dashboardToastAccent;
  const icon = state.dom.dashboardToastIcon;
  const titleEl = state.dom.dashboardToastTitle;
  const messageEl = state.dom.dashboardToastMessage;

  const themeMap = {
    success: {
      accentClass: "bg-success",
      iconClass: "text-bg-success",
      iconHtml: '<i class="bi bi-check-circle"></i>',
    },
    warning: {
      accentClass: "bg-warning",
      iconClass: "text-bg-warning",
      iconHtml: '<i class="bi bi-exclamation-triangle"></i>',
    },
    danger: {
      accentClass: "bg-danger",
      iconClass: "text-bg-danger",
      iconHtml: '<i class="bi bi-x-octagon"></i>',
    },
    info: {
      accentClass: "bg-primary",
      iconClass: "text-bg-primary",
      iconHtml: '<i class="bi bi-info-circle"></i>',
    },
  };

  const theme = themeMap[type] || themeMap.info;

  if (accent) {
    accent.className = theme.accentClass;
    accent.style.height = "4px";
  }

  if (icon) {
    icon.className =
      `rounded-circle d-flex align-items-center justify-content-center flex-shrink-0 ${theme.iconClass}`;
    icon.style.width = "36px";
    icon.style.height = "36px";
    icon.innerHTML = theme.iconHtml;
  }

  if (titleEl) {
    titleEl.textContent = title;
  }

  if (messageEl) {
    messageEl.innerHTML = message || "";
  }

  toast.classList.remove("d-none");

  window.clearTimeout(state.dashboardToastTimeoutId);

  state.dashboardToastTimeoutId = window.setTimeout(() => {
    hideDashboardToast();
  }, 8000);
}

// BATCH PAYROLL DEFAULT - STEP 8A
// Hides the bottom-right notification without changing any page data.
function hideDashboardToast() {
  state.dom.dashboardToast?.classList.add("d-none");

  if (state.dashboardToastTimeoutId) {
    window.clearTimeout(state.dashboardToastTimeoutId);
    state.dashboardToastTimeoutId = null;
  }
}

// HRP-85 - STEP 1E
// Shows local status inside Email / Communication Setup.
// This keeps HRP-85 feedback separate from Payroll Records and Send Payslips.
function setHrp85EmailIntegrationStatus(type = "info", message = "") {
  const status = state.dom.hrp85EmailIntegrationStatus;
  if (!status) return;

  if (!message) {
    status.className = "alert alert-light border d-none mb-0";
    status.textContent = "";
    return;
  }

  status.className = `alert alert-${type} border mb-0`;
  status.textContent = message;
}

// HRP-85 - STEP 1E FINAL COSMETIC FIX
// Personal mailboxes were used only for safe validation.
// This display helper removes placeholder "Bex Test Recipient" labels from
// the UI while keeping future official Bex recipient names database-driven.
function getHrp85RecipientDisplayNameByEmail(email = "", fallbackName = "") {
  const normalisedEmail = String(email || "").trim().toLowerCase();
  const fallback = String(fallbackName || "").trim();

  // HR EMAIL INTEGRATION UI CLEANUP - STEP 1D
  // Keep approved validation mailbox labels professional.
  // The database may still contain old placeholder names such as
  // "Bex Test Recipient 1/2", so the UI resolves known validation
  // mailboxes by email and hides placeholder-style names.
  const validationMailboxLabels = {
    "okworidams@yahoo.com": "Validation Mailbox - Yahoo",
    "okworiadams@yahoo.com": "Validation Mailbox - Yahoo",
    "okworidams@gmail.com": "Validation Mailbox - Gmail",
    "okworiadams@gmail.com": "Validation Mailbox - Gmail",
  };

  const resolvedLabel = validationMailboxLabels[normalisedEmail];

  if (resolvedLabel) {
    return resolvedLabel;
  }

  const isPlaceholderName = /^bex test recipient\b/i.test(fallback);

  return isPlaceholderName
    ? normalisedEmail || "--"
    : fallback || normalisedEmail || "--";
}

// HRP-85 - STEP 1E
// Keep recipient parsing tolerant of small column-name differences while the
// table remains protected by Supabase RLS and approved-recipient policies.
function mapHrp85TestRecipient(row = {}) {
  const recipientEmail = String(
    row.recipient_email ||
    row.email ||
    row.email_address ||
    row.test_email ||
    row.bex_email ||
    "",
  ).trim().toLowerCase();

  // HRP-85 - STEP 1E FINAL COSMETIC FIX
  // Use a clean display label for the personal validation mailboxes.
  // Future official Bex addresses still use the saved database label.
  const savedRecipientName = String(
    row.recipient_name ||
    row.full_name ||
    row.name ||
    row.display_name ||
    recipientEmail,
  ).trim();

  const recipientName = getHrp85RecipientDisplayNameByEmail(
    recipientEmail,
    savedRecipientName,
  );

  return {
    id: String(row.id || recipientEmail).trim(),
    recipientName,
    recipientEmail,
    raw: row,
  };
}

// HRP-85 - STEP 1E
// Render approved test recipients in both the dropdown and review table.
function renderHrp85TestRecipients() {
  const select = state.dom.hrp85TestRecipientSelect;
  const tbody = state.dom.hrp85RecipientsTableBody;
  const recipients = Array.isArray(state.hrp85TestRecipients)
    ? state.hrp85TestRecipients
    : [];

  if (state.dom.hrp85RecipientCountValue) {
    state.dom.hrp85RecipientCountValue.textContent = String(recipients.length);
  }

  if (select) {
    // HRP-85 - STEP 1E FINAL COSMETIC FIX
    // Keep the visible wording generic because current validation uses personal
    // mailboxes, while future Bex mailboxes can be added later.
    select.innerHTML = `<option value="">Select approved recipient</option>`;

    recipients.forEach((recipient) => {
      const option = document.createElement("option");

      option.value = recipient.recipientEmail;
      option.dataset.recipientId = recipient.id;
      option.dataset.recipientName = recipient.recipientName;
      option.textContent = `${recipient.recipientName} — ${recipient.recipientEmail}`;

      select.appendChild(option);
    });
  }

  if (tbody) {
    tbody.innerHTML = "";

    if (!recipients.length) {
      state.dom.hrp85RecipientsEmptyState?.classList.remove("d-none");
      state.dom.hrp85RecipientsTableWrapper?.classList.add("d-none");
    } else {
      state.dom.hrp85RecipientsEmptyState?.classList.add("d-none");
      state.dom.hrp85RecipientsTableWrapper?.classList.remove("d-none");

      recipients.forEach((recipient) => {
        const row = document.createElement("tr");

        row.innerHTML = `
          <td class="border-0 p-0 pb-2">
            <!-- HR EMAIL INTEGRATION UI CLEANUP - STEP 1B
                 Approved Recipients is a controlled reference list, not a
                 working admin table. Keep the data source and IDs unchanged,
                 but present each approved mailbox as a compact HR-friendly row. -->
            <div class="border rounded-3 p-3 bg-light-subtle">
              <div class="d-flex flex-column flex-lg-row justify-content-between align-items-lg-start gap-2">
                <div>
                  <div class="fw-semibold">
                    ${escapeHtml(recipient.recipientName || "--")}
                  </div>
                  <div class="text-secondary small text-break">
                    ${escapeHtml(recipient.recipientEmail || "--")}
                  </div>
                </div>

                <span class="badge rounded-pill text-bg-success align-self-start">
                  Approved
                </span>
              </div>
            </div>
          </td>
        `;

        tbody.appendChild(row);
      });
    }
  }

  updateHrp85SendTestEmailButtonState();
}

// HRP-85 - STEP 1E
// Load approved Bex recipients from the dedicated HRP-85 table.
// RLS/policies remain the source of access control.
async function refreshHrp85TestRecipients(options = {}) {
  const { showAlert = false } = options;
  const button = state.dom.hrp85RefreshRecipientsBtn;
  const startedAt = Date.now();

  try {
    setWorkspaceRefreshLoading(button, true, "Refreshing...");
    setHrp85EmailIntegrationStatus("info", "Loading approved Bex test recipients...");

    const supabase = getSupabaseClient();

    const { data, error } = await supabase
      .from("email_integration_test_recipients")
      .select("*");

    if (error) throw error;

    // HRP-80 - SETUP TENANT SAFETY FIX
    // Hide global/untagged validation recipients from this company workspace.
    // Proper long-term ownership should also be enforced by tenant_id + RLS.
    const tenantScopedRows = (Array.isArray(data) ? data : [])
      .filter(isHrp85RecordForCurrentTenant);

    state.hrp85TestRecipients = tenantScopedRows
      .map(mapHrp85TestRecipient)
      .filter((recipient) => recipient.recipientEmail)
      .sort((a, b) => a.recipientName.localeCompare(b.recipientName));

    renderHrp85TestRecipients();

    const message = `${state.hrp85TestRecipients.length} approved validation recipient(s) loaded for this company workspace.`;
    setHrp85EmailIntegrationStatus(
      state.hrp85TestRecipients.length ? "success" : "warning",
      state.hrp85TestRecipients.length
        ? message
        : "No approved validation recipients are configured for this company workspace.",
    );

    if (showAlert) {
      showPageAlert(
        state.hrp85TestRecipients.length ? "success" : "warning",
        state.hrp85TestRecipients.length
          ? message
          : "No approved validation recipients are configured for this company workspace.",
      );
    }
  } catch (error) {
    console.error("Error loading HRP-85 test recipients:", error);

    state.hrp85TestRecipients = [];
    renderHrp85TestRecipients();

    setHrp85EmailIntegrationStatus(
      "danger",
      error.message || "Approved Bex test recipients could not be loaded.",
    );
  } finally {
    await waitForMinimumLoadingFeedback(startedAt);
    setWorkspaceRefreshLoading(button, false);
  }
}

// HRP-85 - STEP 1E
// Delivery-log badge colours for the Email / Communication Setup table.
function getHrp85DeliveryStatusBadgeClass(status = "") {
  const normalisedStatus = normalizeText(status);

  if (normalisedStatus === "sent") return "text-bg-success";
  if (normalisedStatus === "failed") return "text-bg-danger";
  if (normalisedStatus === "pending") return "text-bg-secondary";

  return "text-bg-light border text-dark";
}

// HR EMAIL INTEGRATION UI CLEANUP - STEP 1B
// Keep audit status labels HR-readable.
// The saved database status remains unchanged; this only changes display text.
function getHrp85DeliveryStatusDisplayLabel(status = "") {
  const normalisedStatus = normalizeText(status);

  if (normalisedStatus === "sent") return "Delivered";
  if (normalisedStatus === "failed") return "Needs Review";
  if (normalisedStatus === "pending") return "Pending";

  return formatStatusLabel(status || "Pending");
}

// HRP-85 - STEP 1E
// Format delivery timestamps with date and time for validation evidence.
function formatHrp85DateTime(value) {
  if (!value) return "--";

  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return "--";

  return date.toLocaleString(undefined, {
    year: "numeric",
    month: "short",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  });
}

// HR EMAIL INTEGRATION UI CLEANUP - STEP 1E
// Split validation evidence timestamp into date and time.
// This keeps the audit table readable without changing the saved timestamp.
function formatHrp85DateTimeParts(value) {
  if (!value) {
    return {
      dateLabel: "--",
      timeLabel: "--",
    };
  }

  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return {
      dateLabel: "--",
      timeLabel: "--",
    };
  }

  return {
    dateLabel: date.toLocaleDateString(undefined, {
      year: "numeric",
      month: "short",
      day: "2-digit",
    }),
    timeLabel: date.toLocaleTimeString(undefined, {
      hour: "2-digit",
      minute: "2-digit",
    }),
  };
}

// HRP-85 - STEP 1E
// Render recent delivery logs from email_delivery_logs.
// HRP-85 - STEP 1E CLEANUP
// Translate technical provider errors into professional, business-readable notes.
function getHrp85DeliveryLogDisplayNote(record = {}) {
  const status = normalizeText(record.status || "");
  const rawError = normalizeText(record.error_message || "");

  if (status === "sent") {
    return "Delivered successfully.";
  }

  if (status === "pending") {
    return "Awaiting delivery confirmation.";
  }

  if (rawError.includes("insufficient authentication scopes")) {
    return "Mailbox connection needs re-authorisation.";
  }

  if (rawError.includes("template id") || rawError.includes("template not found")) {
    return "Email template configuration needs review.";
  }

  if (rawError.includes("non-browser") || rawError.includes("api access")) {
    return "Email provider API access setting needs review.";
  }

  if (status === "failed") {
    return "Delivery failed. Review email provider configuration.";
  }

  return "--";
}

// HRP-85 - STEP 1E CLEANUP
// Update the Last Result summary tile from the newest delivery record.
function updateHrp85LastResultSummary(logs = []) {
  const target = state.dom.hrp85LastResultValue;
  if (!target) return;

  const latest = Array.isArray(logs) && logs.length ? logs[0] : null;

  if (!latest) {
    target.textContent = "--";
    target.className = "summary-tile-value h6 mb-0";
    return;
  }

  const status = normalizeText(latest.status || "");

  if (status === "sent") {
    target.textContent = "Successful";
    target.className = "summary-tile-value h6 mb-0 text-success";
    return;
  }

  if (status === "failed") {
    target.textContent = "Needs Review";
    target.className = "summary-tile-value h6 mb-0 text-danger";
    return;
  }

  if (status === "pending") {
    target.textContent = "Pending";
    target.className = "summary-tile-value h6 mb-0 text-secondary";
    return;
  }

  target.textContent = formatStatusLabel(latest.status || "--");
  target.className = "summary-tile-value h6 mb-0";
}

// HRP-85 - STEP 1E CLEANUP
// Render recent delivery logs without exposing raw provider errors in the UI.
function renderHrp85DeliveryLogs(records = []) {
  const tbody = state.dom.hrp85DeliveryLogsTableBody;
  if (!tbody) return;

  const logs = Array.isArray(records) ? records : [];
  const sentCount = logs.filter((log) => normalizeText(log.status) === "sent").length;
  const failedCount = logs.filter((log) => normalizeText(log.status) === "failed").length;

  if (state.dom.hrp85DeliveryLogCountValue) {
    state.dom.hrp85DeliveryLogCountValue.textContent = String(logs.length);
  }

  if (state.dom.hrp85SentLogCountValue) {
    state.dom.hrp85SentLogCountValue.textContent = String(sentCount);
  }

  if (state.dom.hrp85FailedLogCountValue) {
    state.dom.hrp85FailedLogCountValue.textContent = String(failedCount);
  }

  updateHrp85LastResultSummary(logs);

  tbody.innerHTML = "";

  if (!logs.length) {
    state.dom.hrp85DeliveryLogsEmptyState?.classList.remove("d-none");
    state.dom.hrp85DeliveryLogsTableWrapper?.classList.add("d-none");
    return;
  }

  state.dom.hrp85DeliveryLogsEmptyState?.classList.add("d-none");
  state.dom.hrp85DeliveryLogsTableWrapper?.classList.remove("d-none");

  logs.forEach((record) => {
    const recipientEmail = String(
      record.recipient_email ||
      record.email ||
      record.to_email ||
      "",
    ).trim();

    // HRP-85 - STEP 1E FINAL COSMETIC FIX
    // Existing historical log rows may still contain old placeholder names.
    // Display clean mailbox labels by email without rewriting delivery history.
    const savedRecipientName = String(
      record.recipient_name ||
      record.full_name ||
      record.name ||
      "",
    ).trim();

    const recipientName = getHrp85RecipientDisplayNameByEmail(
      recipientEmail,
      savedRecipientName,
    );

    const sentOn = formatHrp85DateTimeParts(record.sent_at || record.created_at);

    const row = document.createElement("tr");

    row.innerHTML = `
      <td class="px-3 py-3 align-top">
        <!-- HR EMAIL INTEGRATION UI CLEANUP - STEP 1F
             Give each audit row enough vertical and horizontal space so
             recipient identity remains readable in the validation history. -->
        <div class="fw-semibold lh-sm">${escapeHtml(recipientName || recipientEmail || "--")}</div>
        <div class="text-secondary small text-break mt-1">
          ${escapeHtml(recipientEmail || "--")}
        </div>
      </td>

      <td class="px-3 py-3 align-top">
        <span class="badge ${getHrp85DeliveryStatusBadgeClass(record.status)}">
          ${escapeHtml(getHrp85DeliveryStatusDisplayLabel(record.status || "Pending"))}
        </span>
      </td>

      <td class="px-3 py-3 align-top text-nowrap">
        <!-- HR EMAIL INTEGRATION UI CLEANUP - STEP 1F
             Keep date and time stacked, but add spacing so the audit
             timestamp does not collide visually with outcome or notes. -->
        <div class="fw-semibold lh-sm">${escapeHtml(sentOn.dateLabel)}</div>
        <div class="text-secondary small mt-1">${escapeHtml(sentOn.timeLabel)}</div>
      </td>

      <td class="px-3 py-3 align-top small">
        <div class="lh-sm">
          ${escapeHtml(getHrp85DeliveryLogDisplayNote(record))}
        </div>
      </td>
    `;

    tbody.appendChild(row);
  });
}

// HRP-85 - STEP 1E
// Load recent HRP-85 delivery logs. This is read-only and does not send email.
async function refreshHrp85DeliveryLogs(options = {}) {
  const { showAlert = false } = options;
  const button = state.dom.hrp85RefreshDeliveryLogsBtn;
  const startedAt = Date.now();

  try {
    setWorkspaceRefreshLoading(button, true, "Refreshing...");

    const supabase = getSupabaseClient();

    const { data, error } = await supabase
      .from("email_delivery_logs")
      .select("*")
      .order("created_at", { ascending: false })
      .limit(25);

    if (error) throw error;

    // HRP-80 - SETUP TENANT SAFETY FIX
    // Hide delivery logs that are not explicitly tagged to the current company workspace.
    state.hrp85DeliveryLogs = (Array.isArray(data) ? data : [])
      .filter(isHrp85RecordForCurrentTenant);

    renderHrp85DeliveryLogs(state.hrp85DeliveryLogs);

    if (showAlert) {
      showPageAlert(
        "success",
        `${state.hrp85DeliveryLogs.length} validation delivery log(s) loaded for this company workspace.`
      );
    }
  } catch (error) {
    console.error("Error loading HRP-85 delivery logs:", error);

    state.hrp85DeliveryLogs = [];
    renderHrp85DeliveryLogs([]);

    setHrp85EmailIntegrationStatus(
      "danger",
      error.message || "HRP-85 delivery logs could not be loaded.",
    );
  } finally {
    await waitForMinimumLoadingFeedback(startedAt);
    setWorkspaceRefreshLoading(button, false);
  }
}

// HRP-85 - STEP 1E
// Refresh both approved recipients and recent delivery logs.
async function refreshHrp85EmailIntegrationWorkspace() {
  await refreshHrp85TestRecipients();
  await refreshHrp85DeliveryLogs();
}


// HRP-85 - STEP 1E CLEANUP
// Send is enabled from recipient + subject only because the validation
// email body is fixed and controlled by the system.
function updateHrp85SendTestEmailButtonState() {
  const select = state.dom.hrp85TestRecipientSelect;
  const selectedOption = select?.selectedOptions?.[0];

  // HR EMAIL INTEGRATION UX - STEP 1E
  // The send button must stay grey when no approved recipient is selected.
  // This also prevents a stale browser-restored value from making the action
  // look available when the dropdown is effectively empty.
  const hasApprovedRecipient = Boolean(
    String(select?.value || "").trim() &&
    selectedOption &&
    String(selectedOption.value || "").trim(),
  );

  const hasSubject = Boolean(
    String(state.dom.hrp85TestSubject?.value || "").trim(),
  );

  const canSend = Boolean(
    canCurrentUserMaintainCommunicationSetupData() &&
    hasApprovedRecipient &&
    hasSubject,
  );

  setPrimaryActionButtonReadyState(state.dom.hrp85SendTestEmailBtn, canSend);
}

// HRP-85 - STEP 1E CLEANUP
// Validate only the fields HR can safely control.
function validateHrp85EmailIntegrationForm() {
  [
    state.dom.hrp85TestRecipientSelect,
    state.dom.hrp85TestSubject,
  ].forEach((field) => {
    field?.classList.remove("is-invalid");
  });

  const recipientEmail = String(state.dom.hrp85TestRecipientSelect?.value || "").trim();
  const subject = String(state.dom.hrp85TestSubject?.value || "").trim();

  if (!recipientEmail) {
    state.dom.hrp85TestRecipientSelect?.classList.add("is-invalid");
    setHrp85EmailIntegrationStatus("warning", "Select an approved recipient.");
    return false;
  }

  if (!subject) {
    state.dom.hrp85TestSubject?.classList.add("is-invalid");
    setHrp85EmailIntegrationStatus("warning", "Enter a subject for the validation email.");
    return false;
  }

  return true;
}
// HR EMAIL INTEGRATION UX - STEP 1E-1
// After a validation email is sent successfully, reset only the recipient
// selector so the form returns to a deliberate, safe state.
// This prevents the Send Validation Email button from staying blue after
// a completed send.
function resetHrp85ValidationRecipientSelection() {
  const select = state.dom.hrp85TestRecipientSelect;

  if (select) {
    select.value = "";
    select.classList.remove("is-invalid");
  }

  updateHrp85SendTestEmailButtonState();
}

// HR EMAIL INTEGRATION UX - STEP 1E-1
// After a successful validation email, take HR to the audit/history panel.
// This is UI navigation only; it does not resend email or change delivery data.
function redirectToHrp85ValidationHistoryAfterSend() {
  const target =
    state.dom.hrp85DeliveryLogsTableWrapper?.closest(".border") ||
    state.dom.hrp85DeliveryLogsTableWrapper ||
    state.dom.hrp85DeliveryLogsEmptyState;

  if (!target) return;

  window.requestAnimationFrame(() => {
    window.requestAnimationFrame(() => {
      if (typeof scrollToDashboardTarget === "function") {
        scrollToDashboardTarget(target, 96);
      } else {
        target.scrollIntoView({
          behavior: "smooth",
          block: "start",
        });
      }

      if (state.dom.hrp85DeliveryLogsTableWrapper) {
        state.dom.hrp85DeliveryLogsTableWrapper.scrollTop = 0;
      }
    });
  });
}
// HRP-85 - STEP 1E
// Loading state for the Send Test Email button.
function setHrp85SendTestEmailLoading(isLoading) {
  // HR EMAIL INTEGRATION UX - STEP 1E
  // After a validation email is sent, return the form to a clean state.
  // This makes Send Validation Email grey again until HR deliberately selects
  // another approved recipient.
  function resetHrp85ValidationRecipientSelection() {
    const select = state.dom.hrp85TestRecipientSelect;

    if (select) {
      select.value = "";
      select.classList.remove("is-invalid");
    }

    updateHrp85SendTestEmailButtonState();
  }

  // HR EMAIL INTEGRATION UX - STEP 1E
  // After sending, take HR directly to Validation History so the new audit row
  // is visible without needing manual scrolling.
  function redirectToHrp85ValidationHistoryAfterSend() {
    const target =
      state.dom.hrp85DeliveryLogsTableWrapper?.closest(".border") ||
      state.dom.hrp85DeliveryLogsTableWrapper ||
      state.dom.hrp85DeliveryLogsEmptyState;

    if (!target) return;

    window.requestAnimationFrame(() => {
      window.requestAnimationFrame(() => {
        scrollToDashboardTarget(target, 96);

        if (state.dom.hrp85DeliveryLogsTableWrapper) {
          state.dom.hrp85DeliveryLogsTableWrapper.scrollTop = 0;
        }
      });
    });
  }
  const button = state.dom.hrp85SendTestEmailBtn;
  if (!button) return;

  if (isLoading) {
    if (!button.dataset.originalHtml) {
      button.dataset.originalHtml = button.innerHTML;
    }

    button.disabled = true;
    button.className = "btn btn-secondary dashboard-action-btn";
    button.innerHTML = `
      <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
      Sending...
    `;
    return;
  }

  if (button.dataset.originalHtml) {
    button.innerHTML = button.dataset.originalHtml;
    delete button.dataset.originalHtml;
  }

  updateHrp85SendTestEmailButtonState();
}

// HRP-85 - STEP 1E
// Send a controlled validation email through the secure Supabase Edge Function.
// This does not touch real payslip sending and does not pass payroll data.
async function handleHrp85EmailIntegrationSubmit() {
  // HR DASHBOARD ROLE RESTRICTIONS - STEP 2C
  // Email validation sending is a controlled setup action.
  // Payroll, Auditor, QA, and custom HR-routed roles may review logs only.
  if (!canCurrentUserMaintainCommunicationSetupData()) {
    showHrSetupAccessDeniedMessage("Email / Communication Setup");
    return;
  }
  if (!validateHrp85EmailIntegrationForm()) return;

  const select = state.dom.hrp85TestRecipientSelect;
  const selectedOption = select?.selectedOptions?.[0];

  const recipientEmail = String(select?.value || "").trim().toLowerCase();
  const recipientName = String(
    selectedOption?.dataset?.recipientName ||
    selectedOption?.textContent?.split("—")?.[0] ||
    recipientEmail,
  ).trim();

  // HR EMAIL INTEGRATION UI CLEANUP - STEP 1C
  // The Edge Function payload already expects recipientId.
  // Read it from the selected approved-recipient option instead of
  // referencing an undeclared variable. Email fallback keeps older
  // option data safe without changing recipient validation rules.
  const recipientId = String(
    selectedOption?.dataset?.recipientId ||
    selectedOption?.value ||
    recipientEmail ||
    "",
  ).trim();

  const subject = String(state.dom.hrp85TestSubject?.value || "").trim();
  // HRP-85 - STEP 1E CLEANUP
  // Message body is fixed to prevent payroll/salary/bank content being typed
  // into an email validation test.
  const message = HRP85_STANDARD_VALIDATION_MESSAGE;

  // HRP-85 - TENANT OWNERSHIP FIX
  // Send the active company workspace context to the secure Edge Function.
  // The Edge Function must also validate and persist this server-side.
  const tenantContext = getCurrentTenantContext();
  const tenantId = getRequiredTenantIdForHrEmployeeData();
  const tenantCode = String(tenantContext?.tenantCode || "").trim();

  try {
    setHrp85SendTestEmailLoading(true);
    setHrp85EmailIntegrationStatus("info", "Sending validation email...");

    const supabase = getSupabaseClient();

    const { data, error } = await supabase.functions.invoke(
      "hrp85-send-test-email",
      {
        body: {
          recipientId,
          recipient_id: recipientId,
          recipientEmail,
          recipient_email: recipientEmail,
          recipientName,
          recipient_name: recipientName,
          subject,
          message,

          // HRP-85 - TENANT OWNERSHIP FIX
          // Keep validation recipients/logs tied to the active company workspace.
          tenantId,
          tenant_id: tenantId,
          tenantCode,
          tenant_code: tenantCode,
        },
      },
    );

    if (error) throw error;

    if (data?.success === false) {
      throw new Error(data?.error || data?.message || "HRP-85 test email was not sent.");
    }

    const sentStatus = data?.status || "Sent";

    setHrp85EmailIntegrationStatus(
      "success",
      // HR EMAIL INTEGRATION UI CLEANUP - STEP 1D
      // Keep the confirmation operational and HR-readable.
      // This is display wording only; send result handling is unchanged.
      `Validation email sent to ${recipientEmail}. Ask the recipient to check Inbox and Spam/Junk. Delivery status: ${sentStatus}.`,
    );

    showDashboardToast(
      "success",
      "Email validation sent",
      `Validation email sent to ${escapeHtml(recipientEmail)}.`,
    );

    await refreshHrp85DeliveryLogs();

    // HR EMAIL INTEGRATION UX - STEP 1E
    // Successful validation should behave like a completed action:
    // clear the recipient, grey the send button, and show the audit history.
    resetHrp85ValidationRecipientSelection();
    redirectToHrp85ValidationHistoryAfterSend();
  } catch (error) {
    console.error("Error sending HRP-85 test email:", error);

    setHrp85EmailIntegrationStatus(
      "danger",
      error.message || "Validation email could not be sent.",
    );

    showDashboardToast(
      "danger",
      "Email validation failed",
      escapeHtml(error.message || "The validation email could not be sent."),
    );

    await refreshHrp85DeliveryLogs();
  } finally {
    setHrp85SendTestEmailLoading(false);
  }
}

