// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1C
// Escape CSV cell values so names, emails, departments, and job titles
// containing commas or quotes still download correctly.
function escapeBatchEmployeeCsvCell(value) {
  const text = String(value ?? "");

  if (/[",\n\r]/.test(text)) {
    return `"${text.replaceAll('"', '""')}"`;
  }

  return text;
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1C
// Download a clean employee import template.
// Employee Number is intentionally excluded because the system already
// generates employee numbers safely when employee profiles are created.
function downloadBatchEmployeeCsvImportTemplate() {
  const headers = [
    "First Name",
    "Middle Name",
    "Last Name",
    "Work Email",
    "Phone Number",
    "Department",
    "Job Title",
    "Line Manager",
    "Approver Email",
    "Employment Date",
    "Status",
    "System Role",
  ];

  const csvContent = headers
    .map(escapeBatchEmployeeCsvCell)
    .join(",");

  const blob = new Blob([csvContent], {
    type: "text/csv;charset=utf-8;",
  });

  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");

  link.href = url;
  link.download = `employee_batch_import_template_${new Date()
    .toISOString()
    .slice(0, 10)}.csv`;

  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);

  URL.revokeObjectURL(url);

  showPageAlert(
    "success",
    "Employee batch import template downloaded successfully.",
  );
}
// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F
// Shows spinner feedback while reviewed employee rows are being created.
function setBatchEmployeeSubmitLoading(isLoading) {
  const button = state.dom.submitBatchEmployeesBtn;
  if (!button) return;

  if (isLoading) {
    if (!button.dataset.originalHtml) {
      button.dataset.originalHtml = button.innerHTML;
    }

    button.disabled = true;
    button.innerHTML = `
      <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
      Creating Employees...
    `;
    return;
  }

  if (button.dataset.originalHtml) {
    button.innerHTML = button.dataset.originalHtml;
    delete button.dataset.originalHtml;
  }

  // Keep the button disabled after successful creation because the
  // prepared rows are cleared to prevent accidental duplicate inserts.
  button.disabled = !state.batchEmployeePreparedRows.length;
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F
// Final duplicate check before saving.
// This protects the system if another HR user created the same email
// after CSV import but before Create Employees was clicked.
async function findExistingBatchEmployeeEmails(workEmails = []) {
  const emails = Array.from(
    new Set(
      workEmails
        .map((email) => String(email || "").trim().toLowerCase())
        .filter(Boolean),
    ),
  );

  if (!emails.length) {
    return [];
  }

  const supabase = getSupabaseClient();

  const { data, error } = await supabase
    .from("employees")
    .select("work_email")
    .in("work_email", emails);

  if (error) throw error;

  return Array.isArray(data)
    ? data.map((employee) => String(employee.work_email || "").trim().toLowerCase())
    : [];
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F
// Convert one reviewed CSV row into the same shape used by the employee table.
// Employee Number is passed in after being generated by the existing RPC helper.
// HRP-EMPNUM - tenant_id is now required so batch imports are scoped to the
// correct company, matching the behaviour of the single-employee create form.
function buildBatchEmployeeInsertPayload(employee = {}, employeeNumber = "", tenantId = "") {
  return {
    first_name: String(employee.first_name || "").trim(),
    middle_name: String(employee.middle_name || "").trim() || null,
    last_name: String(employee.last_name || "").trim(),
    work_email: String(employee.work_email || "").trim().toLowerCase(),
    phone_number: String(employee.phone_number || "").trim() || null,
    department: String(employee.department || "").trim(),
    job_title: String(employee.job_title || "").trim(),
    line_manager: String(employee.line_manager || "").trim() || null,
    employment_date: employee.employment_date || null,
    approver_email: String(employee.approver_email || "").trim().toLowerCase() || null,
    employee_number: String(employeeNumber || "").trim(),
    status: normalizeText(employee.status || "active") || "active",
    system_role: String(employee.system_role || "").trim() || null,
    // HRP-EMPNUM - Tenant-scope the batch row so RLS and data segmentation
    // treat it identically to an employee created via the single-create form.
    tenant_id: String(tenantId || "").trim() || null,
  };
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F
// Save valid reviewed CSV rows into Supabase as employee records.
// This does not touch the manual Create Employee Profile form.
async function handleBatchEmployeeSubmit() {
  clearPageAlert();

  const preparedRows = Array.isArray(state.batchEmployeePreparedRows)
    ? [...state.batchEmployeePreparedRows]
    : [];

  if (!preparedRows.length) {
    showPageAlert(
      "warning",
      "There are no valid employee rows ready to create. Please import a valid employee CSV first.",
    );
    return;
  }

  const startedAt = Date.now();

  try {
    setBatchEmployeeSubmitLoading(true);
    await waitForNextPaint();

    const duplicateEmails = await findExistingBatchEmployeeEmails(
      preparedRows.map((employee) => employee.work_email),
    );

    if (duplicateEmails.length) {
      showPageAlert(
        "warning",
        `Employee creation stopped because ${duplicateEmails.length} email(s) already exist: <strong>${escapeHtml(
          duplicateEmails.slice(0, 5).join(", "),
        )}</strong>. Please clear, correct the CSV, and import again.`,
      );

      showDashboardToast(
        "warning",
        "Batch employee creation stopped",
        "One or more reviewed employees already exist. No new employee records were created.",
      );

      await refreshEmployeeWorkspace();
      // HR DASHBOARD ROLE RESTRICTIONS - STEP 2B
      // Employee records are now loaded, so resolve the signed-in user's
      // employees.system_role and apply People maintenance restrictions.
      applyHrPeopleAccessControls();
      return;
    }

    const rowsToInsert = [];

    // HRP-EMPNUM - Resolve tenant ID once for the whole batch.
    // generateNextEmployeeCustomId() also calls this internally, but capturing
    // it here lets us pass it directly to the payload builder so every row
    // carries the correct tenant_id without an extra lookup per row.
    const batchTenantId = getRequiredTenantIdForHrEmployeeData();

    for (const employee of preparedRows) {
      const employeeNumber = await generateNextEmployeeCustomId();
      rowsToInsert.push(buildBatchEmployeeInsertPayload(employee, employeeNumber, batchTenantId));
    }

    const supabase = getSupabaseClient();

    // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-3
    // Insert the reviewed employees without chaining .select("*").
    // Some Supabase/RLS setups allow insert but reject the immediate select,
    // which makes the UI show "creation failed" even when the insert worked.
    const { error } = await supabase
      .from("employees")
      .insert(rowsToInsert);

    if (error) {
      throw new Error(error.message || "Employee batch insert failed.");
    }

    const createdCount = rowsToInsert.length;

    // Clear prepared rows after successful save so HR cannot accidentally
    // click Create Employees again for the same CSV batch.
    state.batchEmployeePreparedRows = [];

    if (state.dom.batchEmployeeCsvFile) {
      state.dom.batchEmployeeCsvFile.value = "";
    }

    if (state.dom.batchEmployeeReviewCount) {
      state.dom.batchEmployeeReviewCount.textContent = `${createdCount} created`;
    }

    if (state.dom.batchEmployeeReviewTableBody) {
      state.dom.batchEmployeeReviewTableBody.innerHTML = `
        <tr>
          <td colspan="7" class="text-center text-success py-4">
            ${createdCount} employee profile(s) were created successfully. Check the Full Employee List below.
          </td>
        </tr>
      `;
    }

    if (state.dom.batchEmployeeSkippedRows) {
      state.dom.batchEmployeeSkippedRows.classList.add("d-none");
      state.dom.batchEmployeeSkippedRows.innerHTML = "";
    }

    if (state.dom.batchEmployeeCsvImportSummary) {
      state.dom.batchEmployeeCsvImportSummary.classList.remove("d-none");
      state.dom.batchEmployeeCsvImportSummary.innerHTML = `
        <div class="fw-semibold">Batch employee creation completed</div>
        <div class="small">
          ${createdCount} employee profile(s) were created successfully.
        </div>
      `;
    }

    updateBatchEmployeeCsvImportButtonState();

    await refreshEmployeeWorkspace();

    showPageAlert(
      "success",
      `${createdCount} employee profile(s) were created successfully from the CSV import.`,
    );

    showDashboardToast(
      "success",
      "Employees created",
      `${createdCount} employee profile(s) were added to the HR employee list.`,
    );

    redirectToFullEmployeeListAfterEmployeeSave();
  } catch (error) {
    // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-3
    // Surface Supabase errors clearly instead of hiding them behind [object Object].
    const errorMessage = String(error?.message || "").trim();
    const lowerMessage = errorMessage.toLowerCase();

    console.error("Error creating batch employees:", error);

    if (
      lowerMessage.includes("duplicate key") ||
      lowerMessage.includes("work_email") ||
      lowerMessage.includes("employees_work_email")
    ) {
      showPageAlert(
        "warning",
        "One or more employees in this CSV already exist by Work Email. Please clear the import, remove existing employees from the CSV, and import again.",
      );

      showDashboardToast(
        "warning",
        "Duplicate employee found",
        "Batch import is create-only, so existing employees are skipped instead of being created again.",
      );

      await refreshEmployeeWorkspace();
      return;
    }

    showPageAlert(
      "danger",
      errorMessage || "Batch employee records could not be created.",
    );

    showDashboardToast(
      "danger",
      "Batch employee creation failed",
      errorMessage || "The reviewed employee rows could not be saved. Please check the CSV and try again.",
    );
  }

  finally {
    // Keep spinner visible briefly so the user sees feedback.
    await waitForMinimumLoadingFeedback(startedAt, 600);
    setBatchEmployeeSubmitLoading(false);
  }
}
// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E
// Show spinner feedback while the employee CSV is being parsed.
function setBatchEmployeeCsvImportLoading(isLoading) {
  const button = state.dom.importBatchEmployeesCsvBtn;
  if (!button) return;

  if (isLoading) {
    if (!button.dataset.originalHtml) {
      button.dataset.originalHtml = button.innerHTML;
    }

    button.disabled = true;
    button.innerHTML = `
      <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
      Importing CSV...
    `;
    return;
  }

  if (button.dataset.originalHtml) {
    button.innerHTML = button.dataset.originalHtml;
    delete button.dataset.originalHtml;
  }

  updateBatchEmployeeCsvImportButtonState();
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E
// Normalise CSV headers so "Work Email", "work_email", and "work-email"
// are treated safely as the same type of header.
function normalizeBatchEmployeeCsvHeader(value = "") {
  return String(value || "")
    .trim()
    .toLowerCase()
    .replace(/[\s_-]+/g, "");
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E
// Parse CSV safely, including quoted commas and quoted line breaks.
// This is separate from the payroll parser so employee import remains isolated.
function parseBatchEmployeeCsvText(csvText = "") {
  const rows = [];
  let row = [];
  let cell = "";
  let insideQuotes = false;

  for (let index = 0; index < csvText.length; index += 1) {
    const char = csvText[index];
    const nextChar = csvText[index + 1];

    if (char === '"' && insideQuotes && nextChar === '"') {
      cell += '"';
      index += 1;
      continue;
    }

    if (char === '"') {
      insideQuotes = !insideQuotes;
      continue;
    }

    if (char === "," && !insideQuotes) {
      row.push(cell.trim());
      cell = "";
      continue;
    }

    if ((char === "\n" || char === "\r") && !insideQuotes) {
      if (char === "\r" && nextChar === "\n") {
        index += 1;
      }

      row.push(cell.trim());

      if (row.some((value) => String(value || "").trim())) {
        rows.push(row);
      }

      row = [];
      cell = "";
      continue;
    }

    cell += char;
  }

  row.push(cell.trim());

  if (row.some((value) => String(value || "").trim())) {
    rows.push(row);
  }

  return rows;
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E
// Build a simple header lookup map from the employee CSV header row.
function buildBatchEmployeeHeaderMap(headerRow = []) {
  const headerMap = new Map();

  headerRow.forEach((header, index) => {
    const key = normalizeBatchEmployeeCsvHeader(header);

    if (key) {
      headerMap.set(key, index);
    }
  });

  return headerMap;
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E
// Read a cell value by friendly header name.
function getBatchEmployeeCsvCell(row = [], headerMap, headerName = "") {
  const index = headerMap.get(normalizeBatchEmployeeCsvHeader(headerName));

  if (index === undefined) {
    return "";
  }

  return String(row[index] || "").trim();
}
// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-1
// Convert common CSV date formats into database-safe YYYY-MM-DD.
// The manual employee form already produces YYYY-MM-DD from input[type="date"].
// Batch CSV imports need this conversion because spreadsheets often export
// values like 1-Jan-20, 01/01/2020, or 1 Jan 2020.
function normalizeBatchEmployeeCsvDate(value = "") {
  const rawValue = String(value || "").trim();

  if (!rawValue) {
    return "";
  }

  // Already database-safe.
  if (/^\d{4}-\d{2}-\d{2}$/.test(rawValue)) {
    return rawValue;
  }

  const monthMap = {
    jan: "01",
    january: "01",
    feb: "02",
    february: "02",
    mar: "03",
    march: "03",
    apr: "04",
    april: "04",
    may: "05",
    jun: "06",
    june: "06",
    jul: "07",
    july: "07",
    aug: "08",
    august: "08",
    sep: "09",
    sept: "09",
    september: "09",
    oct: "10",
    october: "10",
    nov: "11",
    november: "11",
    dec: "12",
    december: "12",
  };

  // Handles formats like 1-Jan-20, 01-Jan-2020, or 1 Jan 2020.
  const textDateMatch = rawValue.match(/^(\d{1,2})[\s-]([A-Za-z]{3,9})[\s-](\d{2}|\d{4})$/);

  if (textDateMatch) {
    const day = textDateMatch[1].padStart(2, "0");
    const month = monthMap[textDateMatch[2].toLowerCase()];
    let year = textDateMatch[3];

    if (year.length === 2) {
      year = Number(year) >= 50 ? `19${year}` : `20${year}`;
    }

    if (month) {
      return `${year}-${month}-${day}`;
    }
  }

  // Handles formats like 01/01/2020 or 1/1/20 as DD/MM/YYYY.
  const slashDateMatch = rawValue.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2}|\d{4})$/);

  if (slashDateMatch) {
    const day = slashDateMatch[1].padStart(2, "0");
    const month = slashDateMatch[2].padStart(2, "0");
    let year = slashDateMatch[3];

    if (year.length === 2) {
      year = Number(year) >= 50 ? `19${year}` : `20${year}`;
    }

    return `${year}-${month}-${day}`;
  }

  return "";
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-4
// Build a stable employee name key for duplicate checks.
// HR standard for this create-only batch import:
// if the same full name already exists, do not create another employee
// just because a different work email was used.
function buildBatchEmployeeNameDuplicateKey(employee = {}) {
  return [
    employee.first_name,
    employee.middle_name,
    employee.last_name,
  ]
    .map((value) => normalizeText(value || ""))
    .filter(Boolean)
    .join("|");
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-4
// seenNames is used to stop duplicate employees inside the same CSV file.
function buildBatchEmployeePreparedRowFromCsv(row = [], headerMap, rowNumber, seenEmails, seenNames) {
  const firstName = getBatchEmployeeCsvCell(row, headerMap, "First Name");
  const middleName = getBatchEmployeeCsvCell(row, headerMap, "Middle Name");
  const lastName = getBatchEmployeeCsvCell(row, headerMap, "Last Name");
  const workEmail = getBatchEmployeeCsvCell(row, headerMap, "Work Email").toLowerCase();
  const phoneNumber = getBatchEmployeeCsvCell(row, headerMap, "Phone Number");
  const department = getBatchEmployeeCsvCell(row, headerMap, "Department");
  const jobTitle = getBatchEmployeeCsvCell(row, headerMap, "Job Title");
  const lineManager = getBatchEmployeeCsvCell(row, headerMap, "Line Manager");
  const approverEmail = getBatchEmployeeCsvCell(row, headerMap, "Approver Email").toLowerCase();
  // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-1
  // Normalise spreadsheet-style dates before validation and save.
  const rawEmploymentDate = getBatchEmployeeCsvCell(row, headerMap, "Employment Date");
  const employmentDate = normalizeBatchEmployeeCsvDate(rawEmploymentDate);
  const status = getBatchEmployeeCsvCell(row, headerMap, "Status") || "Active";
  const systemRole = getBatchEmployeeCsvCell(row, headerMap, "System Role");

  const missingFields = [];

  if (!firstName) missingFields.push("First Name");
  if (!lastName) missingFields.push("Last Name");
  if (!workEmail) missingFields.push("Work Email");
  if (!department) missingFields.push("Department");
  if (!jobTitle) missingFields.push("Job Title");
  if (!employmentDate) missingFields.push("Valid Employment Date");

  const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  if (workEmail && !emailPattern.test(workEmail)) {
    missingFields.push("Valid Work Email");
  }

  if (approverEmail && !emailPattern.test(approverEmail)) {
    missingFields.push("Valid Approver Email");
  }

  const existingEmployeeEmail = (state.employees || []).some(
    (employee) => normalizeText(employee.work_email) === normalizeText(workEmail),
  );

  if (workEmail && existingEmployeeEmail) {
    missingFields.push("Work Email already exists");
  }

  if (workEmail && seenEmails.has(normalizeText(workEmail))) {
    missingFields.push("Duplicate Work Email in CSV");
  }

  if (workEmail) {
    seenEmails.add(normalizeText(workEmail));
  }
  // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-4
  // Also block likely duplicate employees by exact full name.
  // This keeps the system HR-standard: one employee profile per person.
  // If an existing employee needs updating, that should be handled by a
  // separate Batch Update flow, not by creating another profile.
  const incomingNameKey = buildBatchEmployeeNameDuplicateKey({
    first_name: firstName,
    middle_name: middleName,
    last_name: lastName,
  });

  const existingEmployeeName = (state.employees || []).some((employee) => {
    return buildBatchEmployeeNameDuplicateKey(employee) === incomingNameKey;
  });

  if (incomingNameKey && existingEmployeeName) {
    missingFields.push("Employee name already exists");
  }

  if (incomingNameKey && seenNames.has(incomingNameKey)) {
    missingFields.push("Duplicate employee name in CSV");
  }

  if (incomingNameKey) {
    seenNames.add(incomingNameKey);
  }
  if (missingFields.length) {
    return {
      skipped: true,
      rowNumber,
      employeeName: `${firstName} ${lastName}`.trim() || "--",
      workEmail: workEmail || "--",
      reason: missingFields.join(", "),
    };
  }

  return {
    skipped: false,
    rowNumber,
    first_name: firstName,
    middle_name: middleName || null,
    last_name: lastName,
    work_email: workEmail,
    phone_number: phoneNumber || null,
    department,
    job_title: jobTitle,
    line_manager: lineManager || null,
    approver_email: approverEmail || null,
    employment_date: employmentDate,
    status,
    system_role: systemRole || null,
  };
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E
// Render valid employee CSV rows into the review table.
// Nothing is saved here.
function renderImportedBatchEmployeeCsvRows(preparedRows = [], skippedRows = []) {
  const tbody = state.dom.batchEmployeeReviewTableBody;
  if (!tbody) return;

  tbody.innerHTML = "";

  if (!preparedRows.length) {
    tbody.innerHTML = `
      <tr>
        <td colspan="7" class="text-center text-secondary py-4">
          No valid employee rows were found in the CSV.
        </td>
      </tr>
    `;
  }

  preparedRows.forEach((employee) => {
    const fullName = [
      employee.first_name,
      employee.middle_name,
      employee.last_name,
    ]
      .filter(Boolean)
      .join(" ");

    const rowElement = document.createElement("tr");

    rowElement.innerHTML = `
      <td>
        <div class="fw-semibold">${escapeHtml(fullName)}</div>
        <div class="text-secondary small">CSV row ${escapeHtml(employee.rowNumber)}</div>
      </td>

      <td class="text-break">${escapeHtml(employee.work_email)}</td>

      <td>${escapeHtml(employee.department || "--")}</td>

      <td>${escapeHtml(employee.job_title || "--")}</td>

<!-- HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-2
     Show the same friendly date style used by the employee list.
     The saved value remains database-safe YYYY-MM-DD underneath. -->
<td class="text-nowrap">${formatDate(employee.employment_date)}</td>

      <td>
        <span class="badge ${getStatusBadgeClass(employee.status || "Active")}">
          ${escapeHtml(formatStatusLabel(employee.status || "Active"))}
        </span>
      </td>

      <td>
        <span class="badge text-bg-success">Ready</span>
        <div class="text-secondary small mt-1">Ready to create</div>
      </td>
    `;

    tbody.appendChild(rowElement);
  });

  if (state.dom.batchEmployeeReviewCount) {
    state.dom.batchEmployeeReviewCount.textContent =
      `${preparedRows.length} ready`;
  }

  if (state.dom.submitBatchEmployeesBtn) {
    state.dom.submitBatchEmployeesBtn.disabled = preparedRows.length === 0;
  }

  if (state.dom.batchEmployeeReviewPanel) {
    state.dom.batchEmployeeReviewPanel.classList.remove("d-none");
  }

  if (state.dom.batchEmployeeSkippedRows) {
    if (skippedRows.length) {
      state.dom.batchEmployeeSkippedRows.classList.remove("d-none");
      state.dom.batchEmployeeSkippedRows.innerHTML = `
        <div class="fw-semibold mb-1">Some CSV rows were skipped</div>
        <div class="small mb-2">
          ${skippedRows.length} row(s) could not be prepared for employee creation.
        </div>
        <ul class="small mb-0">
          ${skippedRows
          .slice(0, 8)
          .map(
            (item) =>
              `<li>Row ${escapeHtml(item.rowNumber)} — ${escapeHtml(item.workEmail)}: ${escapeHtml(item.reason)}</li>`,
          )
          .join("")}
        </ul>
      `;
    } else {
      state.dom.batchEmployeeSkippedRows.classList.add("d-none");
      state.dom.batchEmployeeSkippedRows.innerHTML = "";
    }
  }
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E
// Read the selected employee CSV and prepare rows for review only.
// This does not insert anything into Supabase.
async function handleBatchEmployeeCsvImport() {
  clearPageAlert();

  const file = state.dom.batchEmployeeCsvFile?.files?.[0] || null;

  if (!file) {
    showPageAlert("warning", "Please select an employee CSV file first.");
    return;
  }

  // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E-1
  // Track when the import started so the spinner remains visible briefly,
  // even when the CSV file parses very quickly.
  const startedAt = Date.now();

  try {
    setBatchEmployeeCsvImportLoading(true);
    await waitForNextPaint();

    // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-2
    // Refresh employee records before validating the CSV.
    // This ensures already-created employees are detected and skipped by Work Email.
    await refreshEmployeeWorkspace();

    const csvText = await file.text();
    const rows = parseBatchEmployeeCsvText(csvText);

    const requiredHeaders = [
      "First Name",
      "Last Name",
      "Work Email",
      "Department",
      "Job Title",
      "Employment Date",
    ];

    const headerRowIndex = rows.findIndex((row) => {
      const normalisedRowHeaders = new Set(
        row.map((cell) => normalizeBatchEmployeeCsvHeader(cell)),
      );

      return requiredHeaders.every((header) =>
        normalisedRowHeaders.has(normalizeBatchEmployeeCsvHeader(header)),
      );
    });

    if (headerRowIndex === -1) {
      showPageAlert(
        "warning",
        "This does not look like the approved employee import CSV. Please download the Employee Template and upload the completed file.",
      );

      showDashboardToast(
        "warning",
        "CSV import stopped",
        "The selected file does not contain the required employee import headers.",
      );

      return;
    }

    const headerMap = buildBatchEmployeeHeaderMap(rows[headerRowIndex]);

    const dataRows = rows
      .slice(headerRowIndex + 1)
      .filter((row) => row.some((cell) => String(cell || "").trim()));

    const preparedRows = [];
    const skippedRows = [];
    const seenEmails = new Set();

    // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1F-4
    // Track names inside the uploaded CSV so the same person is not prepared twice.
    const seenNames = new Set();

    dataRows.forEach((row, index) => {
      const preparedRow = buildBatchEmployeePreparedRowFromCsv(
        row,
        headerMap,
        headerRowIndex + index + 2,
        seenEmails,
        seenNames,
      );

      if (preparedRow.skipped) {
        skippedRows.push(preparedRow);
        return;
      }

      preparedRows.push(preparedRow);
    });

    state.batchEmployeePreparedRows = preparedRows;

    renderImportedBatchEmployeeCsvRows(preparedRows, skippedRows);

    if (state.dom.batchEmployeeCsvImportSummary) {
      state.dom.batchEmployeeCsvImportSummary.classList.remove("d-none");
      state.dom.batchEmployeeCsvImportSummary.innerHTML = `
        <div class="fw-semibold">Employee CSV import prepared</div>
        <div class="small">
          ${preparedRows.length} row(s) are ready for review.
          ${skippedRows.length ? `${skippedRows.length} row(s) were skipped.` : "No rows were skipped."}
        </div>
      `;
    }

    showPageAlert(
      preparedRows.length ? "success" : "warning",
      preparedRows.length
        ? `${preparedRows.length} employee row(s) were imported into Batch Employee Review. Review them before creating employee profiles.`
        : "No employee rows were imported. Please check the CSV values and try again.",
    );
  } catch (error) {
    console.error("Error importing employee CSV:", error);

    showPageAlert(
      "danger",
      error.message || "Employee CSV could not be imported.",
    );

    showDashboardToast(
      "danger",
      "Employee CSV import failed",
      "The employee CSV could not be imported. Please check the file and try again.",
    );
  } finally {
    // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E-1
    // Keep spinner feedback visible long enough for HR to notice it.
    await waitForMinimumLoadingFeedback(startedAt, 600);
    setBatchEmployeeCsvImportLoading(false);
  }
}
// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1D
// Keep Import CSV grey/disabled until a CSV file has been selected.
// Actual parsing and spinner feedback will be added in the next step.
function updateBatchEmployeeCsvImportButtonState() {
  const hasCsvFile = Boolean(state.dom.batchEmployeeCsvFile?.files?.[0]);

  setPrimaryActionButtonReadyState(
    state.dom.importBatchEmployeesCsvBtn,
    hasCsvFile,
  );
}

// HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1C
// Clear the selected CSV and reset the review area.
// This does not touch saved employees or the existing manual employee form.
function clearBatchEmployeeCsvImportUi() {
  // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1E
  // Clear prepared employee rows from memory when HR clears the import area.
  state.batchEmployeePreparedRows = [];
  if (state.dom.batchEmployeeCsvFile) {
    state.dom.batchEmployeeCsvFile.value = "";
  }

  state.dom.batchEmployeeCsvImportSummary?.classList.add("d-none");
  state.dom.batchEmployeeReviewPanel?.classList.add("d-none");
  state.dom.batchEmployeeSkippedRows?.classList.add("d-none");

  if (state.dom.batchEmployeeCsvImportSummary) {
    state.dom.batchEmployeeCsvImportSummary.innerHTML = "";
  }

  if (state.dom.batchEmployeeSkippedRows) {
    state.dom.batchEmployeeSkippedRows.innerHTML = "";
  }

  if (state.dom.batchEmployeeReviewCount) {
    state.dom.batchEmployeeReviewCount.textContent = "0 ready";
  }

  if (state.dom.batchEmployeeReviewTableBody) {
    state.dom.batchEmployeeReviewTableBody.innerHTML = `
      <tr>
        <td colspan="7" class="text-center text-secondary py-4">
          No employee CSV rows imported yet.
        </td>
      </tr>
    `;
  }

  if (state.dom.submitBatchEmployeesBtn) {
    state.dom.submitBatchEmployeesBtn.disabled = true;
  }

  // HRP-78 - BATCH EMPLOYEE CSV IMPORT - STEP 1D
  // Re-check the Import CSV button after clearing the selected file.
  // Since the file input is empty, the button returns to grey/disabled.
  updateBatchEmployeeCsvImportButtonState();

  showPageAlert("info", "Employee CSV import area was cleared.");
}
function setWorkspaceRefreshLoading(button, isLoading, loadingText = "Refreshing...") {
  if (!button) return;

  button.disabled = isLoading;

  if (isLoading) {
    if (!button.dataset.originalHtml) {
      button.dataset.originalHtml = button.innerHTML;
    }

    button.innerHTML = `
      <span class="spinner-border spinner-border-sm me-2" aria-hidden="true"></span>
      ${loadingText}
    `;
  } else if (button.dataset.originalHtml) {
    button.innerHTML = button.dataset.originalHtml;
    delete button.dataset.originalHtml;
  }
}

function waitForNextPaint() {
  return new Promise((resolve) => {
    window.requestAnimationFrame(() => {
      window.requestAnimationFrame(resolve);
    });
  });
}

// =========================================================
// UI POLISH
// Keeps fast-loading buttons from clearing too quickly,
// so the spinner is actually visible to the user.
// =========================================================
function waitForMinimumLoadingFeedback(startedAt, minimumMs = 300) {
  const elapsed = Date.now() - startedAt;

  if (elapsed >= minimumMs) {
    return Promise.resolve();
  }

  return new Promise((resolve) => {
    setTimeout(resolve, minimumMs - elapsed);
  });
}

// HR BUTTON UNIFORMITY - STEP 6B
// One shared helper for form action buttons.
// Incomplete form = grey and disabled.
// Complete form = blue and enabled.
// This keeps Bank Directory, Employee Bank Details, Payroll Master,
// Allowance Components, and Submit Payroll visually consistent.
function setPrimaryActionButtonReadyState(button, canSubmit) {
  if (!button) return;

  button.disabled = !canSubmit;

  button.classList.toggle("btn-primary", canSubmit);
  button.classList.toggle("btn-secondary", !canSubmit);
}

// PAYROLL RECORD LOCKING - STEP 5D
// Finalised payroll records are monthly payroll snapshots.
// Once finalised, salary/calculation fields should not be edited from
// Edit Payroll Record. Any salary or allowance change should be made in
// Payroll Master / Allowance Components before a new payroll run is created.
function setFinalisedPayrollRecordReadOnlyMode(isReadOnly = false) {
  const fieldsToLock = [
    state.dom.payrollEmployeeId,
    state.dom.payrollPayCycle,
    state.dom.payrollPayDate,
    state.dom.payrollEmployeeGroup,
    state.dom.payrollModel,
    state.dom.regularIncrementPercent,
    state.dom.regularIncrementAmount,
    state.dom.regularMeritIncrement,
    state.dom.regularNewBaseSalary,
    state.dom.regularBasicPercent,
    state.dom.regularHousingPercent,
    state.dom.regularTransportPercent,
    state.dom.regularUtilityPercent,
    state.dom.regularOtherAllowancePercent,
    state.dom.regularBht,
    state.dom.regularNetSalary,
    state.dom.regularMonthlySalaryPlusLogistics,
    state.dom.payrollStatus,
    state.dom.payrollReference,
    state.dom.payrollBaseSalary,
    state.dom.payrollBasicPay,
    state.dom.payrollHousingAllowance,
    state.dom.payrollTransportAllowance,
    state.dom.payrollUtilityAllowance,
    state.dom.payrollMedicalAllowance,
    state.dom.payrollOtherAllowance,
    state.dom.payrollBonus,
    state.dom.payrollOvertime,
    state.dom.payrollLogisticsAllowance,
    state.dom.payrollDataAirtimeAllowance,
    state.dom.payrollGrossPay,
    state.dom.payrollPayeTax,
    state.dom.payrollWhtTax,
    state.dom.payrollEmployeePension,
    state.dom.payrollEmployerPension,
    state.dom.payrollOtherDeductions,
    state.dom.payrollTotalDeductions,
    state.dom.payrollNetPay,
    state.dom.payrollCurrency,
    state.dom.payrollIsFinalised,
  ];

  fieldsToLock.forEach((field) => {
    if (!field) return;

    if (field.type === "checkbox") {
      field.disabled = isReadOnly;
      return;
    }

    if (field.tagName === "SELECT") {
      field.disabled = isReadOnly;
      return;
    }

    field.readOnly = isReadOnly;
    field.classList.toggle("bg-light", isReadOnly);
  });

  // Notes remain readable/editable later only if we deliberately decide that.
  // For this lock step, keep the whole finalised record as a true snapshot.
  if (state.dom.payrollNotes) {
    state.dom.payrollNotes.readOnly = isReadOnly;
    state.dom.payrollNotes.classList.toggle("bg-light", isReadOnly);
  }

  if (state.dom.savePayrollBtn) {
    state.dom.savePayrollBtn.disabled = isReadOnly;
    state.dom.savePayrollBtn.classList.toggle("d-none", isReadOnly);
  }

  if (state.dom.topSubmitPayrollBtn) {
    state.dom.topSubmitPayrollBtn.disabled = isReadOnly;
    state.dom.topSubmitPayrollBtn.classList.toggle("d-none", isReadOnly);
  }
}

// PAYROLL RECORD LOCKING - STEP 5D
// Simple check for records that should behave as locked payroll snapshots.
function isFinalisedPayrollRecord(record = {}) {
  return (
    Boolean(record.is_finalised) ||
    normalizeText(record.status) === "authorised" ||
    normalizeText(record.status) === "finalised"
  );
}

// ASSIGN LINE MANAGER - STEP 1
// Build the display name used in the Assign Line Manager dropdown.
function getEmployeeManagerDisplayName(employee = {}) {
  return [
    employee.first_name,
    employee.middle_name,
    employee.last_name,
  ]
    .filter(Boolean)
    .join(" ")
    .trim() || employee.work_email || "Unnamed Employee";
}

// ASSIGN LINE MANAGER - STEP 1D
// Build one legacy saved manager option for the employee currently being edited.
// This avoids showing every old free-text manager globally in Create Employee.
// Legacy values are only kept so existing employee records do not lose their
// saved Line Manager / Approver Email during edit.
function getSavedLineManagerOptionForEmployee(employee = {}) {
  const managerName = String(employee.line_manager || "").trim();
  const managerEmail = String(employee.approver_email || "").trim().toLowerCase();

  if (!managerName || !managerEmail) {
    return null;
  }

  return {
    id: `saved:${managerEmail}`,
    name: managerName,
    email: managerEmail,
  };
}

// ASSIGN LINE MANAGER - STEP 1
// Populate Assign Line Manager from existing active employee records.
// This uses state.employees already loaded from Supabase, so no new table is needed.
function populateAssignedLineManagerOptions(preferredEmployeeId = "") {
  const select = state.dom.assignedLineManagerEmployeeId;
  if (!select) return;

  const currentEditingEmployeeId = String(
    state.currentEditingEmployee?.id || state.dom.editingEmployeeId?.value || "",
  ).trim();

  const currentValue = String(preferredEmployeeId || select.value || "").trim();

  // ASSIGN LINE MANAGER - STEP 1A
  // Do not show every employee as a possible line manager.
  // Only active employees with manager-level system roles or manager-style job titles
  // should appear in the Assign Line Manager dropdown.
  const managerEligibleRoles = new Set([
    "manager",
  ]);

  const managerCandidates = (state.employees || [])
    .filter((employee) => {
      const isActive = normalizeText(employee.status) === "active";
      const hasEmail = Boolean(String(employee.work_email || "").trim());
      const isNotCurrentEmployee =
        String(employee.id || "").trim() !== currentEditingEmployeeId;

      const systemRole = normalizeText(employee.system_role || employee.role || "");
      const jobTitle = normalizeText(employee.job_title || "");

      const hasManagerRole = managerEligibleRoles.has(systemRole);

      const hasManagerJobTitle =
        jobTitle.includes("manager") ||
        jobTitle.includes("supervisor") ||
        jobTitle.includes("lead") ||
        jobTitle.includes("head");

      return (
        isActive &&
        hasEmail &&
        isNotCurrentEmployee &&
        (hasManagerRole || hasManagerJobTitle)
      );
    })
    .sort((a, b) =>
      getEmployeeManagerDisplayName(a).localeCompare(
        getEmployeeManagerDisplayName(b),
      ),
    );

  // ASSIGN LINE MANAGER - STEP 1D
  // Only include a saved/free-text manager while editing the employee that
  // already has that saved manager. Do not show all legacy managers globally.
  const savedManagerOption = currentEditingEmployeeId
    ? getSavedLineManagerOptionForEmployee(state.currentEditingEmployee || {})
    : null;

  select.innerHTML = "";

  const placeholderOption = document.createElement("option");
  placeholderOption.value = "";
  placeholderOption.textContent =
    managerCandidates.length || savedManagerOption
      ? "Select line manager"
      : "No manager employee records available";
  select.appendChild(placeholderOption);

  managerCandidates.forEach((employee) => {
    const option = document.createElement("option");
    option.value = employee.id;
    // EMPLOYEE BIODATA COMPLETION - STEP 6B-PREP
    // Keep the manager dropdown readable. Email is shown separately in Primary Approver Email.
    option.textContent = `${getEmployeeManagerDisplayName(employee)} — ${employee.job_title || "Manager"}`;
    option.dataset.managerName = getEmployeeManagerDisplayName(employee);
    option.dataset.managerEmail = String(employee.work_email || "").trim().toLowerCase();
    select.appendChild(option);
  });

  // ASSIGN LINE MANAGER - STEP 1D
  // Add only the current employee's saved legacy manager, if no real
  // manager employee record already matches that email.
  if (savedManagerOption) {
    const alreadyExists = Array.from(select.options).some(
      (option) =>
        normalizeText(option.dataset.managerEmail || "") ===
        normalizeText(savedManagerOption.email),
    );

    if (!alreadyExists) {
      const option = document.createElement("option");
      option.value = savedManagerOption.id;
      // EMPLOYEE BIODATA COMPLETION - STEP 6B-PREP
      // Avoid repeating email in the dropdown because Approver Email is displayed separately.
      option.textContent = `${savedManagerOption.name} (saved manager)`;
      option.dataset.managerName = savedManagerOption.name;
      option.dataset.managerEmail = savedManagerOption.email;
      select.appendChild(option);
    }
  }

  if (currentValue) {
    const matchingOption = Array.from(select.options).find(
      (option) => String(option.value) === currentValue,
    );

    if (matchingOption) {
      select.value = currentValue;
    }
  }
}

// ASSIGN LINE MANAGER - STEP 1
// When HR selects a manager, auto-fill the existing Line Manager and
// Approver Email fields. These existing fields are still what get saved.
function applyAssignedLineManagerSelection() {
  const selectedManagerId = String(
    state.dom.assignedLineManagerEmployeeId?.value || "",
  ).trim();

  const selectedOption =
    state.dom.assignedLineManagerEmployeeId?.selectedOptions?.[0] || null;

  const selectedManager = (state.employees || []).find(
    (employee) => String(employee.id || "").trim() === selectedManagerId,
  );

  // ASSIGN LINE MANAGER - STEP 1B
  // Support both real employee manager records and saved manager values
  // pulled from existing line_manager / approver_email data.
  const managerName =
    selectedManager
      ? getEmployeeManagerDisplayName(selectedManager)
      : String(selectedOption?.dataset?.managerName || "").trim();

  const managerEmail =
    selectedManager
      ? String(selectedManager.work_email || "").trim().toLowerCase()
      : String(selectedOption?.dataset?.managerEmail || "").trim().toLowerCase();

  // QUICK FIX - APPROVER EMAIL BYPASS
  // A manager name can exist without an approver email while workflow mailboxes
  // are still being prepared. Keep the manager snapshot, but allow approver
  // email to remain blank.
  if (!managerName) {
    if (state.dom.lineManager) state.dom.lineManager.value = "";
    if (state.dom.approverEmail) state.dom.approverEmail.value = "";
    updateEmployeeSaveButtonState();
    return;
  }

  if (state.dom.lineManager) {
    state.dom.lineManager.value = managerName;
  }

  if (state.dom.approverEmail) {
    state.dom.approverEmail.value = managerEmail || "";
  }

  state.dom.lineManager?.classList.remove("is-invalid");
  state.dom.approverEmail?.classList.remove("is-invalid");

  updateEmployeeSaveButtonState();
}

// ASSIGN LINE MANAGER - STEP 1
// During edit mode, select the matching manager if the saved approver email
// or saved manager name matches an active employee record.
function syncAssignedLineManagerFromSavedValues(employee = {}) {
  const select = state.dom.assignedLineManagerEmployeeId;
  if (!select) return;

  const savedApproverEmail = normalizeText(employee.approver_email || "");
  const savedManagerName = normalizeText(employee.line_manager || "");

  const matchedManager = (state.employees || []).find((candidate) => {
    const candidateEmail = normalizeText(candidate.work_email || "");
    const candidateName = normalizeText(getEmployeeManagerDisplayName(candidate));

    return (
      (savedApproverEmail && candidateEmail === savedApproverEmail) ||
      (savedManagerName && candidateName === savedManagerName)
    );
  });

  // ASSIGN LINE MANAGER - STEP 1D
  // Build the saved manager key only for the employee currently being edited.
  // This keeps old manager values available in edit mode without polluting
  // Create Employee with all legacy manager names.
  const savedManagerOption = getSavedLineManagerOptionForEmployee(employee);
  const savedManagerKey = savedManagerOption?.id || "";

  populateAssignedLineManagerOptions(matchedManager?.id || savedManagerKey);

  if (matchedManager) {
    select.value = matchedManager.id;
    return;
  }

  if (savedManagerKey) {
    const savedOption = Array.from(select.options).find(
      (option) => option.value === savedManagerKey,
    );

    if (savedOption) {
      select.value = savedManagerKey;
    }
  }
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Return manager candidates that can be assigned as reporting lines.
// This mirrors the existing Primary Line Manager rule: active employees
// with manager-level roles or manager-style job titles only.
function getEmployeeReportingLineManagerCandidates() {
  const currentEditingEmployeeId = String(
    state.currentEditingEmployee?.id || state.dom.editingEmployeeId?.value || "",
  ).trim();

  const managerEligibleRoles = new Set([
    "manager",
  ]);

  return (state.employees || [])
    .filter((employee) => {
      const isActive = normalizeText(employee.status) === "active";
      const hasEmail = Boolean(String(employee.work_email || "").trim());
      const isNotCurrentEmployee =
        String(employee.id || "").trim() !== currentEditingEmployeeId;

      const systemRole = normalizeText(employee.system_role || employee.role || "");
      const jobTitle = normalizeText(employee.job_title || "");

      const hasManagerRole = managerEligibleRoles.has(systemRole);

      const hasManagerJobTitle =
        jobTitle.includes("manager") ||
        jobTitle.includes("supervisor") ||
        jobTitle.includes("lead") ||
        jobTitle.includes("head");

      return (
        isActive &&
        hasEmail &&
        isNotCurrentEmployee &&
        (hasManagerRole || hasManagerJobTitle)
      );
    })
    .sort((a, b) =>
      getEmployeeManagerDisplayName(a).localeCompare(
        getEmployeeManagerDisplayName(b),
      ),
    );
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Build select options for additional reporting manager rows.
function buildEmployeeReportingLineManagerOptions(selectedManagerId = "") {
  const selectedId = String(selectedManagerId || "").trim();
  const candidates = getEmployeeReportingLineManagerCandidates();

  const options = [
    `<option value="">Select manager</option>`,
  ];

  candidates.forEach((employee) => {
    const employeeId = String(employee.id || "").trim();
    const selected = employeeId === selectedId ? " selected" : "";

    options.push(`
      <option value="${escapeHtml(employeeId)}"${selected}
        data-manager-name="${escapeHtml(getEmployeeManagerDisplayName(employee))}"
        data-manager-email="${escapeHtml(String(employee.work_email || "").trim().toLowerCase())}">
        ${escapeHtml(getEmployeeManagerDisplayName(employee))} — ${escapeHtml(employee.work_email || "--")}
      </option>
    `);
  });

  return options.join("");
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Empty-state for additional reporting lines.
function renderEmployeeReportingLinesEmptyStateIfNeeded() {
  const container = state.dom.employeeReportingLinesList;
  if (!container) return;

  const hasRows = Boolean(
    container.querySelector("[data-employee-reporting-line-row]"),
  );

  if (hasRows) return;

  container.innerHTML = `
    <div class="alert alert-light border mb-0" data-reporting-line-empty-state>
      No additional reporting managers added.
    </div>
  `;
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Add one additional reporting manager row.
// This is not a placeholder: rows are read and saved to employee_reporting_lines.
function addEmployeeReportingLineRow(rowData = {}) {
  const container = state.dom.employeeReportingLinesList;
  if (!container) return;

  container.querySelector("[data-reporting-line-empty-state]")?.remove();

  const row = document.createElement("div");
  row.className = "border rounded-4 p-3 mb-3 bg-white";
  row.dataset.employeeReportingLineRow = "true";

  // EMPLOYEE BIODATA COMPLETION - STEP 3I
  // Keep additional reporting lines simple in the employee biodata form.
  // The Product Owner asked for 2+ line managers, not complex reporting types.
  // Additional managers are saved as Secondary by default.
  row.innerHTML = `
    <div class="row g-3 align-items-end">
      <div class="col-md-11">
        <label class="form-label fw-semibold">Secondary Manager</label>
        <select class="form-select" data-reporting-line-manager-id>
          ${buildEmployeeReportingLineManagerOptions(rowData.managerEmployeeId || "")}
        </select>
        <div class="invalid-feedback">Select a secondary manager or remove this row.</div>
      </div>

      <div class="col-md-1">
        <button type="button" class="btn btn-outline-danger w-100"
          title="Remove secondary manager" data-remove-reporting-line-row>
          <i class="bi bi-trash"></i>
        </button>
      </div>

      <input type="hidden" data-reporting-line-manager-type value="Secondary" />
    </div>
  `;

  container.appendChild(row);

  // EMPLOYEE BIODATA COMPLETION - STEP 3I
  // Manager Type is hidden in the biodata form and saved as Secondary.
  const managerType = row.querySelector("[data-reporting-line-manager-type]");
  if (managerType) managerType.value = "Secondary";

  row.querySelectorAll("select, input").forEach((field) => {
    field.addEventListener("input", updateEmployeeSaveButtonState);
    field.addEventListener("change", updateEmployeeSaveButtonState);
  });

  row.querySelector("[data-remove-reporting-line-row]")?.addEventListener("click", () => {
    row.remove();
    renderEmployeeReportingLinesEmptyStateIfNeeded();
    updateEmployeeSaveButtonState();
  });

  updateEmployeeSaveButtonState();
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Reset additional reporting lines when the employee form clears.
function resetEmployeeReportingLineRows() {
  if (!state.dom.employeeReportingLinesList) return;
  state.dom.employeeReportingLinesList.innerHTML = "";
  renderEmployeeReportingLinesEmptyStateIfNeeded();
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Keep the existing employee table fields aligned with the selected primary manager.
// This preserves current workflow behaviour while child rows support multiple managers.
function syncPrimaryReportingLineSnapshotToEmployeeFields() {
  applyAssignedLineManagerSelection();
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Read primary + additional reporting lines from the form.
function getEmployeeReportingLinesFromForm() {
  const rows = [];

  const primaryManagerId = String(
    state.dom.assignedLineManagerEmployeeId?.value || "",
  ).trim();

  if (primaryManagerId && !primaryManagerId.startsWith("saved:")) {
    rows.push({
      managerEmployeeId: primaryManagerId,
      managerType: "Primary",
      effectiveDate: state.dom.employmentDate?.value || null,
      status: "Active",
      notes: "Primary reporting line",
    });
  }

  state.dom.employeeReportingLinesList
    ?.querySelectorAll("[data-employee-reporting-line-row]")
    .forEach((row) => {
      // EMPLOYEE BIODATA COMPLETION - STEP 3H
      // Additional manager UI is intentionally simple.
      // Effective Date defaults to Employment Date, Status defaults to Active,
      // and Notes stays null unless a future maintenance screen exposes it.
      rows.push({
        managerEmployeeId: String(
          row.querySelector("[data-reporting-line-manager-id]")?.value || "",
        ).trim(),
        managerType: String(
          row.querySelector("[data-reporting-line-manager-type]")?.value || "Secondary",
        ).trim(),
        effectiveDate: state.dom.employmentDate?.value || null,
        status: "Active",
        notes: null,
        rowElement: row,
      });
    });

  return rows;
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Validate additional reporting lines before saving.
// Primary manager remains optional, but any added row must be complete,
// and the same manager cannot be assigned twice.
function validateEmployeeReportingLines() {
  const rows = getEmployeeReportingLinesFromForm();
  const managerIds = [];
  let isValid = true;
  let firstInvalidField = null;

  state.dom.employeeReportingLinesList
    ?.querySelectorAll("[data-reporting-line-manager-id]")
    .forEach((select) => {
      select.classList.remove("is-invalid");
    });

  rows.forEach((row) => {
    if (!row.managerEmployeeId) {
      const managerSelect = row.rowElement?.querySelector("[data-reporting-line-manager-id]");
      managerSelect?.classList.add("is-invalid");
      isValid = false;
      if (!firstInvalidField) firstInvalidField = managerSelect;
      return;
    }

    managerIds.push(row.managerEmployeeId);
  });

  const duplicateManagerId = managerIds.find(
    (managerId, index) => managerIds.indexOf(managerId) !== index,
  );

  if (duplicateManagerId) {
    state.dom.employeeReportingLinesList
      ?.querySelectorAll("[data-reporting-line-manager-id]")
      .forEach((select) => {
        if (select.value === duplicateManagerId) {
          select.classList.add("is-invalid");
        }
      });

    showPageAlert(
      "warning",
      "The same manager cannot be assigned more than once on the employee reporting lines.",
    );

    isValid = false;
  }

  if (!isValid) {
    if (firstInvalidField?.focus) {
      firstInvalidField.focus();
    }

    return false;
  }

  return true;
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Save reporting lines by replacing this employee's current reporting setup.
// This keeps the child table aligned with the latest employee form state.
async function saveEmployeeReportingLinesForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return;

  const supabase = getSupabaseClient();

  // HRP-80 - TENANT DATA SEGMENTATION - STEP 7C
  // Reporting line child rows inherit the same tenant as the employee record.
  const tenantId = getRequiredTenantIdForHrEmployeeData();

  const reportingRows = getEmployeeReportingLinesFromForm()
    .filter((row) => row.managerEmployeeId)
    .map((row) => ({
      employee_id: employeeKey,
      tenant_id: tenantId,
      manager_employee_id: row.managerEmployeeId,
      manager_type: row.managerType || "Secondary",
      effective_date: row.effectiveDate || null,
      status: row.status || "Active",
      notes: row.notes || null,
      created_by: state.currentUser?.id || null,
      updated_by: state.currentUser?.id || null,
    }));

  const { error: deleteError } = await supabase
    .from("employee_reporting_lines")
    .delete()
    .eq("employee_id", employeeKey);

  if (deleteError) throw deleteError;

  if (!reportingRows.length) return;

  const { error: insertError } = await supabase
    .from("employee_reporting_lines")
    .insert(reportingRows);

  if (insertError) throw insertError;
}

// EMPLOYEE BIODATA COMPLETION - STEP 3C
// Load saved child reporting lines when HR edits an employee.
async function loadEmployeeReportingLinesForEdit(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  resetEmployeeReportingLineRows();

  if (!employeeKey) return;

  try {
    const supabase = getSupabaseClient();

    const { data, error } = await supabase
      .from("employee_reporting_lines")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("manager_type", { ascending: true })
      .order("created_at", { ascending: true });

    if (error) throw error;

    const rows = Array.isArray(data) ? data : [];

    const primaryRow = rows.find(
      (row) => normalizeText(row.manager_type) === "primary",
    );

    if (primaryRow?.manager_employee_id) {
      populateAssignedLineManagerOptions(primaryRow.manager_employee_id);

      if (state.dom.assignedLineManagerEmployeeId) {
        state.dom.assignedLineManagerEmployeeId.value = primaryRow.manager_employee_id;
      }

      applyAssignedLineManagerSelection();
    }

    rows
      .filter((row) => row.id !== primaryRow?.id)
      .forEach((row) => {
        addEmployeeReportingLineRow({
          managerEmployeeId: row.manager_employee_id || "",
          managerType: row.manager_type || "Secondary",
          effectiveDate: row.effective_date || "",
          status: row.status || "Active",
          notes: row.notes || "",
        });
      });
  } catch (error) {
    console.error("Error loading employee reporting lines:", error);

    showPageAlert(
      "warning",
      "Employee profile opened, but saved reporting lines could not be loaded. Please refresh and try again.",
    );
  }
}

// EMPLOYEE BIODATA COMPLETION - STEP 4D
// Address data is stored in employee_addresses because employees can have
// different address types over time. The biodata form currently exposes the
// two standard HR address types: Current and Permanent.
function getEmployeeAddressGroups() {
  return [
    {
      type: "Current",
      isPrimary: true,
      addressLine1: state.dom.employeeCurrentAddressLine1,
      city: state.dom.employeeCurrentCity,
      stateRegion: state.dom.employeeCurrentStateRegion,
      country: state.dom.employeeCurrentCountry,
      postalCode: state.dom.employeeCurrentPostalCode,
    },
    {
      type: "Permanent",
      isPrimary: false,
      addressLine1: state.dom.employeePermanentAddressLine1,
      city: state.dom.employeePermanentCity,
      stateRegion: state.dom.employeePermanentStateRegion,
      country: state.dom.employeePermanentCountry,
      // EMPLOYEE BIODATA COMPLETION - STEP 5I
      // Keep the Permanent Address group clean.
      // Next of Kin listeners belong in bindEvents(), not inside this address config object.
      postalCode: state.dom.employeePermanentPostalCode,
    },
  ];
}

// EMPLOYEE BIODATA COMPLETION - STEP 4D
// Address fields are optional, but if HR starts entering an address group,
// the main address line must be completed before save.
function isEmployeeAddressGroupStarted(group = {}) {
  return [
    group.addressLine1,
    group.city,
    group.stateRegion,
    group.country,
    group.postalCode,
  ].some((field) => Boolean(String(field?.value || "").trim()));
}

function clearEmployeeAddressValidationState() {
  getEmployeeAddressGroups().forEach((group) => {
    group.addressLine1?.classList.remove("is-invalid");
  });
}

function validateEmployeeAddressFields() {
  clearEmployeeAddressValidationState();

  let isValid = true;
  let firstInvalidField = null;

  getEmployeeAddressGroups().forEach((group) => {
    const hasAnyValue = isEmployeeAddressGroupStarted(group);
    const hasMainAddress = Boolean(String(group.addressLine1?.value || "").trim());

    if (hasAnyValue && !hasMainAddress) {
      group.addressLine1?.classList.add("is-invalid");
      isValid = false;
      if (!firstInvalidField) firstInvalidField = group.addressLine1;
    }
  });

  if (!isValid) {
    showPageAlert(
      "warning",
      "Please complete the main address line for any current or permanent address you started.",
    );

    firstInvalidField?.focus?.();
  }

  return isValid;
}

// EMPLOYEE BIODATA COMPLETION - STEP 4D
// Build insert rows for employee_addresses.
// Empty address groups are not saved.
function buildEmployeeAddressRowsForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return [];

  // HRP-80 - TENANT DATA SEGMENTATION - STEP 7C
  // Address child rows inherit the logged-in HR user's tenant.
  const tenantId = getRequiredTenantIdForHrEmployeeData();

  return getEmployeeAddressGroups()
    .filter((group) => isEmployeeAddressGroupStarted(group))
    .map((group) => ({
      employee_id: employeeKey,
      tenant_id: tenantId,
      address_type: group.type,
      address_line_1: String(group.addressLine1?.value || "").trim(),
      address_line_2: null,
      city: String(group.city?.value || "").trim() || null,
      state_region: String(group.stateRegion?.value || "").trim() || null,
      country: String(group.country?.value || "").trim() || "Nigeria",
      postal_code: String(group.postalCode?.value || "").trim() || null,
      is_primary: Boolean(group.isPrimary),
      status: "Active",
      created_by: state.currentUser?.id || null,
      updated_by: state.currentUser?.id || null,
    }));
}

// EMPLOYEE BIODATA COMPLETION - STEP 4D
// Save addresses by replacing the employee's current address snapshot.
// This matches the reporting-line save pattern and keeps the form state clean.
async function saveEmployeeAddressesForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return;

  const supabase = getSupabaseClient();
  const addressRows = buildEmployeeAddressRowsForEmployee(employeeKey);

  const { error: deleteError } = await supabase
    .from("employee_addresses")
    .delete()
    .eq("employee_id", employeeKey);

  if (deleteError) throw deleteError;

  if (!addressRows.length) return;

  const { error: insertError } = await supabase
    .from("employee_addresses")
    .insert(addressRows);

  if (insertError) throw insertError;
}

function resetEmployeeAddressFields() {
  getEmployeeAddressGroups().forEach((group) => {
    [
      group.addressLine1,
      group.city,
      group.stateRegion,
      group.country,
      group.postalCode,
    ].forEach((field) => {
      if (!field) return;
      field.value = "";
      field.classList.remove("is-invalid");
    });
  });
}

function applyEmployeeAddressRecordToFields(record = {}) {
  const addressType = normalizeText(record.address_type);

  const group = getEmployeeAddressGroups().find(
    (item) => normalizeText(item.type) === addressType,
  );

  if (!group) return;

  if (group.addressLine1) group.addressLine1.value = record.address_line_1 || "";
  if (group.city) group.city.value = record.city || "";
  if (group.stateRegion) group.stateRegion.value = record.state_region || "";
  if (group.country) group.country.value = record.country || "";
  if (group.postalCode) group.postalCode.value = record.postal_code || "";
}

// EMPLOYEE BIODATA COMPLETION - STEP 4D
// Load saved current/permanent addresses when HR edits an employee.
async function loadEmployeeAddressesForEdit(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  resetEmployeeAddressFields();

  if (!employeeKey) return;

  try {
    const supabase = getSupabaseClient();

    const { data, error } = await supabase
      .from("employee_addresses")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("address_type", { ascending: true })
      .order("created_at", { ascending: true });

    if (error) throw error;

    (Array.isArray(data) ? data : []).forEach((record) => {
      applyEmployeeAddressRecordToFields(record);
    });

    updateEmployeeSaveButtonState();
  } catch (error) {
    console.error("Error loading employee addresses:", error);

    showPageAlert(
      "warning",
      "Employee profile opened, but saved address details could not be loaded. Please refresh and try again.",
    );
  }
}

function areEmployeeAddressFieldsReadyForSubmit() {
  return getEmployeeAddressGroups().every((group) => {
    const hasAnyValue = isEmployeeAddressGroupStarted(group);
    const hasMainAddress = Boolean(String(group.addressLine1?.value || "").trim());

    return !hasAnyValue || hasMainAddress;
  });
}

// EMPLOYEE BIODATA COMPLETION - STEP 5D
// Next of Kin is optional at employee creation.
// If HR starts it, Full Name, Relationship, and Phone Number must be completed.
function getEmployeeNextOfKinFields() {
  return {
    fullName: state.dom.employeeNextOfKinFullName,
    relationship: state.dom.employeeNextOfKinRelationship,
    phoneNumber: state.dom.employeeNextOfKinPhoneNumber,
    email: state.dom.employeeNextOfKinEmail,
    address: state.dom.employeeNextOfKinAddress,
  };
}

function isEmployeeNextOfKinStarted() {
  const fields = getEmployeeNextOfKinFields();

  return [
    fields.fullName,
    fields.relationship,
    fields.phoneNumber,
    fields.email,
    fields.address,
  ].some((field) => Boolean(String(field?.value || "").trim()));
}

function clearEmployeeNextOfKinValidationState() {
  const fields = getEmployeeNextOfKinFields();

  [
    fields.fullName,
    fields.relationship,
    fields.phoneNumber,
    fields.email,
  ].forEach((field) => {
    field?.classList.remove("is-invalid");
  });
}

function validateEmployeeNextOfKinFields() {
  clearEmployeeNextOfKinValidationState();

  if (!isEmployeeNextOfKinStarted()) {
    return true;
  }

  const fields = getEmployeeNextOfKinFields();
  const issues = [];
  let firstInvalidField = null;

  const fullName = String(fields.fullName?.value || "").trim();
  const relationship = String(fields.relationship?.value || "").trim();
  const phoneNumber = String(fields.phoneNumber?.value || "").trim();

  if (!fullName) {
    issues.push("Enter the next of kin full name.");
    fields.fullName?.classList.add("is-invalid");
    firstInvalidField ||= fields.fullName;
  }

  if (!relationship) {
    issues.push("Select the next of kin relationship.");
    fields.relationship?.classList.add("is-invalid");
    firstInvalidField ||= fields.relationship;
  }

  if (!phoneNumber) {
    issues.push("Enter the next of kin phone number.");
    fields.phoneNumber?.classList.add("is-invalid");
    firstInvalidField ||= fields.phoneNumber;
  }

  if (!validateEmailField(fields.email, { required: false })) {
    issues.push("Enter a valid next of kin email address.");
    firstInvalidField ||= fields.email;
  }

  if (issues.length) {
    showPageAlert(
      "warning",
      "Please complete the required next of kin details or clear the next of kin section.",
    );

    firstInvalidField?.focus?.();
    return false;
  }

  return true;
}

function buildEmployeeNextOfKinRowsForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();

  if (!employeeKey || !isEmployeeNextOfKinStarted()) {
    return [];
  }

  // HRP-80 - TENANT DATA SEGMENTATION - STEP 7C
  // Next of Kin child rows inherit the logged-in HR user's tenant.
  const tenantId = getRequiredTenantIdForHrEmployeeData();

  const fields = getEmployeeNextOfKinFields();

  return [
    {
      employee_id: employeeKey,
      tenant_id: tenantId,
      full_name: String(fields.fullName?.value || "").trim(),
      relationship: String(fields.relationship?.value || "").trim(),
      phone_number: String(fields.phoneNumber?.value || "").trim(),
      email: String(fields.email?.value || "").trim().toLowerCase() || null,
      address: String(fields.address?.value || "").trim() || null,
      is_primary: true,
      status: "Active",
      created_by: state.currentUser?.id || null,
      updated_by: state.currentUser?.id || null,
    },
  ];
}

// EMPLOYEE BIODATA COMPLETION - STEP 5D
// Save one primary next of kin snapshot for the employee.
// This mirrors the address/reporting-line child-table pattern.
async function saveEmployeeNextOfKinForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return;

  const supabase = getSupabaseClient();
  const nextOfKinRows = buildEmployeeNextOfKinRowsForEmployee(employeeKey);

  const { error: deleteError } = await supabase
    .from("employee_next_of_kin")
    .delete()
    .eq("employee_id", employeeKey);

  if (deleteError) throw deleteError;

  if (!nextOfKinRows.length) return;

  const { error: insertError } = await supabase
    .from("employee_next_of_kin")
    .insert(nextOfKinRows);

  if (insertError) throw insertError;
}

function resetEmployeeNextOfKinFields() {
  const fields = getEmployeeNextOfKinFields();

  [
    fields.fullName,
    fields.relationship,
    fields.phoneNumber,
    fields.email,
    fields.address,
  ].forEach((field) => {
    if (!field) return;
    field.value = "";
    field.classList.remove("is-invalid");
  });
}

function applyEmployeeNextOfKinRecordToFields(record = {}) {
  const fields = getEmployeeNextOfKinFields();

  if (fields.fullName) fields.fullName.value = record.full_name || "";
  if (fields.relationship) fields.relationship.value = record.relationship || "";
  if (fields.phoneNumber) fields.phoneNumber.value = record.phone_number || "";
  if (fields.email) fields.email.value = record.email || "";
  if (fields.address) fields.address.value = record.address || "";
}

// EMPLOYEE BIODATA COMPLETION - STEP 5D
// Load saved primary Next of Kin when HR edits an employee.
async function loadEmployeeNextOfKinForEdit(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  resetEmployeeNextOfKinFields();

  if (!employeeKey) return;

  try {
    const supabase = getSupabaseClient();

    const { data, error } = await supabase
      .from("employee_next_of_kin")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("is_primary", { ascending: false })
      .order("created_at", { ascending: true })
      .limit(1);

    if (error) throw error;

    const record = Array.isArray(data) ? data[0] : null;

    if (record) {
      applyEmployeeNextOfKinRecordToFields(record);
    }

    updateEmployeeSaveButtonState();
  } catch (error) {
    console.error("Error loading employee next of kin:", error);

    showPageAlert(
      "warning",
      "Employee profile opened, but saved next of kin details could not be loaded. Please refresh and try again.",
    );
  }
}

function areEmployeeNextOfKinFieldsReadyForSubmit() {
  if (!isEmployeeNextOfKinStarted()) {
    return true;
  }

  const fields = getEmployeeNextOfKinFields();

  const hasRequiredFields = Boolean(
    String(fields.fullName?.value || "").trim() &&
    String(fields.relationship?.value || "").trim() &&
    String(fields.phoneNumber?.value || "").trim(),
  );

  const emailValue = String(fields.email?.value || "").trim();
  const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const hasValidEmail = !emailValue || emailPattern.test(emailValue);

  return hasRequiredFields && hasValidEmail;
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-3A
// Education is optional at employee creation.
// If HR starts it, Institution and Qualification must be completed.
// Graduation Year is optional, but must be realistic when entered.
function getEmployeeEducationFields() {
  return {
    institutionName: state.dom.employeeEducationInstitutionName,
    qualification: state.dom.employeeEducationQualification,
    fieldOfStudy: state.dom.employeeEducationFieldOfStudy,
    graduationYear: state.dom.employeeEducationGraduationYear,
    educationStatus: state.dom.employeeEducationStatus,
    highestQualification: state.dom.employeeEducationHighestQualification,
  };
}

function isEmployeeEducationStarted() {
  const fields = getEmployeeEducationFields();

  return [
    fields.institutionName,
    fields.qualification,
    fields.fieldOfStudy,
    fields.graduationYear,
    fields.educationStatus,
  ].some((field) => Boolean(String(field?.value || "").trim()));
}

function clearEmployeeEducationValidationState() {
  const fields = getEmployeeEducationFields();

  [
    fields.institutionName,
    fields.qualification,
    fields.graduationYear,
  ].forEach((field) => {
    field?.classList.remove("is-invalid");
  });
}

function isEmployeeGraduationYearValid() {
  const fields = getEmployeeEducationFields();
  const yearValue = String(fields.graduationYear?.value || "").trim();

  if (!yearValue) return true;

  const year = Number(yearValue);
  const currentYear = new Date().getFullYear();

  return Number.isInteger(year) && year >= 1950 && year <= currentYear + 10;
}

function validateEmployeeEducationFields() {
  clearEmployeeEducationValidationState();

  if (!isEmployeeEducationStarted()) {
    return true;
  }

  const fields = getEmployeeEducationFields();
  let firstInvalidField = null;

  const institutionName = String(fields.institutionName?.value || "").trim();
  const qualification = String(fields.qualification?.value || "").trim();

  if (!institutionName) {
    fields.institutionName?.classList.add("is-invalid");
    firstInvalidField ||= fields.institutionName;
  }

  if (!qualification) {
    fields.qualification?.classList.add("is-invalid");
    firstInvalidField ||= fields.qualification;
  }

  if (!isEmployeeGraduationYearValid()) {
    fields.graduationYear?.classList.add("is-invalid");
    firstInvalidField ||= fields.graduationYear;
  }

  if (firstInvalidField) {
    showPageAlert(
      "warning",
      "Please complete the required education details or clear the education section.",
    );

    firstInvalidField.focus?.();
    return false;
  }

  return true;
}

function areEmployeeEducationFieldsReadyForSubmit() {
  if (!isEmployeeEducationStarted()) {
    return true;
  }

  const fields = getEmployeeEducationFields();

  const hasRequiredFields = Boolean(
    String(fields.institutionName?.value || "").trim() &&
    String(fields.qualification?.value || "").trim(),
  );

  return hasRequiredFields && isEmployeeGraduationYearValid();
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-4B
// Normalise each staged education row before saving to Supabase.
// This prevents display-only fields, old IDs, or loaded metadata from being reinserted.
function normaliseEmployeeEducationRecordForSave(record = {}, employeeId = "") {
  const employeeKey = String(employeeId || "").trim();

  // HRP-80 - TENANT DATA SEGMENTATION - STEP 7C
  // Education child rows inherit the logged-in HR user's tenant.
  const tenantId = getRequiredTenantIdForHrEmployeeData();

  return {
    employee_id: employeeKey,
    tenant_id: tenantId,
    institution_name: String(record.institution_name || "").trim(),
    qualification: String(record.qualification || "").trim(),
    field_of_study: String(record.field_of_study || "").trim() || null,
    graduation_year: record.graduation_year ? Number(record.graduation_year) : null,
    education_status: String(record.education_status || "").trim() || "Completed",
    is_highest_qualification: Boolean(record.is_highest_qualification),
    created_by: state.currentUser?.id || null,
    updated_by: state.currentUser?.id || null,
  };
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-4B
// Build all education rows for save.
// Staged rows come from "Add Education Record".
// A visible, un-staged row is also saved so HR does not lose a final entry.
function buildEmployeeEducationRowsForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();

  if (!employeeKey) {
    return [];
  }

  const stagedRecords = Array.isArray(state.pendingEmployeeEducationRecords)
    ? state.pendingEmployeeEducationRecords
    : [];

  const recordsToSave = [...stagedRecords];

  if (isEmployeeEducationStarted()) {
    recordsToSave.push(buildEmployeeEducationRecordFromCurrentFields());
  }

  return recordsToSave
    .map((record) => normaliseEmployeeEducationRecordForSave(record, employeeKey))
    .filter((record) => record.institution_name && record.qualification);
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-3B
// Save the current visible Education section for the employee.
// This mirrors the existing address/next-of-kin replace pattern.
async function saveEmployeeEducationRecordsForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return;

  const supabase = getSupabaseClient();
  const educationRows = buildEmployeeEducationRowsForEmployee(employeeKey);

  const { error: deleteError } = await supabase
    .from("employee_education_records")
    .delete()
    .eq("employee_id", employeeKey);

  if (deleteError) throw deleteError;

  if (!educationRows.length) return;

  const { error: insertError } = await supabase
    .from("employee_education_records")
    .insert(educationRows);

  if (insertError) throw insertError;
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1A
// Build a clean, unique, alphabetical list of saved schools/courses.
// Empty values are ignored so the datalist stays useful and not noisy.
function getUniqueSortedEducationSuggestionValues(rows = [], columnName = "") {
  const valuesByKey = new Map();

  rows.forEach((row) => {
    const value = String(row?.[columnName] || "").trim();
    if (!value) return;

    const key = value.toLowerCase().replace(/\s+/g, " ");

    if (!valuesByKey.has(key)) {
      valuesByKey.set(key, value);
    }
  });

  return Array.from(valuesByKey.values()).sort((a, b) =>
    a.localeCompare(b, undefined, { sensitivity: "base" }),
  );
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1A
// Replace the old static datalist options with values learned from saved
// employee education records.
// DYNAMIC EDUCATION SUGGESTIONS - STEP 1B
// Keep the original hardcoded HTML suggestions as seed values, then merge
// saved database values into the same datalist. This prevents useful default
// suggestions from disappearing after dynamic suggestions load.
function renderEducationDatalistOptions(datalist, values = []) {
  if (!datalist) return;

  if (!datalist.dataset.staticSuggestionValues) {
    const staticValues = Array.from(datalist.options || [])
      .map((option) => String(option.value || "").trim())
      .filter(Boolean);

    datalist.dataset.staticSuggestionValues = JSON.stringify(staticValues);
  }

  let staticValues = [];

  try {
    staticValues = JSON.parse(datalist.dataset.staticSuggestionValues || "[]");
  } catch (error) {
    staticValues = [];
  }

  const mergedValuesByKey = new Map();

  [...staticValues, ...values].forEach((value) => {
    const cleanValue = String(value || "").trim();
    if (!cleanValue) return;

    const key = cleanValue.toLowerCase().replace(/\s+/g, " ");

    if (!mergedValuesByKey.has(key)) {
      mergedValuesByKey.set(key, cleanValue);
    }
  });

  const mergedValues = Array.from(mergedValuesByKey.values()).sort((a, b) =>
    a.localeCompare(b, undefined, { sensitivity: "base" }),
  );

  datalist.innerHTML = "";

  mergedValues.forEach((value) => {
    const option = document.createElement("option");
    option.value = value;
    datalist.appendChild(option);
  });
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1C
// Native browser datalist popups cannot be styled reliably.
// Keep the datalist as the source of truth, but render a compact in-app
// suggestion panel with a slimmer scrollbar for School and Course fields.
function injectEducationSuggestionPanelStyles() {
  if (document.getElementById("educationSuggestionPanelStyles")) return;

  const style = document.createElement("style");
  style.id = "educationSuggestionPanelStyles";

  style.textContent = `
    .education-suggestion-panel {
      position: absolute;
      top: calc(100% + 0.35rem);
      left: 0;
      right: 0;
      z-index: 1080;
      max-height: 13rem;
      overflow-y: auto;
      background: #ffffff;
      border: 1px solid rgba(13, 110, 253, 0.18);
      border-radius: 0.85rem;
      box-shadow: 0 0.65rem 1.5rem rgba(15, 23, 42, 0.14);
      padding: 0.35rem;
    }

    .education-suggestion-panel::-webkit-scrollbar {
      width: 6px;
    }

    .education-suggestion-panel::-webkit-scrollbar-track {
      background: transparent;
    }

    .education-suggestion-panel::-webkit-scrollbar-thumb {
      background: rgba(15, 23, 42, 0.22);
      border-radius: 999px;
    }

    .education-suggestion-panel::-webkit-scrollbar-thumb:hover {
      background: rgba(15, 23, 42, 0.34);
    }

    .education-suggestion-item {
      width: 100%;
      border: 0;
      background: transparent;
      text-align: left;
      padding: 0.55rem 0.7rem;
      border-radius: 0.65rem;
      font-size: 0.92rem;
      line-height: 1.25;
      color: #0f172a;
    }

    .education-suggestion-item:hover,
    .education-suggestion-item:focus {
      background: rgba(13, 110, 253, 0.08);
      outline: none;
    }
  `;

  document.head.appendChild(style);
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1C
// Read the current merged datalist values. This supports both seeded
// hardcoded suggestions and saved values learned from employee records.
function getEducationSuggestionValuesFromDatalist(datalist) {
  const valuesByKey = new Map();

  Array.from(datalist?.options || []).forEach((option) => {
    const value = String(option.value || "").trim();
    if (!value) return;

    const key = value.toLowerCase().replace(/\s+/g, " ");

    if (!valuesByKey.has(key)) {
      valuesByKey.set(key, value);
    }
  });

  return Array.from(valuesByKey.values()).sort((a, b) =>
    a.localeCompare(b, undefined, { sensitivity: "base" }),
  );
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1C
// Keep the popup compact. Matching starts-with values come first, then
// contains matches. This avoids a tall, heavy dropdown.
function getMatchingEducationSuggestionValues(values = [], searchText = "") {
  const searchKey = String(searchText || "").trim().toLowerCase();

  if (!searchKey) {
    return values.slice(0, 10);
  }

  const startsWithMatches = values.filter((value) =>
    value.toLowerCase().startsWith(searchKey),
  );

  const containsMatches = values.filter((value) => {
    const lowerValue = value.toLowerCase();

    return (
      !lowerValue.startsWith(searchKey) &&
      lowerValue.includes(searchKey)
    );
  });

  return [...startsWithMatches, ...containsMatches].slice(0, 10);
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1C
// Render the compact custom suggestion panel for one Education input.
function renderEducationSuggestionPanel(input, datalist, panel) {
  if (!input || !datalist || !panel) return;

  const values = getEducationSuggestionValuesFromDatalist(datalist);
  const matches = getMatchingEducationSuggestionValues(values, input.value);

  panel.innerHTML = "";

  if (!matches.length) {
    panel.classList.add("d-none");
    return;
  }

  matches.forEach((value) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "education-suggestion-item";
    button.textContent = value;

    button.addEventListener("mousedown", (event) => {
      event.preventDefault();

      input.value = value;
      panel.classList.add("d-none");

      // Keep existing employee save-button readiness in sync.
      input.dispatchEvent(new Event("input", { bubbles: true }));
      input.dispatchEvent(new Event("change", { bubbles: true }));
    });

    panel.appendChild(button);
  });

  panel.classList.remove("d-none");
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1C
// Bind one input to the compact suggestion panel and disable the native
// datalist popup only for this app-controlled field.
function bindEducationSuggestionField(input, datalist) {
  if (!input || !datalist) return;
  if (input.dataset.educationSuggestionPanelBound === "true") return;

  input.dataset.educationSuggestionPanelBound = "true";
  input.dataset.originalList = input.getAttribute("list") || "";

  // Disable the native browser popup so the large black scrollbar disappears.
  input.removeAttribute("list");

  const fieldWrapper = input.parentElement;
  if (!fieldWrapper) return;

  fieldWrapper.classList.add("position-relative");

  const panel = document.createElement("div");
  panel.className = "education-suggestion-panel d-none";
  panel.setAttribute("role", "listbox");

  input.insertAdjacentElement("afterend", panel);

  input.addEventListener("focus", () => {
    renderEducationSuggestionPanel(input, datalist, panel);
  });

  input.addEventListener("input", () => {
    renderEducationSuggestionPanel(input, datalist, panel);
  });

  input.addEventListener("blur", () => {
    window.setTimeout(() => {
      panel.classList.add("d-none");
    }, 150);
  });

  document.addEventListener("click", (event) => {
    if (fieldWrapper.contains(event.target)) return;
    panel.classList.add("d-none");
  });
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1C
// Apply compact suggestion panels to School / Institution and Course only.
// This keeps the change focused and avoids touching unrelated dropdowns.
function bindEducationSuggestionPanels() {
  injectEducationSuggestionPanelStyles();

  bindEducationSuggestionField(
    state.dom.employeeEducationInstitutionName,
    state.dom.employeeEducationInstitutionSuggestions,
  );

  bindEducationSuggestionField(
    state.dom.employeeEducationFieldOfStudy,
    state.dom.employeeEducationCourseSuggestions,
  );
}

// DYNAMIC EDUCATION SUGGESTIONS - STEP 1A
// Load saved School / Institution and Course / Field of Study values from
// employee_education_records and use them as live suggestions.
async function refreshEducationSuggestionLists() {
  const institutionList = state.dom.employeeEducationInstitutionSuggestions;
  const courseList = state.dom.employeeEducationCourseSuggestions;

  if (!institutionList && !courseList) return;

  try {
    const supabase = getSupabaseClient();

    const { data, error } = await supabase
      .from("employee_education_records")
      .select("institution_name, field_of_study")
      .limit(1000);

    if (error) throw error;

    const rows = Array.isArray(data) ? data : [];

    renderEducationDatalistOptions(
      institutionList,
      getUniqueSortedEducationSuggestionValues(rows, "institution_name"),
    );

    renderEducationDatalistOptions(
      courseList,
      getUniqueSortedEducationSuggestionValues(rows, "field_of_study"),
    );
  } catch (error) {
    // DYNAMIC EDUCATION SUGGESTIONS - STEP 1A
    // Suggestions are helpful only; they must not block HR from creating
    // or editing employee records if the suggestion query fails.
    console.error("Error loading education suggestion lists:", error);
  }
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-3
// Normalise staged beneficiary/dependant rows before saving to Supabase.
// This keeps employee_dependants as the repeatable child table and avoids
// reinserting display-only fields when HR edits an existing employee.
function normaliseEmployeeDependantRecordForSave(record = {}, employeeId = "") {
  const employeeKey = String(employeeId || "").trim();

  // HRP-80 - TENANT DATA SEGMENTATION - STEP 7C
  // Beneficiary/dependant child rows inherit the logged-in HR user's tenant.
  const tenantId = getRequiredTenantIdForHrEmployeeData();

  return {
    employee_id: employeeKey,
    tenant_id: tenantId,
    full_name: String(record.full_name || "").trim(),
    relationship: String(record.relationship || "").trim(),
    date_of_birth: record.date_of_birth || null,
    phone_number: String(record.phone_number || "").trim() || null,
    coverage_type: String(record.coverage_type || "").trim(),
    status: "Active",
    created_by: state.currentUser?.id || null,
    updated_by: state.currentUser?.id || null,
  };
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-3
// Build all beneficiary/dependant rows for save.
// Staged rows come from Add Beneficiary / Dependant. A visible un-staged row
// is also saved so HR does not lose the final entry before clicking Save.
function buildEmployeeDependantRowsForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();

  if (!employeeKey) {
    return [];
  }

  const stagedRecords = Array.isArray(state.pendingEmployeeDependants)
    ? state.pendingEmployeeDependants
    : [];

  const recordsToSave = [...stagedRecords];

  if (isEmployeeDependantStarted()) {
    recordsToSave.push(buildEmployeeDependantRecordFromCurrentFields());
  }

  return recordsToSave
    .map((record) => normaliseEmployeeDependantRecordForSave(record, employeeKey))
    .filter((record) => record.full_name && record.relationship && record.coverage_type);
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-3
// Save beneficiaries/dependants by replacing this employee's current child rows.
// This mirrors Education, Address, and Next of Kin behaviour so removed rows
// stay removed after HR saves and reopens the employee profile.
async function saveEmployeeDependantRecordsForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return;

  const supabase = getSupabaseClient();
  const dependantRows = buildEmployeeDependantRowsForEmployee(employeeKey);

  const { error: deleteError } = await supabase
    .from("employee_dependants")
    .delete()
    .eq("employee_id", employeeKey);

  if (deleteError) throw deleteError;

  if (!dependantRows.length) return;

  const { error: insertError } = await supabase
    .from("employee_dependants")
    .insert(dependantRows);

  if (insertError) throw insertError;
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-3
// Clear dependant/beneficiary inputs and the saved-record display when the
// employee form returns to create mode.
function resetEmployeeDependantFields() {
  clearEmployeeDependantInputFields();
  clearEmployeeDependantValidationState();

  state.pendingEmployeeDependants = [];
  renderEmployeeDependantRecords([]);
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-3
// Load saved beneficiaries/dependants into the staged list when HR edits an
// employee. The visible form remains blank so HR can add another clean row.
async function loadEmployeeDependantRecordsForEdit(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  resetEmployeeDependantFields();

  if (!employeeKey) return;

  try {
    const supabase = getSupabaseClient();

    const { data, error } = await supabase
      .from("employee_dependants")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("created_at", { ascending: true });

    if (error) throw error;

    const records = Array.isArray(data)
      ? data.map((record) => ({
        full_name: record.full_name || "",
        relationship: record.relationship || "",
        date_of_birth: record.date_of_birth || null,
        phone_number: record.phone_number || null,
        coverage_type: record.coverage_type || "",
      }))
      : [];

    state.pendingEmployeeDependants = records;

    renderEmployeeDependantRecords(state.pendingEmployeeDependants);
    clearEmployeeDependantValidationState();
    updateEmployeeSaveButtonState();
  } catch (error) {
    console.error("Error loading employee beneficiaries/dependants:", error);

    showPageAlert(
      "warning",
      "Employee profile opened, but saved beneficiaries/dependants could not be loaded. Please refresh and try again.",
    );
  }
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-3
// Keep Save button readiness aligned with optional beneficiary/dependant rows.
// Empty is allowed, but a started row must have Full Name, Relationship, and Type.
function areEmployeeDependantFieldsReadyForSubmit() {
  if (!isEmployeeDependantStarted()) {
    return true;
  }

  const fields = getEmployeeDependantFields();

  return Boolean(
    String(fields.fullName?.value || "").trim() &&
    String(fields.relationship?.value || "").trim() &&
    String(fields.coverageType?.value || "").trim(),
  );
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Keep dependant/beneficiary field access in one place.
function getEmployeeDependantFields() {
  return {
    fullName: state.dom.employeeDependantFullName,
    relationship: state.dom.employeeDependantRelationship,
    dateOfBirth: state.dom.employeeDependantDateOfBirth,
    phoneNumber: state.dom.employeeDependantPhoneNumber,
    coverageType: state.dom.employeeDependantCoverageType,
  };
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Dependant/beneficiary records are optional.
// If HR starts one, name, relationship, and type are required.
function isEmployeeDependantStarted() {
  const fields = getEmployeeDependantFields();

  return [
    fields.fullName,
    fields.relationship,
    fields.dateOfBirth,
    fields.phoneNumber,
    fields.coverageType,
  ].some((field) => Boolean(String(field?.value || "").trim()));
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Clear validation styling from dependant/beneficiary fields.
function clearEmployeeDependantValidationState() {
  const fields = getEmployeeDependantFields();

  [
    fields.fullName,
    fields.relationship,
    fields.coverageType,
  ].forEach((field) => {
    field?.classList.remove("is-invalid");
  });
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Validate the visible dependant/beneficiary entry before staging it.
function validateEmployeeDependantFields() {
  clearEmployeeDependantValidationState();

  if (!isEmployeeDependantStarted()) {
    showPageAlert(
      "warning",
      "Enter beneficiary or dependant details before adding the record.",
    );
    return false;
  }

  const fields = getEmployeeDependantFields();
  let firstInvalidField = null;

  if (!String(fields.fullName?.value || "").trim()) {
    fields.fullName?.classList.add("is-invalid");
    firstInvalidField ||= fields.fullName;
  }

  if (!String(fields.relationship?.value || "").trim()) {
    fields.relationship?.classList.add("is-invalid");
    firstInvalidField ||= fields.relationship;
  }

  if (!String(fields.coverageType?.value || "").trim()) {
    fields.coverageType?.classList.add("is-invalid");
    firstInvalidField ||= fields.coverageType;
  }

  if (firstInvalidField) {
    showPageAlert(
      "warning",
      "Please complete Full Name, Relationship, and Type before adding the record.",
    );
    firstInvalidField.focus?.();
    return false;
  }

  return true;
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Build one staged dependant/beneficiary row from the visible form.
function buildEmployeeDependantRecordFromCurrentFields() {
  const fields = getEmployeeDependantFields();

  return {
    full_name: String(fields.fullName?.value || "").trim(),
    relationship: String(fields.relationship?.value || "").trim(),
    date_of_birth: String(fields.dateOfBirth?.value || "").trim() || null,
    phone_number: String(fields.phoneNumber?.value || "").trim() || null,
    coverage_type: String(fields.coverageType?.value || "").trim(),
  };
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Render staged beneficiary/dependant records under the form.
function renderEmployeeDependantRecords(records = []) {
  const emptyState = state.dom.employeeDependantsEmptyState;
  const list = state.dom.employeeDependantsRecordsList;

  if (!emptyState || !list) return;

  if (!records.length) {
    emptyState.classList.remove("d-none");
    list.classList.add("d-none");
    list.innerHTML = "";
    return;
  }

  emptyState.classList.add("d-none");
  list.classList.remove("d-none");

  list.innerHTML = records
    .map((record, index) => {
      const fullName = escapeHtml(record.full_name || "--");
      const relationship = escapeHtml(record.relationship || "--");
      const coverageType = escapeHtml(record.coverage_type || "--");
      const dateOfBirth = record.date_of_birth
        ? ` • DOB: ${escapeHtml(record.date_of_birth)}`
        : "";
      const phoneNumber = record.phone_number
        ? ` • ${escapeHtml(record.phone_number)}`
        : "";

      return `
        <!-- EMPLOYEE ORIGIN AND IDENTITY DETAILS - STEP 6C
             Mark each rendered beneficiary/dependant row so the form progress
             stepper can reliably detect saved/staged dependant records. -->
        <div class="list-group-item" data-dependant-record="true">
          <div class="d-flex flex-column flex-md-row justify-content-between gap-2">
            <div>
              <div class="fw-semibold">${fullName}</div>
              <div class="small text-secondary">${relationship}${dateOfBirth}${phoneNumber}</div>
            </div>

            <div class="d-flex align-items-start gap-2 flex-wrap">
              <span class="badge text-bg-light border">${coverageType}</span>

              <button
                type="button"
                class="btn btn-sm btn-outline-danger"
                title="Remove beneficiary or dependant"
                aria-label="Remove beneficiary or dependant"
                onclick="window.hrRemoveEmployeeDependantRecord(${index})"
              >
                <i class="bi bi-trash"></i>
              </button>
            </div>
          </div>
        </div>
      `;
    })
    .join("");
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Clear visible dependant/beneficiary input fields after staging.
function clearEmployeeDependantInputFields() {
  const fields = getEmployeeDependantFields();

  [
    fields.fullName,
    fields.relationship,
    fields.dateOfBirth,
    fields.phoneNumber,
    fields.coverageType,
  ].forEach((field) => {
    if (!field) return;
    field.value = "";
    field.classList.remove("is-invalid");
  });
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Add the visible dependant/beneficiary form into the staged list.
function stageEmployeeDependantRecordFromForm() {
  if (!validateEmployeeDependantFields()) {
    return;
  }

  const stagedRecord = buildEmployeeDependantRecordFromCurrentFields();

  state.pendingEmployeeDependants = [
    ...(state.pendingEmployeeDependants || []),
    stagedRecord,
  ];

  clearEmployeeDependantInputFields();
  renderEmployeeDependantRecords(state.pendingEmployeeDependants);
  updateEmployeeSaveButtonState();

  showDashboardToast(
    "success",
    "Beneficiary / dependant added",
    "Save the employee profile to keep this record.",
  );
}

// EMPLOYEE BIODATA COMPLETION - STEP 6D-2
// Remove one staged dependant/beneficiary record before employee save.
function removeEmployeeDependantRecordAtIndex(recordIndex) {
  const index = Number(recordIndex);

  if (!Number.isInteger(index) || index < 0) {
    showPageAlert("warning", "The selected beneficiary/dependant could not be removed.");
    return;
  }

  const records = Array.isArray(state.pendingEmployeeDependants)
    ? [...state.pendingEmployeeDependants]
    : [];

  if (!records[index]) {
    showPageAlert("warning", "The selected beneficiary/dependant could not be found.");
    return;
  }

  records.splice(index, 1);
  state.pendingEmployeeDependants = records;

  renderEmployeeDependantRecords(state.pendingEmployeeDependants);
  updateEmployeeSaveButtonState();

  showDashboardToast(
    "success",
    "Beneficiary / dependant removed",
    "Save the employee profile to keep this change.",
  );
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-3B
// Reset Education fields and the Saved Education Records display.
function resetEmployeeEducationFields() {
  const fields = getEmployeeEducationFields();

  [
    fields.institutionName,
    fields.qualification,
    fields.fieldOfStudy,
    fields.graduationYear,
    fields.educationStatus,
    fields.highestQualification,
  ].forEach((field) => {
    if (!field) return;
    field.value = "";
    field.classList.remove("is-invalid");
  });

  if (fields.highestQualification) {
    fields.highestQualification.value = "false";
  }

  // EMPLOYEE BIODATA COMPLETION - STEP 6C-4B
  // Reset staged education records when the employee form is cleared.
  state.pendingEmployeeEducationRecords = [];

  renderEmployeeEducationRecords([]);
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-3B
// Load the first saved education record back into the visible form fields.
function applyEmployeeEducationRecordToFields(record = {}) {
  const fields = getEmployeeEducationFields();

  if (fields.institutionName) {
    fields.institutionName.value = record.institution_name || "";
  }

  if (fields.qualification) {
    fields.qualification.value = record.qualification || "";
  }

  if (fields.fieldOfStudy) {
    fields.fieldOfStudy.value = record.field_of_study || "";
  }

  if (fields.graduationYear) {
    fields.graduationYear.value = record.graduation_year
      ? String(record.graduation_year)
      : "";
  }

  if (fields.educationStatus) {
    fields.educationStatus.value = record.education_status || "";
  }

  if (fields.highestQualification) {
    fields.highestQualification.value = String(Boolean(record.is_highest_qualification));
  }
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-4A
// Build one staged education row from the visible Education form.
// This lets HR add several qualifications before saving the employee profile.
function buildEmployeeEducationRecordFromCurrentFields() {
  const fields = getEmployeeEducationFields();
  const graduationYearValue = String(fields.graduationYear?.value || "").trim();

  return {
    institution_name: String(fields.institutionName?.value || "").trim(),
    qualification: String(fields.qualification?.value || "").trim(),
    field_of_study: String(fields.fieldOfStudy?.value || "").trim() || null,
    graduation_year: graduationYearValue ? Number(graduationYearValue) : null,
    education_status: String(fields.educationStatus?.value || "").trim() || "Completed",
    is_highest_qualification:
      String(fields.highestQualification?.value || "false") === "true",
  };
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-4A
// Add the current Education form values into the staged list, then clear
// the visible fields so HR can add another qualification.
function stageEmployeeEducationRecordFromForm() {
  if (!validateEmployeeEducationFields()) {
    updateEmployeeSaveButtonState();
    return;
  }

  if (!isEmployeeEducationStarted()) {
    showPageAlert(
      "warning",
      "Enter education details before adding an education record.",
    );
    return;
  }

  const stagedRecord = buildEmployeeEducationRecordFromCurrentFields();

  state.pendingEmployeeEducationRecords = [
    ...(state.pendingEmployeeEducationRecords || []),
    stagedRecord,
  ];

  clearEmployeeEducationValidationState();

  const fields = getEmployeeEducationFields();

  [
    fields.institutionName,
    fields.qualification,
    fields.fieldOfStudy,
    fields.graduationYear,
    fields.educationStatus,
  ].forEach((field) => {
    if (field) field.value = "";
  });

  if (fields.highestQualification) {
    fields.highestQualification.value = "false";
  }

  renderEmployeeEducationRecords(state.pendingEmployeeEducationRecords);
  updateEmployeeSaveButtonState();

  showPageAlert(
    "success",
    "Education record added. Save the employee profile to keep the changes.",
  );
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-4C
// Render staged/saved education records with a remove action.
// HR can remove an incorrect qualification before saving the employee profile.
function renderEmployeeEducationRecords(records = []) {
  const emptyState = state.dom.employeeEducationEmptyState;
  const list = state.dom.employeeEducationRecordsList;

  if (!emptyState || !list) return;

  if (!records.length) {
    emptyState.classList.remove("d-none");
    list.classList.add("d-none");
    list.innerHTML = "";
    return;
  }

  emptyState.classList.add("d-none");
  list.classList.remove("d-none");

  list.innerHTML = records
    .map((record, index) => {
      const institution = escapeHtml(record.institution_name || "--");
      const qualification = escapeHtml(record.qualification || "--");
      const fieldOfStudy = escapeHtml(record.field_of_study || "--");
      const year = record.graduation_year
        ? ` • ${escapeHtml(String(record.graduation_year))}`
        : "";
      const status = escapeHtml(record.education_status || "Completed");
      const highestBadge = record.is_highest_qualification
        ? `<span class="badge text-bg-primary ms-2">Highest</span>`
        : "";

      return `
        <div class="list-group-item">
          <div class="d-flex flex-column flex-md-row justify-content-between gap-2">
            <div>
              <div class="fw-semibold">${qualification}${highestBadge}</div>
              <div class="small text-secondary">${institution}</div>
              <div class="small text-secondary">${fieldOfStudy}${year}</div>
            </div>

            <div class="d-flex align-items-start gap-2 flex-wrap">
              <span class="badge text-bg-light border">${status}</span>

              <button
                type="button"
                class="btn btn-sm btn-outline-danger"
                title="Remove education record"
                aria-label="Remove education record"
                onclick="window.hrRemoveEmployeeEducationRecord(${index})"
              >
                <i class="bi bi-trash"></i>
              </button>
            </div>
          </div>
        </div>
      `;
    })
    .join("");
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-4C
// Remove one staged education record from the current employee edit session.
// The actual database change is saved when HR clicks Update Employee Profile.
function removeEmployeeEducationRecordAtIndex(recordIndex) {
  const index = Number(recordIndex);

  if (!Number.isInteger(index) || index < 0) {
    showPageAlert("warning", "The selected education record could not be removed.");
    return;
  }

  const records = Array.isArray(state.pendingEmployeeEducationRecords)
    ? [...state.pendingEmployeeEducationRecords]
    : [];

  if (!records[index]) {
    showPageAlert("warning", "The selected education record could not be found.");
    return;
  }

  const confirmed = window.confirm(
    "Remove this education record from the employee profile? Click Update Employee Profile afterwards to save the change.",
  );

  if (!confirmed) return;

  records.splice(index, 1);
  state.pendingEmployeeEducationRecords = records;

  renderEmployeeEducationRecords(state.pendingEmployeeEducationRecords);
  updateEmployeeSaveButtonState();

  showPageAlert(
    "success",
    "Education record removed. Click Update Employee Profile to save the change.",
  );

  showDashboardToast(
    "success",
    "Education record removed",
    "Click Update Employee Profile to save this change permanently.",
  );
}

// EMPLOYEE BIODATA COMPLETION - STEP 6C-3B
// Load saved education records when HR edits an employee.
async function loadEmployeeEducationRecordsForEdit(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  resetEmployeeEducationFields();

  if (!employeeKey) return;

  try {
    const supabase = getSupabaseClient();

    const { data, error } = await supabase
      .from("employee_education_records")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("is_highest_qualification", { ascending: false })
      .order("created_at", { ascending: true });

    if (error) throw error;

    // EMPLOYEE BIODATA COMPLETION - STEP 6C-4B
    // Existing saved education records become the staged list for this edit session.
    // The visible form stays empty so HR can add another qualification cleanly.
    const records = Array.isArray(data)
      ? data.map((record) => ({
        institution_name: record.institution_name || "",
        qualification: record.qualification || "",
        field_of_study: record.field_of_study || null,
        graduation_year: record.graduation_year || null,
        education_status: record.education_status || "Completed",
        is_highest_qualification: Boolean(record.is_highest_qualification),
      }))
      : [];

    state.pendingEmployeeEducationRecords = records;

    renderEmployeeEducationRecords(state.pendingEmployeeEducationRecords);
    clearEmployeeEducationValidationState();
    updateEmployeeSaveButtonState();
  } catch (error) {
    console.error("Error loading employee education records:", error);

    showPageAlert(
      "warning",
      "Employee profile opened, but saved education records could not be loaded. Please refresh and try again.",
    );
  }
}

// ASSIGN LINE MANAGER - STEP 1E
// Display labels for standard system roles.
// Custom roles are displayed as typed by HR.
const EMPLOYEE_SYSTEM_ROLE_LABELS = {
  employee: "Employee",
  manager: "Manager",
  hr: "HR",
  admin: "Admin",
};

// ASSIGN LINE MANAGER - STEP 1E
// Convert a saved role value into a friendly display label.
function formatEmployeeSystemRoleLabel(roleValue = "") {
  const value = String(roleValue || "").trim();

  if (!value) {
    return "No role set";
  }

  return EMPLOYEE_SYSTEM_ROLE_LABELS[value] || value;
}

// ASSIGN LINE MANAGER - STEP 1E
// Return standard role values already present in the System Role dropdown.
function getStandardEmployeeSystemRoleValues() {
  const select = state.dom.systemRole;
  if (!select) return new Set();

  return new Set(
    Array.from(select.options)
      .map((option) => String(option.value || "").trim())
      .filter((value) => value && value !== "custom"),
  );
}

// ASSIGN LINE MANAGER - STEP 1E
// Read the role that should be saved.
// If HR selects Other, use the custom role field.
function getSelectedEmployeeSystemRoleValue() {
  const selectedRole = String(state.dom.systemRole?.value || "").trim();

  if (selectedRole === "custom") {
    return String(state.dom.customSystemRole?.value || "").trim();
  }

  return selectedRole;
}

// ASSIGN LINE MANAGER - STEP 1E
// Show the custom role input only when HR selects "Other / Add new role".
function syncCustomSystemRoleVisibility() {
  const isCustom = String(state.dom.systemRole?.value || "") === "custom";

  state.dom.customSystemRole?.classList.toggle("d-none", !isCustom);

  if (!isCustom && state.dom.customSystemRole) {
    state.dom.customSystemRole.value = "";
  }
}
// HR SELF-ROLE PROTECTION - STEP 1
// Detect whether the employee being edited is the currently signed-in HR user.
// Match linked auth user first, then work email. This mirrors the existing
// current-user employee resolution pattern used by dashboard permission checks.
function isCurrentSignedInEmployeeRecord(employee = {}) {
  const currentUserId = String(state.currentUser?.id || "").trim();
  const currentProfileEmail = String(state.currentProfile?.email || "")
    .trim()
    .toLowerCase();

  const employeeUserId = String(employee.user_id || employee.auth_user_id || "").trim();
  const employeeWorkEmail = String(employee.work_email || "").trim().toLowerCase();

  return Boolean(
    (currentUserId && employeeUserId && currentUserId === employeeUserId) ||
    (currentProfileEmail && employeeWorkEmail && currentProfileEmail === employeeWorkEmail),
  );
}

// HR SELF-ROLE PROTECTION - STEP 1
// Applies only in edit mode when HR opens their own employee row.
function isEditingCurrentSignedInEmployeeRecord() {
  return Boolean(
    state.currentEditingEmployee &&
    isCurrentSignedInEmployeeRecord(state.currentEditingEmployee),
  );
}

// HR SELF-ROLE / PEER HR PROTECTION - STEP 2
// Protect System Role when HR edits:
// 1. their own employee row, or
// 2. any employee row that is already saved as HR.
//
// This keeps normal biodata maintenance available, but prevents HR-to-HR
// access changes from the employee list. HR access must be managed by Admin.
function syncHrSelfRoleProtectionState() {
  const savedRole = normaliseHrBusinessRole(
    state.currentEditingEmployee?.system_role || "",
  );

  const isOwnEmployeeRecord = isEditingCurrentSignedInEmployeeRecord();
  const isSavedHrEmployeeRecord = savedRole === "hr";
  const shouldProtectSystemRole =
    Boolean(state.currentEditingEmployee) &&
    (isOwnEmployeeRecord || isSavedHrEmployeeRecord);

  state.dom.hrSelfRoleProtectionNotice?.classList.toggle(
    "d-none",
    !shouldProtectSystemRole,
  );

  if (shouldProtectSystemRole) {
    setEmployeeSystemRoleFieldValue(state.currentEditingEmployee?.system_role || "");
  }

  if (state.dom.systemRole) {
    state.dom.systemRole.disabled = shouldProtectSystemRole;
    state.dom.systemRole.setAttribute("aria-disabled", String(shouldProtectSystemRole));
    state.dom.systemRole.classList.toggle("bg-light", shouldProtectSystemRole);
  }

  if (state.dom.customSystemRole) {
    state.dom.customSystemRole.disabled = shouldProtectSystemRole;
    state.dom.customSystemRole.setAttribute("aria-disabled", String(shouldProtectSystemRole));
    state.dom.customSystemRole.classList.toggle("bg-light", shouldProtectSystemRole);
  }
}

// HR SELF-ROLE / PEER HR PROTECTION - STEP 2
// Defensive save guard:
// - HR cannot change their own System Role.
// - HR cannot change another saved HR employee's System Role.
// This catches browser-tool manipulation even when the dropdown is disabled.
function isOwnSystemRoleChangeBlockedForSubmit() {
  const savedRole = normaliseHrBusinessRole(
    state.currentEditingEmployee?.system_role || "",
  );

  const selectedRole = normaliseHrBusinessRole(
    getSelectedEmployeeSystemRoleValue(),
  );

  const isOwnEmployeeRecord = isEditingCurrentSignedInEmployeeRecord();
  const isSavedHrEmployeeRecord = savedRole === "hr";

  return (
    Boolean(state.currentEditingEmployee) &&
    (isOwnEmployeeRecord || isSavedHrEmployeeRecord) &&
    selectedRole !== savedRole
  );
}

// HR SELF-ROLE / PEER HR PROTECTION - STEP 2
// Show one clear message for protected HR access, whether HR is editing
// their own row or another employee row already saved as HR.
function showOwnSystemRoleChangeBlockedMessage() {
  setEmployeeSystemRoleFieldValue(state.currentEditingEmployee?.system_role || "");
  syncHrSelfRoleProtectionState();

  showPageAlert(
    "warning",
    "HR dashboard access is protected. Ask Admin to update HR access for this employee.",
  );

  showDashboardToast(
    "warning",
    "HR access protected",
    "System Role cannot be changed for an HR employee from the employee list.",
  );
}
// HR ROLE ASSIGNMENT SAFEGUARD - STEP 1
// Require confirmation only when HR access is newly being assigned.
// Existing HR employees can still be edited without repeatedly confirming
// the same already-saved HR role.
function isHrRoleAssignmentConfirmationRequired() {
  const selectedRole = normaliseHrBusinessRole(state.dom.systemRole?.value || "");
  const savedRole = normaliseHrBusinessRole(state.currentEditingEmployee?.system_role || "");

  return selectedRole === "hr" && savedRole !== "hr";
}

// HR ROLE ASSIGNMENT SAFEGUARD - STEP 1
// Show the amber warning only when HR is being newly assigned.
// Hide and clear it when HR changes back to Employee, Manager, blank, or custom.
function syncHrRoleAssignmentWarning() {
  const isRequired = isHrRoleAssignmentConfirmationRequired();

  state.dom.hrRoleAssignmentWarning?.classList.toggle("d-none", !isRequired);

  if (!isRequired && state.dom.confirmHrRoleAssignment) {
    state.dom.confirmHrRoleAssignment.checked = false;
    state.dom.confirmHrRoleAssignment.classList.remove("is-invalid");
  }
}

// HR ROLE ASSIGNMENT SAFEGUARD - STEP 1
// Employee save readiness must include the HR confirmation checkbox
// when HR access is being newly assigned.
function isHrRoleAssignmentConfirmedForSubmit() {
  if (!isHrRoleAssignmentConfirmationRequired()) {
    return true;
  }

  return Boolean(state.dom.confirmHrRoleAssignment?.checked);
}

// HR ROLE ASSIGNMENT SAFEGUARD - STEP 1
// Defensive save guard in case a disabled button is bypassed.
function showHrRoleAssignmentConfirmationWarning() {
  syncHrRoleAssignmentWarning();

  state.dom.confirmHrRoleAssignment?.classList.add("is-invalid");

  showPageAlert(
    "warning",
    "Please confirm that this employee is authorised to perform HR administration before saving the HR role.",
  );

  showDashboardToast(
    "warning",
    "HR access confirmation required",
    "Tick the HR authorisation confirmation box before saving this employee as HR.",
  );
}

// ASSIGN LINE MANAGER - STEP 1E
// Load saved role values correctly in edit mode.
// Standard roles select the dropdown option.
// Unknown/custom saved roles show in the custom role input.
function setEmployeeSystemRoleFieldValue(roleValue = "") {
  const role = String(roleValue || "").trim();

  if (!state.dom.systemRole) return;

  if (!role) {
    state.dom.systemRole.value = "";
    if (state.dom.customSystemRole) state.dom.customSystemRole.value = "";
    syncCustomSystemRoleVisibility();
    syncHrRoleAssignmentWarning();
    return;
  }

  const standardRoles = getStandardEmployeeSystemRoleValues();

  if (standardRoles.has(role)) {
    state.dom.systemRole.value = role;
    if (state.dom.customSystemRole) state.dom.customSystemRole.value = "";
  } else {
    state.dom.systemRole.value = "custom";
    if (state.dom.customSystemRole) state.dom.customSystemRole.value = role;
  }

  syncCustomSystemRoleVisibility();
  syncHrRoleAssignmentWarning();
}

// EMPLOYEE CUSTOM ID AUTO GENERATION - STEP 1D FIX
// Employee form follows the same button behaviour as the other HR/payroll forms.
// Incomplete form = grey and disabled.
// Complete form = blue and enabled.
// This check is non-invasive and does not show red validation while HR is typing.
function isEmployeeFormReadyForSubmit() {
  const requiredFields = [
    state.dom.firstName,
    state.dom.lastName,
    state.dom.workEmail,
    state.dom.department,
    state.dom.jobTitle,
    state.dom.employmentDate,
  ];

  const hasRequiredValues = requiredFields.every((field) =>
    Boolean(String(field?.value || "").trim()),
  );

  const workEmail = String(state.dom.workEmail?.value || "").trim();
  const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const hasValidWorkEmail = emailPattern.test(workEmail);

  // EMPLOYEE BIODATA COMPLETION - STEP 2G
  // Optional Personal Email should not be required, but should block Save
  // if HR enters an invalid email format.
  const personalEmail = String(state.dom.personalEmail?.value || "").trim();
  const hasValidPersonalEmail = !personalEmail || emailPattern.test(personalEmail);

  const employmentDateValue = String(state.dom.employmentDate?.value || "").trim();
  const exitDateValue = String(state.dom.exitDate?.value || "").trim();
  const hasValidExitDate =
    !employmentDateValue ||
    !exitDateValue ||
    new Date(exitDateValue).getTime() >= new Date(employmentDateValue).getTime();

  // EMPLOYEE BIODATA COMPLETION - STEP 3I
  // Additional reporting manager rows are optional.
  // But if HR adds a row, the secondary manager must be selected before Save turns blue.
  const reportingLineRows = Array.from(
    state.dom.employeeReportingLinesList?.querySelectorAll("[data-employee-reporting-line-row]") || [],
  );

  const hasValidReportingLines = reportingLineRows.every((row) =>
    Boolean(String(row.querySelector("[data-reporting-line-manager-id]")?.value || "").trim()),
  );

  // EMPLOYEE BIODATA COMPLETION - STEP 4H
  // Address groups are optional. If HR starts Current or Permanent Address,
  // the main address line must be present before Save turns blue.
  const hasValidAddressFields = areEmployeeAddressFieldsReadyForSubmit();

  // EMPLOYEE BIODATA COMPLETION - STEP 5H
  // Next of Kin is optional. If HR starts it, Full Name, Relationship,
  // Phone Number, and optional Email format must be valid before Save turns blue.
  const hasValidNextOfKinFields = areEmployeeNextOfKinFieldsReadyForSubmit();

  // EMPLOYEE BIODATA COMPLETION - STEP 6C-3A
  // Education is optional. If HR starts it, Institution and Qualification
  // must be completed, and Graduation Year must be realistic.
  const hasValidEducationFields = areEmployeeEducationFieldsReadyForSubmit();

  // EMPLOYEE BIODATA COMPLETION - STEP 6D-3
  // Beneficiaries/dependants are optional. If HR starts a visible row,
  // it must be complete before Create/Update Employee is enabled.
  const hasValidDependantFields = areEmployeeDependantFieldsReadyForSubmit();

  // HR ROLE ASSIGNMENT SAFEGUARD - STEP 1
  // If HR access is newly selected, Save must remain disabled until
  // the authorisation checkbox is ticked.
  const hasValidHrRoleAssignmentConfirmation =
    isHrRoleAssignmentConfirmedForSubmit();

  // HR SELF-ROLE PROTECTION - STEP 1
  // Save must not become active if the signed-in HR user's own System Role
  // has somehow been changed through browser tools.
  const hasValidSelfRoleProtection =
    !isOwnSystemRoleChangeBlockedForSubmit();

  return (
    hasRequiredValues &&
    hasValidWorkEmail &&
    hasValidPersonalEmail &&
    hasValidExitDate &&
    hasValidReportingLines &&
    hasValidAddressFields &&
    hasValidNextOfKinFields &&
    hasValidEducationFields &&
    hasValidDependantFields &&
    hasValidHrRoleAssignmentConfirmation &&
    hasValidSelfRoleProtection
  );
}

// EMPLOYEE CUSTOM ID AUTO GENERATION - STEP 1D FIX
// Updates the Create/Update Employee button without submitting the form.
function updateEmployeeSaveButtonState() {
  setPrimaryActionButtonReadyState(
    state.dom.saveEmployeeBtn,
    isEmployeeFormReadyForSubmit(),
  );
  updateEmployeeFormSteps();
}

// BEXHR FORM PROGRESS STEPPER
// Marks each form section step as done when the user has entered data.
// Step 1 (Core Details) is always marked done — it contains the required fields.
// All other sections are optional and light up as the user fills them in.
function updateEmployeeFormSteps() {
  const hasVal = (el) => Boolean(String(el?.value || "").trim());

  const stepDone = [
    // Step 1: Core Details — always active once form is open
    true,
    // Step 2: Reporting Lines — primary line manager selected
    hasVal(state.dom.assignedLineManagerEmployeeId),
    // EMPLOYEE ORIGIN AND IDENTITY DETAILS - STEP 6C
    // Step 3: Dependants — complete when HR has either started a visible
    // dependant row or has saved/staged dependant records in the list.
    // The old selector checked [data-dependant-id], but rendered rows do not
    // have database IDs because rows are staged/replaced on employee save.
    hasVal(state.dom.employeeDependantFullName) ||
    Boolean(state.pendingEmployeeDependants?.length) ||
    Boolean(state.dom.employeeDependantsRecordsList?.querySelector("[data-dependant-record]")),
    // Step 4: Address — current address line 1 entered
    hasVal(state.dom.employeeCurrentAddressLine1) || hasVal(state.dom.employeePermanentAddressLine1),
    // Step 5: Next of Kin — full name entered
    hasVal(state.dom.employeeNextOfKinFullName),
    // Step 6: Education — institution name entered
    hasVal(state.dom.employeeEducationInstitutionName),
    // Step 7: Documents — pending file queued or attached doc exists
    state.pendingFiles?.length > 0 ||
    Boolean(state.dom.attachedDocumentsList?.querySelector("[data-document-id]")),
  ];

  stepDone.forEach((done, i) => {
    const step = document.querySelector(`#employeeFormSteps [data-step="${i + 1}"]`);
    if (step) step.classList.toggle("form-step-done", done);
  });
}

async function handleEmployeeRecordsRefresh() {
  const button = state.dom.refreshEmployeesBtn;

  try {
    setWorkspaceRefreshLoading(button, true);
    await waitForNextPaint();
    await refreshEmployeeWorkspace();

    // EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
    // Employee names used by the queue can change after People refresh,
    // so reload the queue immediately after employee records refresh.
    await refreshProfileCorrectionRequestsWorkspace();
  } finally {
    setWorkspaceRefreshLoading(button, false);
  }
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Status normalisation used only for HR correction-request display.
function normalizeProfileCorrectionRequestStatus(status = "") {
  return normalizeText(status).replaceAll("_", " ");
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Pending and in-review requests are still active HR work.
function isOpenProfileCorrectionRequest(record = {}) {
  const status = normalizeProfileCorrectionRequestStatus(record.status || "Pending");

  // EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C
  // Approved is still open HR work because HR must manually update the
  // employee master record before marking the request Completed.
  return status === "pending" || status === "in review" || status === "approved";
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Badge colour for request lifecycle status.
function getProfileCorrectionRequestStatusBadgeClass(status = "") {
  const normalisedStatus = normalizeProfileCorrectionRequestStatus(status || "Pending");

  if (normalisedStatus === "pending") return "text-bg-warning";
  if (normalisedStatus === "in review") return "text-bg-primary";
  if (normalisedStatus === "approved") return "text-bg-success";
  if (normalisedStatus === "completed") return "text-bg-success";
  if (normalisedStatus === "rejected") return "text-bg-danger";
  if (normalisedStatus === "closed") return "text-bg-secondary";

  return "text-bg-light border text-dark";
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Resolve employee display details from the already-loaded tenant employee list.
function getProfileCorrectionRequestEmployeeDisplay(record = {}) {
  const employeeId = String(record.employee_id || "").trim();

  const employee = (state.employees || []).find(
    (item) => String(item.id || "").trim() === employeeId,
  );

  if (!employee) {
    return {
      name: "Unknown Employee",
      email: "--",
      employeeNumber: "--",
    };
  }

  return {
    name: getEmployeeDisplayNameById(employeeId),
    email: employee.work_email || employee.email || "--",
    employeeNumber: employee.employee_number || employee.employee_id || "--",
  };
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Keep newest active requests first, then newest closed requests.
function sortProfileCorrectionRequests(records = []) {
  return [...records].sort((a, b) => {
    const aOpen = isOpenProfileCorrectionRequest(a) ? 1 : 0;
    const bOpen = isOpenProfileCorrectionRequest(b) ? 1 : 0;

    if (bOpen !== aOpen) {
      return bOpen - aOpen;
    }

    const aTime = new Date(a.created_at || a.updated_at || 0).getTime() || 0;
    const bTime = new Date(b.created_at || b.updated_at || 0).getTime() || 0;

    return bTime - aTime;
  });
}

// HR PROFILE CORRECTION REQUESTS UX - STEP 1B
// Smart default:
// - open HR work should stay visible;
// - fully closed/no-work queue should stay compact.
// This only collapses the queue details, not the summary tiles.
function syncProfileCorrectionRequestsSmartCollapse(records = []) {
  const requests = Array.isArray(records) ? records : [];
  const hasOpenRequests = requests.some(isOpenProfileCorrectionRequest);

  setDashboardCardExpanded(
    state.dom.toggleProfileCorrectionRequestsBtn,
    state.dom.profileCorrectionRequestsCollapse,
    hasOpenRequests,
  );
}

// HR PROFILE CORRECTION REQUESTS UX - STEP 1C
// Default HR operational view is Open Only.
// All Requests is available for audit/history review.
function getProfileCorrectionRequestsViewFilter() {
  const selectedFilter = String(
    state.dom.profileCorrectionRequestsViewFilter?.value || "open",
  )
    .trim()
    .toLowerCase();

  return selectedFilter === "all" ? "all" : "open";
}

// HR PROFILE CORRECTION REQUESTS UX - STEP 1C
// This affects table visibility only.
// Summary tiles and saved request data remain based on the full request list.
function filterProfileCorrectionRequestsForCurrentView(records = []) {
  const requests = Array.isArray(records) ? records : [];

  if (getProfileCorrectionRequestsViewFilter() === "all") {
    return requests;
  }

  return requests.filter(isOpenProfileCorrectionRequest);
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Update correction request summary tiles.
function updateProfileCorrectionRequestSummary(records = []) {
  const requests = Array.isArray(records) ? records : [];
  const pendingCount = requests.filter(
    (record) => normalizeProfileCorrectionRequestStatus(record.status || "Pending") === "pending",
  ).length;
  const openCount = requests.filter(isOpenProfileCorrectionRequest).length;
  const closedCount = requests.length - openCount;

  if (state.dom.profileCorrectionPendingCount) {
    state.dom.profileCorrectionPendingCount.textContent = String(pendingCount);
  }

  if (state.dom.profileCorrectionOpenCount) {
    state.dom.profileCorrectionOpenCount.textContent = String(openCount);
  }

  if (state.dom.profileCorrectionClosedCount) {
    state.dom.profileCorrectionClosedCount.textContent = String(closedCount);
  }

  if (state.dom.profileCorrectionTotalCount) {
    state.dom.profileCorrectionTotalCount.textContent = String(requests.length);
  }
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Local status helper for the HR review queue.
function setProfileCorrectionRequestsStatus(type = "info", message = "") {
  const status = state.dom.profileCorrectionRequestsStatus;
  if (!status) return;

  const safeType = ["success", "info", "warning", "danger"].includes(type)
    ? type
    : "info";

  status.className = `alert alert-${safeType} border mb-4`;
  status.innerHTML = message || "";
  status.classList.toggle("d-none", !message);
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C
// Show a real loading row while HR correction requests are being read.
function renderProfileCorrectionRequestsLoadingState() {
  if (!state.dom.profileCorrectionRequestsTableBody) return;

  state.dom.profileCorrectionRequestsEmptyState?.classList.add("d-none");
  state.dom.profileCorrectionRequestsTableWrapper?.classList.remove("d-none");

  state.dom.profileCorrectionRequestsTableBody.innerHTML = `
    <tr>
      <td colspan="6" class="text-center text-secondary py-4">
        Loading profile correction requests.
      </td>
    </tr>
  `;
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C
// HR response/comment display helper.
// Keep fallback names defensive so older database snapshots do not break rendering.
function getProfileCorrectionRequestHrResponse(record = {}) {
  return String(
    record.hr_response ||
    record.hr_comment ||
    record.hr_response_comment ||
    record.review_comment ||
    record.review_notes ||
    "",
  ).trim();
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C
// Only allow controlled lifecycle decisions from the HR queue.
// This prevents accidental free-text statuses from being saved.
function isValidProfileCorrectionDecisionStatus(status = "") {
  return [
    "Pending",
    "In Review",
    "Approved",
    "Rejected",
    "Completed",
  ].includes(String(status || "").trim());
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C UX FIX
// Rejected and Completed decisions need a clear HR audit note.
// In Review and Approved can move without comment because they are lifecycle states.
function doesProfileCorrectionDecisionRequireComment(status = "") {
  const cleanStatus = normalizeProfileCorrectionRequestStatus(status);

  return cleanStatus === "rejected" || cleanStatus === "completed";
}

// HR PROFILE CORRECTION REQUESTS UX - STEP 1H
// Display Approved as "Ready to Update" so HR understands this is not final.
// The stored database value remains Approved to avoid breaking existing rows.
function formatProfileCorrectionDecisionDisplayLabel(status = "") {
  const cleanStatus = normalizeProfileCorrectionRequestStatus(status);

  if (cleanStatus === "pending") return "Pending Review";
  if (cleanStatus === "in review") return "In Review";
  if (cleanStatus === "approved") return "Ready to Update";
  if (cleanStatus === "rejected") return "Rejected";
  if (cleanStatus === "completed") return "Completed";
  if (cleanStatus === "closed") return "Closed";

  return formatStatusLabel(status || "Pending");
}

// HR PROFILE CORRECTION REQUESTS UX - STEP 1D
// Give HR clear status-specific guidance beside the decision control.
// This is display guidance only; it does not update employee master data.
function getProfileCorrectionDecisionGuidance(status = "") {
  const cleanStatus = normalizeProfileCorrectionRequestStatus(status);

  if (cleanStatus === "in review") {
    return "Use while HR is checking the employee’s request.";
  }

  if (cleanStatus === "approved") {
    return "Ready to Update means HR accepts the correction. Open the edit form, update the employee profile manually, then mark this request Completed.";
  }

  if (cleanStatus === "completed") {
    return "Use Completed only after the employee master record has been manually updated.";
  }

  if (cleanStatus === "rejected") {
    return "Rejected requires an HR response/comment explaining why the request was not accepted.";
  }

  return "Pending Review means the request is waiting for HR review.";
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C UX FIX
// Pending Review is the system intake/default state, not a normal HR decision.
// Keep it visible only when the request is still pending, then remove it once HR has started review.
function buildProfileCorrectionDecisionOptions(currentStatus = "") {
  const cleanCurrentStatus = normalizeProfileCorrectionRequestStatus(currentStatus);

  const decisionOptions = [];

  if (cleanCurrentStatus === "pending") {
    decisionOptions.push({
      value: "Pending",
      label: "Pending Review",
    });
  }

  decisionOptions.push(
    {
      value: "In Review",
      label: "In Review",
    },
    {
      // HR PROFILE CORRECTION REQUESTS UX - STEP 1H
      // Keep the saved database value as Approved, but display the HR workflow
      // meaning more clearly: this request is accepted and ready for manual update.
      value: "Approved",
      label: "Ready to Update",
    },
    {
      value: "Rejected",
      label: "Rejected",
    },
    {
      value: "Completed",
      label: "Completed",
    },
  );

  return decisionOptions
    .map((option) => {
      const isSelected =
        normalizeProfileCorrectionRequestStatus(option.value) === cleanCurrentStatus;

      return `
        <option value="${option.value}" ${isSelected ? "selected" : ""}>
          ${option.label}
        </option>
      `;
    })
    .join("");
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C
// Render the HR queue with lifecycle decision controls.
// This does not update employee master data automatically.
function renderProfileCorrectionRequests(records = []) {
  const tbody = state.dom.profileCorrectionRequestsTableBody;
  if (!tbody) return;

  const requests = sortProfileCorrectionRequests(records);

  // HR PROFILE CORRECTION REQUESTS UX - STEP 1C
  // Summary tiles stay based on all loaded requests.
  // The table can then show Open Only or All Requests.
  const visibleRequests = filterProfileCorrectionRequestsForCurrentView(requests);

  updateProfileCorrectionRequestSummary(requests);

  // HR PROFILE CORRECTION REQUESTS UX - STEP 1B
  // Keep active HR work expanded, but collapse the queue when there is no open work.
  syncProfileCorrectionRequestsSmartCollapse(requests);

  tbody.innerHTML = "";

  if (!requests.length) {
    if (state.dom.profileCorrectionRequestsEmptyState) {
      state.dom.profileCorrectionRequestsEmptyState.textContent =
        "No profile correction requests have been submitted yet.";
    }

    state.dom.profileCorrectionRequestsEmptyState?.classList.remove("d-none");
    state.dom.profileCorrectionRequestsTableWrapper?.classList.add("d-none");
    return;
  }

  if (!visibleRequests.length) {
    if (state.dom.profileCorrectionRequestsEmptyState) {
      state.dom.profileCorrectionRequestsEmptyState.textContent =
        "No open profile correction requests. Switch to All Requests to review completed or rejected request history.";
    }

    state.dom.profileCorrectionRequestsEmptyState?.classList.remove("d-none");
    state.dom.profileCorrectionRequestsTableWrapper?.classList.add("d-none");
    return;
  }

  state.dom.profileCorrectionRequestsEmptyState?.classList.add("d-none");
  state.dom.profileCorrectionRequestsTableWrapper?.classList.remove("d-none");

  visibleRequests.forEach((request) => {
    const employee = getProfileCorrectionRequestEmployeeDisplay(request);

    // HR PROFILE CORRECTION REQUESTS UX - STEP 1F
    // Let HR open the existing read-only employee filled-form modal directly
    // from the correction request row. This keeps HR inside People and avoids
    // routing to the employee dashboard or exposing employee IDs in the URL.
    const requestEmployeeId = String(request.employee_id || "").trim();
    const canOpenEmployeeProfileFromRequest = Boolean(
      requestEmployeeId && typeof viewEmployeeFilledForm === "function",
    );

    const employeeNameHtml = canOpenEmployeeProfileFromRequest
      ? `
      <button type="button"
        class="btn btn-link p-0 fw-semibold text-start text-decoration-none"
        title="Open employee profile details"
        aria-label="Open employee profile details for ${escapeHtml(employee.name)}"
        data-profile-correction-view-employee>
        ${escapeHtml(employee.name)}
      </button>
    `
      : `<div class="fw-semibold">${escapeHtml(employee.name)}</div>`;

    const status = request.status || "Pending";

    // HR PROFILE CORRECTION REQUESTS UX - STEP 1G
    // HR must not edit directly from the employee name link.
    // The edit form is exposed only after the request is Approved, because
    // Approved means HR has accepted the correction but still needs to manually
    // update the employee master record before marking the request Completed.
    const canOpenEmployeeEditFromRequest = Boolean(
      requestEmployeeId &&
      normalizeProfileCorrectionRequestStatus(status) === "approved" &&
      canCurrentUserMaintainPeopleData() &&
      typeof startEmployeeEdit === "function",
    );

    const employeeEditButtonHtml = canOpenEmployeeEditFromRequest
      ? `
      <button type="button"
        class="btn btn-sm btn-outline-primary dashboard-action-btn w-100 mb-2"
        data-profile-correction-edit-employee>
        <i class="bi bi-pencil-square me-1"></i>
        Open Edit Form
      </button>

      <div class="form-text mb-2">
        Update the employee profile manually, then mark this request Completed.
      </div>
    `
      : "";

    const categoryLabel = formatStatusLabel(request.request_category || "");
    const submittedOn = formatDateTime(request.created_at || request.updated_at);

    const currentValue = String(request.current_value_snapshot || "").trim() || "--";
    const requestedValue = String(request.requested_value || "").trim() || "Not provided";
    const reason = String(request.reason || "").trim() || "--";
    const hrResponse = getProfileCorrectionRequestHrResponse(request);

    // EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C UX FIX
    // Show the saved HR response as read-only audit context.
    // Keep the action textarea empty after refresh so HR is not looking at a stale input field.
    const savedHrResponseHtml = hrResponse
      ? `
    <div class="small mt-2 pt-2 border-top">
      <span class="fw-semibold">HR Response:</span>
      <span class="text-secondary">${escapeHtml(hrResponse)}</span>
    </div>
  `
      : "";

    // EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C UX FIX
    // Build the HR decision dropdown from the current lifecycle state.
    // This prevents HR from moving an already-reviewed request back to Pending Review.
    const profileCorrectionDecisionOptionsHtml =
      buildProfileCorrectionDecisionOptions(status);

    const row = document.createElement("tr");

    row.innerHTML = `
<td class="align-top">
  <!-- HR PROFILE CORRECTION REQUESTS UX - STEP 1F
       Employee name is the HR drilldown point for the request.
       It opens the existing read-only employee profile modal only. -->
  ${employeeNameHtml}
  <div class="small text-secondary text-break">${escapeHtml(employee.email)}</div>
  <div class="small text-secondary">Employee No: ${escapeHtml(employee.employeeNumber)}</div>
</td>

      <td class="align-top">
        <div class="fw-semibold">${escapeHtml(request.field_label || request.field_key || "--")}</div>
        <div class="small text-secondary">${escapeHtml(categoryLabel || "--")}</div>
      </td>

      <td class="align-top">
        <div class="small mb-2">
          <span class="fw-semibold">Current:</span>
          <span class="text-secondary">${escapeHtml(currentValue)}</span>
        </div>

        <div class="small mb-2">
          <span class="fw-semibold">Requested:</span>
          <span class="text-secondary">${escapeHtml(requestedValue)}</span>
        </div>

<div class="small">
  <span class="fw-semibold">Reason:</span>
  <span class="text-secondary">${escapeHtml(reason)}</span>
</div>

${savedHrResponseHtml}
      </td>

      <td class="align-top">
<span class="badge ${getProfileCorrectionRequestStatusBadgeClass(status)}">
  ${escapeHtml(formatProfileCorrectionDecisionDisplayLabel(status))}
</span>
      </td>

      <td class="align-top text-nowrap">
        ${escapeHtml(submittedOn)}
      </td>

      <td class="align-top" style="min-width: 260px;">
        <!-- EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C
             HR decision controls only update the request lifecycle record.
             They must not auto-write to the employee master record. -->
        <label class="form-label small fw-semibold mb-1" for="profileCorrectionStatus-${escapeHtml(request.id)}">
          HR Decision
        </label>

<select id="profileCorrectionStatus-${escapeHtml(request.id)}"
  class="form-select form-select-sm mb-1"
  data-profile-correction-status>
  ${profileCorrectionDecisionOptionsHtml}
</select>

<div class="form-text mb-2" data-profile-correction-decision-guidance>
  ${escapeHtml(getProfileCorrectionDecisionGuidance(status))}
</div>

<label class="form-label small fw-semibold mb-1" for="profileCorrectionHrResponse-${escapeHtml(request.id)}">
  New HR Response / Comment
</label>

<textarea id="profileCorrectionHrResponse-${escapeHtml(request.id)}"
  class="form-control form-control-sm mb-1"
  rows="2"
  maxlength="500"
  placeholder="Add a new HR note, rejection reason, or completion comment."
  data-profile-correction-response></textarea>

<div class="form-text mb-2">
  Leave blank to keep the existing HR response.
</div>

${employeeEditButtonHtml}

<button type="button"
  id="profileCorrectionSaveBtn-${escapeHtml(request.id)}"
  class="btn btn-sm btn-secondary dashboard-action-btn w-100"
  data-original-status="${escapeHtml(status)}"
  data-profile-correction-save
  disabled>
  <i class="bi bi-check2-circle me-1"></i>
  Save Decision
</button>
      </td>
    `;

    const statusControl = row.querySelector("[data-profile-correction-status]");
    const responseControl = row.querySelector("[data-profile-correction-response]");
    const saveControl = row.querySelector("[data-profile-correction-save]");

    // HR PROFILE CORRECTION REQUESTS UX - STEP 1F
    // Employee-name drilldown inside correction requests.
    // Stop propagation so this does not interfere with card double-click collapse.
    const employeeProfileButton = row.querySelector("[data-profile-correction-view-employee]");

    employeeProfileButton?.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();

      viewEmployeeFilledForm(requestEmployeeId);
    });
    // HR PROFILE CORRECTION REQUESTS UX - STEP 1G
    // Explicit edit action for Approved correction requests only.
    // This opens the normal HR employee edit form; it does not auto-change data
    // and it does not mark the correction request Completed.
    const employeeEditButton = row.querySelector("[data-profile-correction-edit-employee]");

    employeeEditButton?.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();

      if (!canCurrentUserMaintainPeopleData()) {
        showHrPeopleAccessDeniedMessage();
        return;
      }

      // HR PROFILE CORRECTION REQUESTS UX - STEP 1I
      // Open the normal employee edit form, but remember this came from a
      // correction request so save can return HR to the request queue.
      startEmployeeEdit(requestEmployeeId, {
        profileCorrectionRequestId: request.id,
      });

      showPageAlert(
        "info",
        "Employee edit form opened. Update the employee profile manually, save the employee record, then mark the request Completed.",
      );
    });
    // HR PROFILE CORRECTION REQUESTS UX - STEP 1D
    // Inline helper text changes as HR changes the decision dropdown.
    const decisionGuidanceControl = row.querySelector("[data-profile-correction-decision-guidance]");

    const updateSaveDecisionButtonState = () => {
      const originalStatus = normalizeProfileCorrectionRequestStatus(status);
      const selectedStatus = normalizeProfileCorrectionRequestStatus(statusControl?.value || "");
      const newComment = String(responseControl?.value || "").trim();

      const statusChanged = Boolean(selectedStatus && selectedStatus !== originalStatus);
      const commentAdded = Boolean(newComment);
      const commentRequired = doesProfileCorrectionDecisionRequireComment(statusControl?.value || "");

      if (responseControl) {
        responseControl.required = commentRequired;
      }

      // HR PROFILE CORRECTION REQUESTS UX - STEP 1D
      // Keep the HR guidance text in sync with the selected lifecycle decision.
      // This is display guidance only and does not update employee master data.
      if (decisionGuidanceControl) {
        decisionGuidanceControl.textContent = getProfileCorrectionDecisionGuidance(
          statusControl?.value || "",
        );
      }

      if (!saveControl) return;

      const canSave = (statusChanged || commentAdded) && (!commentRequired || commentAdded);

      saveControl.disabled = !canSave;
      saveControl.className = canSave
        ? "btn btn-sm btn-primary dashboard-action-btn w-100"
        : "btn btn-sm btn-secondary dashboard-action-btn w-100";
    };

    statusControl?.addEventListener("change", updateSaveDecisionButtonState);
    responseControl?.addEventListener("input", updateSaveDecisionButtonState);

    updateSaveDecisionButtonState();

    saveControl?.addEventListener("click", async () => {
      await handleProfileCorrectionRequestDecisionSave(request.id);
    });

    tbody.appendChild(row);
  });
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C
// Save the HR lifecycle decision only.
// Critical HR behaviour: this does not overwrite employee master data.
async function handleProfileCorrectionRequestDecisionSave(requestId) {
  const cleanRequestId = String(requestId || "").trim();

  if (!cleanRequestId) {
    showPageAlert("warning", "The selected profile correction request is missing its request ID.");
    return;
  }

  const request = (state.profileCorrectionRequests || []).find(
    (item) => String(item.id || "").trim() === cleanRequestId,
  );

  if (!request) {
    showPageAlert(
      "warning",
      "The selected profile correction request could not be found. Refresh the queue and try again.",
    );
    return;
  }

  const statusField = document.getElementById(`profileCorrectionStatus-${cleanRequestId}`);
  const responseField = document.getElementById(`profileCorrectionHrResponse-${cleanRequestId}`);
  const saveButton = document.getElementById(`profileCorrectionSaveBtn-${cleanRequestId}`);

  const nextStatus = String(statusField?.value || "").trim();
  const hrResponse = String(responseField?.value || "").trim();
  const existingHrResponse = getProfileCorrectionRequestHrResponse(request);

  if (!isValidProfileCorrectionDecisionStatus(nextStatus)) {
    showPageAlert("warning", "Select a valid HR decision status before saving.");
    return;
  }

  // EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C UX FIX
  // Rejection and completion are audit-heavy HR decisions, so HR must record
  // why the request was rejected or what was completed manually.
  if (doesProfileCorrectionDecisionRequireComment(nextStatus) && !hrResponse) {
    showPageAlert(
      "warning",
      `${formatStatusLabel(nextStatus)} requires an HR response/comment before saving.`,
    );

    responseField?.focus();
    return;
  }

  const supabase = getSupabaseClient();
  const tenantId = getRequiredTenantIdForHrEmployeeData();
  const reviewedAt = new Date().toISOString();

  const payload = {
    status: nextStatus,
    reviewed_by: state.currentUser?.id || null,
    reviewed_at: reviewedAt,
    updated_at: reviewedAt,
  };

  // EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1C UX FIX
  // Empty comment should not wipe the previous saved HR response.
  // HR can enter a new response when they deliberately want to replace the old one.
  if (hrResponse || !existingHrResponse) {
    payload.hr_response = hrResponse || null;
  }

  try {
    setWorkspaceRefreshLoading(saveButton, true, "Saving...");

    const { data, error } = await supabase
      .from("employee_profile_correction_requests")
      .update(payload)
      .eq("id", cleanRequestId)
      .eq("tenant_id", tenantId)
      .select("*")
      .maybeSingle();

    if (error) {
      throw error;
    }

    if (!data) {
      showPageAlert(
        "warning",
        "No profile correction request was updated. Refresh the queue and confirm the request still belongs to this company workspace.",
      );
      return;
    }

    setProfileCorrectionRequestsStatus(
      "success",
      `Profile correction request marked as ${escapeHtml(formatProfileCorrectionDecisionDisplayLabel(nextStatus))}. Employee master data was not changed automatically.`
    );

    showPageAlert(
      "success",
      `Profile correction request marked as ${formatProfileCorrectionDecisionDisplayLabel(nextStatus)}. Update the employee master record manually where appropriate.`
    );

    await refreshProfileCorrectionRequestsWorkspace();
  } catch (error) {
    console.error("Error saving profile correction request decision:", error);

    setProfileCorrectionRequestsStatus(
      "danger",
      error.message || "The HR decision could not be saved.",
    );

    showPageAlert(
      "danger",
      error.message || "The HR decision could not be saved.",
    );
  } finally {
    setWorkspaceRefreshLoading(saveButton, false);
  }
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Load correction requests for the current HR tenant only.
async function loadProfileCorrectionRequests() {
  const supabase = getSupabaseClient();
  const tenantId = getRequiredTenantIdForHrEmployeeData();

  const { data, error } = await supabase
    .from("employee_profile_correction_requests")
    .select("*")
    .eq("tenant_id", tenantId);

  if (error) throw error;

  state.profileCorrectionRequests = sortProfileCorrectionRequests(
    Array.isArray(data) ? data : [],
  );

  renderProfileCorrectionRequests(state.profileCorrectionRequests);
}

// EMPLOYEE PROFILE CORRECTION REQUESTS - HR REVIEW PANEL - STEP 1B
// Public refresh wrapper used on startup and by the Refresh Requests button.
async function refreshProfileCorrectionRequestsWorkspace(options = {}) {
  const { showAlert = false } = options;

  if (!state.dom.profileCorrectionRequestsCard) return;

  const button = state.dom.refreshProfileCorrectionRequestsBtn;
  const startedAt = Date.now();

  try {
    setWorkspaceRefreshLoading(button, true, "Refreshing...");
    renderProfileCorrectionRequestsLoadingState();
    setProfileCorrectionRequestsStatus("info", "");

    await waitForNextPaint();
    await loadProfileCorrectionRequests();

    if (showAlert) {
      showPageAlert(
        "success",
        `${state.profileCorrectionRequests.length} profile correction request(s) loaded.`,
      );
    }
  } catch (error) {
    console.error("Error loading profile correction requests:", error);

    state.profileCorrectionRequests = [];
    renderProfileCorrectionRequests([]);

    setProfileCorrectionRequestsStatus(
      "danger",
      error.message || "Profile correction requests could not be loaded.",
    );
  } finally {
    await waitForMinimumLoadingFeedback(startedAt, 400);
    setWorkspaceRefreshLoading(button, false);
  }
}

