async function loadAllEmployeeDocuments() {
  const supabase = getSupabaseClient();

  try {
    // HRP-80 - TENANT DATA SEGMENTATION - STEP 7D
    // Load document indicators only for the logged-in tenant's employee records.
    const { data, error } = await applyCurrentTenantFilter(
      supabase
        .from("employee_documents")
        .select("id, employee_id, file_name, uploaded_at"),
    ).order("uploaded_at", { ascending: false });

    if (error) throw error;
    state.allEmployeeDocuments = Array.isArray(data) ? data : [];
  } catch (error) {
    console.error("Error loading all employee documents:", error);
    state.allEmployeeDocuments = [];
  }
}

async function loadAuthProfilesForLinkage() {
  const supabase = getSupabaseClient();

  try {
    const { data, error } = await supabase
      .from("profiles")
      .select("id, email, full_name, role");

    if (error) throw error;
    state.authProfiles = Array.isArray(data) ? data : [];
  } catch (error) {
    console.error("Error loading auth profiles for linkage:", error);
    state.authProfiles = [];
  }
}

async function loadEmployees() {
  const supabase = getSupabaseClient();

  try {
    // HRP-80 - TENANT DATA SEGMENTATION - STEP 7D
    // HR users should only load employees that belong to their logged-in tenant.
    const { data, error } = await applyCurrentTenantFilter(
      supabase
        .from("employees")
        .select("*"),
    ).order("created_at", { ascending: false });

    if (error) throw error;

    state.employees = Array.isArray(data) ? data : [];
    applyEmployeeSearch();
  } catch (error) {
    console.error("Error loading employee records:", error);
    showPageAlert(
      "danger",
      error.message || "Employee records could not be loaded.",
    );
    state.employees = [];
    state.filteredEmployees = [];
    renderEmployeeRecords([]);
    renderEmployeeSummary([]);
  }
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 2A
// Build a safe full-name value for employee list export.
// This mirrors the list display without exposing unnecessary sensitive data.
function getEmployeeListExportFullName(employee = {}) {
  return [
    employee.first_name,
    employee.middle_name,
    employee.last_name,
  ]
    .map((namePart) => String(namePart || "").trim())
    .filter(Boolean)
    .join(" ") || "Unnamed Employee";
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 2A
// Create a safe filename segment from the company name.
// This keeps downloaded files easy to identify without adding risky characters.
function getSafeEmployeeListExportFileSegment(value = "") {
  return String(value || "company")
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "_")
    .replace(/^_+|_+$/g, "") || "company";
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 2A
// Download the HR employee list as CSV.
// This is a list-level export only: no NIN, no identity numbers, no document URLs,
// and no full document metadata. Those would need a separate compliance export.
function downloadEmployeeListCsv() {
  const records = Array.isArray(state.employees) ? state.employees : [];

  if (!records.length) {
    showPageAlert(
      "warning",
      "No employee records are available to download.",
    );

    showDashboardToast(
      "warning",
      "No employees exported",
      "There are no employee records available in this HR workspace.",
    );

    return;
  }

  const documentCountMap = buildEmployeeDocumentCountMap();

  // HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 2B
  // Keep the HR employee list export clean and report-friendly.
  // Full Name is enough for a normal HR list export; split name fields belong
  // in import templates or technical migration extracts, not this download.
  const headers = [
    "Employee Number",
    "Full Name",
    "Work Email",
    "Phone Number",
    "Alternative Phone Number",
    "Department",
    "Job Title",
    "Status",
    "System Role",
    "Line Manager",
    "Approver Email",
    "Employment Date",
    "Account Linkage",
    "Document Count",
  ];

  const rows = sortEmployeeRecordsByLatestActivity(records).map((employee) => {
    const employeeId = String(employee.id || "").trim();
    const documentCount = documentCountMap.get(employeeId) || 0;
    const accountLinkage = getEmployeeAccountLinkage(employee);

    return [
      employee.employee_number || "",
      getEmployeeListExportFullName(employee),
      employee.work_email || "",
      employee.phone_number || "",
      employee.alternative_phone_number || "",
      employee.department || "",
      employee.job_title || "",
      formatStatusLabel(employee.status || ""),
      formatEmployeeSystemRoleLabel(employee.system_role || ""),
      employee.line_manager || "",
      employee.approver_email || "",
      formatDate(employee.employment_date),
      accountLinkage.label || "",
      documentCount,
    ];
  });

  const csvContent = [headers, ...rows]
    .map((row) => row.map(escapeBatchEmployeeCsvCell).join(","))
    .join("\n");

  const blob = new Blob([csvContent], {
    type: "text/csv;charset=utf-8;",
  });

  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");

  const companySegment = getSafeEmployeeListExportFileSegment(
    getAdminControlledOrganizationName(),
  );

  link.href = url;
  link.download = `${companySegment}_employee_list_${new Date()
    .toISOString()
    .slice(0, 10)}.csv`;

  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);

  URL.revokeObjectURL(url);

  showPageAlert(
    "success",
    `${records.length} employee record(s) exported successfully.`,
  );

  showDashboardToast(
    "success",
    "Employee list downloaded",
    `${records.length} employee record(s) exported to CSV.`,
  );
}

function applyEmployeeSearch() {
  const searchTerm = normalizeText(state.dom.employeeSearchInput?.value || "");

  // BATCH PAYROLL DEFAULT - STEP 1
  // Normal Employee Management still shows all employees.
  // Run Payroll mode shows active employees only, because the batch payroll
  // table should not prepare inactive employees for a new payroll run.
  const employeeSource = state.isRunPayrollSelectionMode
    ? state.employees.filter(
      (employee) => normalizeText(employee.status) === "active",
    )
    : [...state.employees];

  if (!searchTerm) {
    state.filteredEmployees = employeeSource;
  } else {
    state.filteredEmployees = employeeSource.filter((employee) => {
      // EMPLOYEE CUSTOM ID AUTO GENERATION - STEP 1C
      // Include optional Middle Name in Employee Management search.
      // This applies only to the main employee list search.
      const searchableText = [
        employee.first_name,
        employee.middle_name,
        employee.last_name,
        employee.work_email,
        employee.department,
        employee.job_title,
        employee.line_manager,
        employee.approver_email,
        employee.status,
        employee.employee_number,
        employee.phone_number,
      ]
        .join(" ")
        .toLowerCase();

      return searchableText.includes(searchTerm);
    });
  }

  renderEmployeeSummary(state.employees);
  renderEmployeeRecords(state.filteredEmployees);
}

function buildEmployeeDocumentCountMap() {
  const countMap = new Map();

  state.allEmployeeDocuments.forEach((documentRow) => {
    const employeeId = String(documentRow.employee_id || "").trim();
    if (!employeeId) return;

    const existingCount = countMap.get(employeeId) || 0;
    countMap.set(employeeId, existingCount + 1);
  });

  return countMap;
}

function getEmployeeAccountLinkage(employee) {
  const employeeUserId = String(employee?.auth_user_id || employee?.user_id || "").trim();
  const workEmail = normalizeText(employee?.work_email || "");

  if (employeeUserId) {
    const linkedProfile =
      state.authProfiles.find(
        (profile) => String(profile.id || "").trim() === employeeUserId,
      ) || null;

    return {
      code: "linked",
      label: "Linked",
      badgeClass: "text-bg-success",
      matchedEmail: linkedProfile?.email || employee.work_email || "--",
      helperText: "This employee already has a user account linked.",
    };
  }

  const matchedProfile =
    state.authProfiles.find(
      (profile) => normalizeText(profile.email || "") === workEmail,
    ) || null;

  if (matchedProfile) {
    return {
      code: "matched",
      label: "Profile Found",
      badgeClass: "text-bg-warning",
      matchedEmail: matchedProfile.email || "--",
      helperText: "A matching user profile exists for this work email.",
    };
  }

  return {
    code: "unlinked",
    label: "No User Account",
    badgeClass: "text-bg-secondary",
    matchedEmail: "--",
    helperText: "No user account exists yet for this employee.",
  };
}

// MANAGER ROLE ASSIGNMENT
// Look up the current profile role for an employee from the cached auth profiles.
// Matches first by auth_user_id (direct link), then by work email as fallback.
function getEmployeeProfileRole(employee) {
  const employeeUserId = String(employee?.auth_user_id || employee?.user_id || "").trim();
  const workEmail = normalizeText(employee?.work_email || "");

  const profile = employeeUserId
    ? state.authProfiles.find((p) => String(p.id || "").trim() === employeeUserId)
    : state.authProfiles.find((p) => normalizeText(p.email || "") === workEmail);

  return profile?.role || null;
}

// MANAGER ROLE ASSIGNMENT AND DASHBOARD ROUTING - STEP 1F
// The HR form is the master role-control path.
// The row button is only a safe shortcut for Employee <-> Manager.
// For HR, Payroll, Auditor, QA, Leadership, and custom roles, HR must use
// the form so the selected business role and dashboard route remain deliberate.
function getEmployeeSystemRoleKey(employee = {}) {
  return String(employee.system_role || "employee")
    .trim()
    .toLowerCase()
    .replace(/[\s-]+/g, "_");
}

// MANAGER ROLE ASSIGNMENT AND DASHBOARD ROUTING - STEP 1F
// Decide how the quick manager button should behave from employees.system_role,
// not profiles.role only. This prevents stale profile routes from making a
// saved Manager still show "Assign as manager".
function getManagerQuickActionState(employee = {}) {
  const systemRole = getEmployeeSystemRoleKey(employee);

  if (!systemRole || systemRole === "employee") {
    return {
      canUseQuickAction: true,
      isQuickManager: false,
      nextRole: "manager",
      buttonClass: "btn-outline-primary",
      iconClass: "bi-person-plus",
      title: "Assign as manager",
      ariaLabel: "Assign as manager",
    };
  }

  if (systemRole === "manager") {
    return {
      canUseQuickAction: true,
      isQuickManager: true,
      nextRole: "employee",
      buttonClass: "btn-warning",
      iconClass: "bi-person-dash",
      title: "Revert to employee",
      ariaLabel: "Revert manager to employee",
    };
  }

  return {
    canUseQuickAction: false,
    isQuickManager: false,
    nextRole: "",
    buttonClass: "btn-outline-secondary",
    iconClass: "bi-person-gear",
    title: "Use the employee form to change this role",
    ariaLabel: "Use employee form to change role",
  };
}

// DESCRIPTION ITEM 9 - STEP 1
// Payroll selection helpers for the Full Employee List.
// These keep each employee checkbox stable while the user searches,
// filters, collapses, or re-renders the list during the session.
function isEmployeeSelectedForPayroll(employeeId) {
  return state.selectedEmployeesForPayroll.has(String(employeeId));
}

// DESCRIPTION ITEM 9 - STEP 2
// Get the employee ids currently visible in the filtered employee list.
// The master checkbox should only act on what HR is currently viewing.
function getVisibleEmployeeIdsForPayrollSelection() {
  return (state.filteredEmployees || [])
    .map((employee) => String(employee?.id || "").trim())
    .filter(Boolean);
}

// DESCRIPTION ITEM 9 - STEP 2
// Keep the master header checkbox in sync with the visible row selections.
function syncSelectAllEmployeesForPayrollCheckbox() {
  const checkbox = state.dom.selectAllEmployeesForPayroll;
  const summary = state.dom.employeePayrollSelectionSummary;
  const visibleEmployeeIds = getVisibleEmployeeIdsForPayrollSelection();

  // EMPLOYEE LIST CONTEXTUAL PAYROLL SELECTION - STEP 1
  // Pay checkboxes are only needed when HR is actively running payroll.
  // In normal Employee List mode, hide the Pay header and payroll summary
  // so the table behaves like a clean HR reference list.
  const isPayrollSelectionMode = Boolean(state.isRunPayrollSelectionMode);
  const payHeaderCell = checkbox?.closest("th");
  const payrollSummaryRow = summary?.closest(".d-flex");

  payHeaderCell?.classList.toggle("d-none", !isPayrollSelectionMode);
  payrollSummaryRow?.classList.toggle("d-none", !isPayrollSelectionMode);

  const selectedVisibleCount = visibleEmployeeIds.filter((employeeId) =>
    state.selectedEmployeesForPayroll.has(employeeId),
  ).length;

  // DESCRIPTION ITEM 9 - STEP 3
  // Keep the live payroll selection summary in sync with the visible list.
  if (summary) {
    summary.textContent =
      selectedVisibleCount === 1
        ? "1 employee selected for this month."
        : `${selectedVisibleCount} employees selected for this month.`;
  }

  // RUN PAYROLL - STEP 3
  // Keep the Run Payroll action row in sync with current employee selections.
  if (state.dom.runPayrollSelectedCount) {
    state.dom.runPayrollSelectedCount.textContent =
      selectedVisibleCount === 1
        ? "1 employee selected for this payroll run."
        : `${selectedVisibleCount} employees selected for this payroll run.`;
  }

  if (state.dom.continueRunPayrollBtn) {
    state.dom.continueRunPayrollBtn.disabled = selectedVisibleCount === 0;
  }

  if (!checkbox) return;

  // EMPLOYEE LIST CONTEXTUAL PAYROLL SELECTION - STEP 1
  // When not in Run Payroll mode, keep the hidden master checkbox cleared
  // and disabled so no stale selection remains active in the background.
  if (!isPayrollSelectionMode) {
    checkbox.checked = false;
    checkbox.indeterminate = false;
    checkbox.disabled = true;
    return;
  }

  checkbox.disabled = false;
  checkbox.checked = selectedVisibleCount === visibleEmployeeIds.length;
  checkbox.indeterminate =
    selectedVisibleCount > 0 &&
    selectedVisibleCount < visibleEmployeeIds.length;
}

function toggleEmployeePayrollSelection(employeeId, isChecked) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return;

  if (isChecked) {
    state.selectedEmployeesForPayroll.add(employeeKey);
  } else {
    state.selectedEmployeesForPayroll.delete(employeeKey);
  }

  // DESCRIPTION ITEM 9 - STEP 2
  // Re-sync the master checkbox whenever an individual row changes.
  syncSelectAllEmployeesForPayrollCheckbox();
}

// BATCH PAYROLL DEFAULT - STEP 11
// Removes one employee from the current Batch Payroll Review table.
// This gives HR a quick way to fix a blocked duplicate batch without
// going back to the employee list.
function removeEmployeeFromCurrentPayrollBatch(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return;

  state.selectedEmployeesForPayroll.delete(employeeKey);

  const selectedEmployeeIds = Array.from(state.selectedEmployeesForPayroll || [])
    .map((selectedId) => String(selectedId || "").trim())
    .filter(Boolean);

  // BATCH PAYROLL DEFAULT - STEP 11
  // Clear any stale duplicate warning because the batch selection has changed.
  // Submit will re-check duplicates again when HR tries to submit.
  clearPageAlert();
  hideDashboardToast();

  renderBatchPayrollReviewTable(selectedEmployeeIds);
  syncSelectAllEmployeesForPayrollCheckbox();
  updateSubmitBatchPayrollButtonState();

  showDashboardToast(
    "info",
    "Employee removed",
    selectedEmployeeIds.length
      ? "The employee has been removed from this payroll batch."
      : "The employee has been removed. No employees remain in this payroll batch.",
  );
}

// HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1C
// Keeps the Create Payroll "Select all active employees" checkbox visually
// aligned with the row checkboxes inside Batch Payroll Review.
function syncCreatePayrollCardSelectAllCheckboxState() {
  const checkbox = state.dom.selectAllPayrollEmployeesFromCreateCard;
  if (!checkbox) return;

  const activeEmployeeIds = getActiveEmployeeIdsForCreatePayrollSelectAll();
  const selectedActiveCount = activeEmployeeIds.filter((employeeId) =>
    state.selectedEmployeesForPayroll.has(employeeId),
  ).length;

  checkbox.checked =
    activeEmployeeIds.length > 0 &&
    selectedActiveCount === activeEmployeeIds.length;

  checkbox.indeterminate =
    selectedActiveCount > 0 &&
    selectedActiveCount < activeEmployeeIds.length;
}

// HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1C
// Toggling a row checkbox includes or excludes that employee from the payroll batch.
// Inactive employees remain excluded because payroll should only process active staff.
function toggleBatchPayrollReviewEmployeeSelection(employeeId, isChecked) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return;

  const employee = (state.employees || []).find(
    (row) => String(row.id || "").trim() === employeeKey,
  );

  if (!employee || normalizeText(employee.status) !== "active") {
    return;
  }

  if (isChecked) {
    state.selectedEmployeesForPayroll.add(employeeKey);
  } else {
    state.selectedEmployeesForPayroll.delete(employeeKey);
  }

  const selectedEmployeeIds = Array.from(state.selectedEmployeesForPayroll || [])
    .map((selectedId) => String(selectedId || "").trim())
    .filter(Boolean);

  clearPageAlert();
  hideDashboardToast();

  renderBatchPayrollReviewTable(selectedEmployeeIds);
  syncSelectAllEmployeesForPayrollCheckbox();
  syncCreatePayrollCardSelectAllCheckboxState();
  updateSubmitBatchPayrollButtonState();
}

// DESCRIPTION ITEM 9 - STEP 2
// Select or clear all employees currently visible in the list.
// Re-render keeps every row checkbox visually in sync immediately.
function toggleAllVisibleEmployeesForPayroll(isChecked) {
  const visibleEmployeeIds = getVisibleEmployeeIdsForPayrollSelection();

  visibleEmployeeIds.forEach((employeeId) => {
    if (isChecked) {
      state.selectedEmployeesForPayroll.add(employeeId);
    } else {
      state.selectedEmployeesForPayroll.delete(employeeId);
    }
  });

  renderEmployeeRecords(state.filteredEmployees);
}

// HRP-83 - CREATE PAYROLL SELECT ALL - STEP 1D RECOVERY
// Return active employees only because inactive staff should not be prepared
// for a new payroll run in a standard HR/payroll process.
function getActiveEmployeeIdsForCreatePayrollSelectAll() {
  return (state.employees || [])
    .filter((employee) => normalizeText(employee.status) === "active")
    .map((employee) => String(employee.id || "").trim())
    .filter(Boolean);
}

// HRP-83 - CREATE PAYROLL SELECT ALL - STEP 1D RECOVERY
// Clear only the Create Payroll select-all working state.
// This does not delete saved payroll records.
function clearCreatePayrollCardSelectAllSelection({ hideReview = false } = {}) {
  if (state.dom.selectAllPayrollEmployeesFromCreateCard) {
    // HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1D
    // Clear both checked and partial/indeterminate states when batch selection resets.
    state.dom.selectAllPayrollEmployeesFromCreateCard.checked = false;
    state.dom.selectAllPayrollEmployeesFromCreateCard.indeterminate = false;
  }

  state.selectedEmployeesForPayroll.clear();
  state.batchPayrollPreparedRows = [];

  if (state.dom.batchPayrollReviewCount) {
    state.dom.batchPayrollReviewCount.textContent = "0 selected";
  }

  if (state.dom.batchPayrollReviewTableBody) {
    state.dom.batchPayrollReviewTableBody.innerHTML = `
      <tr>
        <td colspan="7" class="text-center text-secondary py-4">
          No employees selected for batch payroll.
        </td>
      </tr>
    `;
  }

  if (state.dom.batchPayrollSetupWarning) {
    state.dom.batchPayrollSetupWarning.classList.add("d-none");
    state.dom.batchPayrollSetupWarning.innerHTML = "";
  }

  if (hideReview) {
    state.dom.batchPayrollReviewPanel?.classList.add("d-none");

    // HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1I RECOVERY
    // Restore manual payroll entry when batch mode is cleared.
    state.dom.payrollCreateForm?.classList.remove("d-none");
    setPayrollRecordToolbarForManualMode();

    // PAYROLL WORKFLOW UX REPAIR - STEP 5B
    // Manual mode is now labelled as single employee payroll finalisation.
    // This is wording only; payroll save/finalisation logic remains unchanged.
    if (state.dom.payrollFormTitle) {
      state.dom.payrollFormTitle.textContent = "Finalise Payroll & Payslips";
    }

    if (state.dom.payrollFormSubtext) {
      state.dom.payrollFormSubtext.textContent =
        "Finalise payroll for one employee or prepare all active employees for payroll review. Payslips are sent separately after payroll records are finalised.";
    }

    if (state.dom.payrollFormModeBadge) {
      state.dom.payrollFormModeBadge.textContent = "Single Employee Mode";
    }
  }

  updateSubmitBatchPayrollButtonState();
  syncSelectAllEmployeesForPayrollCheckbox();
}

// HRP-83 - CREATE PAYROLL SELECT ALL - STEP 1D RECOVERY
// Move all active employees into the existing Batch Payroll Review panel
// so HR can review before submitting payroll.
function handleCreatePayrollCardSelectAllEmployees(isChecked) {
  clearPageAlert();
  hideDashboardToast();

  if (!isChecked) {
    clearCreatePayrollCardSelectAllSelection({ hideReview: true });
    return;
  }

  const activeEmployeeIds = getActiveEmployeeIdsForCreatePayrollSelectAll();

  if (!activeEmployeeIds.length) {
    clearCreatePayrollCardSelectAllSelection({ hideReview: true });

    showPageAlert(
      "warning",
      "No active employees are available for payroll selection.",
    );

    return;
  }

  // HRP-83 - CREATE PAYROLL SELECT ALL - STEP 1D RECOVERY
  // Clear manual single employee selection because this path is batch payroll.
  if (state.dom.payrollEmployeeId) {
    state.dom.payrollEmployeeId.value = "";
  }

  renderPayrollSelectedEmployeeReference("");

  // HRP-83 - BATCH MODE UI CLEANUP - STEP 1D
  // Once Select All starts a batch payroll run, hide the manual single-payroll form.
  // Batch payroll should be reviewed and submitted from Batch Payroll Review only.
  if (state.dom.payrollCreateForm) {
    state.dom.payrollCreateForm.classList.add("d-none");
  }

  // HRP-83 - BATCH MODE UI CLEANUP - STEP 1D
  // Use the same batch toolbar behaviour as CSV import / Run Payroll.
  setPayrollRecordToolbarForBatchMode();

  // PAYROLL WORKFLOW UX REPAIR - STEP 5
  // All-active employee mode uses the existing Batch Payroll Review table
  // so HR can review readiness before finalising records.
  if (state.dom.payrollFormTitle) {
    state.dom.payrollFormTitle.textContent = "Finalise All Active Employees";
  }

  if (state.dom.payrollFormSubtext) {
    state.dom.payrollFormSubtext.textContent =
      "Review active employees in Batch Payroll Review before finalising payroll records.";
  }

  state.isRunPayrollSelectionMode = true;
  state.selectedEmployeesForPayroll = new Set(activeEmployeeIds);

  // HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1I RECOVERY
  // Select All is now a batch payroll flow.
  // After the Batch Payroll Review table is rendered, hide the manual
  // single-payroll form so HR does not see two payroll entry modes at once.
  renderBatchPayrollReviewTable(activeEmployeeIds);

  state.dom.payrollCreateForm?.classList.add("d-none");
  setPayrollRecordToolbarForBatchMode();

  // PAYROLL WORKFLOW UX REPAIR - STEP 5B
  // Batch mode is all-active employee payroll finalisation review.
  if (state.dom.payrollFormTitle) {
    state.dom.payrollFormTitle.textContent = "Finalise All Active Employees";
  }

  if (state.dom.payrollFormSubtext) {
    state.dom.payrollFormSubtext.textContent =
      "Review active employees in Batch Payroll Review before finalising payroll records.";
  }

  if (state.dom.payrollFormModeBadge) {
    state.dom.payrollFormModeBadge.textContent = "All Active Employees Mode";
  }

  syncSelectAllEmployeesForPayrollCheckbox();
  updateSubmitBatchPayrollButtonState();

  state.dom.batchPayrollReviewPanel?.scrollIntoView({
    behavior: "smooth",
    block: "start",
  });
}

// HRP-83 - CREATE PAYROLL SELECT ALL - STEP 1D
// Returns active employees only because inactive staff should not be prepared
// for a new payroll run in a standard HR/payroll process.
function getActiveEmployeeIdsForCreatePayrollSelectAll() {
  return (state.employees || [])
    .filter((employee) => normalizeText(employee.status) === "active")
    .map((employee) => String(employee.id || "").trim())
    .filter(Boolean);
}

// HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1I FINAL
// Hide the manual single-payroll form when HR is working in batch mode.
// This keeps Batch Payroll Review and Manual Single Payroll Entry from showing together.
function setCreatePayrollBatchModeUi() {
  state.dom.payrollCreateForm?.classList.add("d-none");
  setPayrollRecordToolbarForBatchMode();

  // PAYROLL WORKFLOW UX REPAIR - STEP 5B
  // All-active employee mode must not revert to old Create Payroll Batch wording.
  if (state.dom.payrollFormTitle) {
    state.dom.payrollFormTitle.textContent = "Finalise All Active Employees";
  }

  if (state.dom.payrollFormSubtext) {
    state.dom.payrollFormSubtext.textContent =
      "Review active employees in Batch Payroll Review before finalising payroll records.";
  }

  if (state.dom.payrollFormModeBadge) {
    state.dom.payrollFormModeBadge.textContent = "All Active Employees Mode";
  }
}

// HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1I FINAL
// Restore the manual single-payroll form only when batch mode is cleared.
function setCreatePayrollManualModeUi() {
  state.dom.payrollCreateForm?.classList.remove("d-none");
  setPayrollRecordToolbarForManualMode();

  // PAYROLL WORKFLOW UX REPAIR - STEP 5D
  // Manual mode is now single-employee payroll finalisation.
  // Do not revert the card back to old "Create Payroll Record" wording.
  if (state.dom.payrollFormTitle) {
    state.dom.payrollFormTitle.textContent = "Finalise Payroll & Payslips";
  }

  if (state.dom.payrollFormSubtext) {
    state.dom.payrollFormSubtext.textContent =
      "Finalise payroll for one employee or prepare all active employees for payroll review. Payslips are sent separately after payroll records are finalised.";
  }

  if (state.dom.payrollFormModeBadge) {
    state.dom.payrollFormModeBadge.textContent = "Single Employee Mode";
  }
}

// HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1I FINAL
// Clears the Create Payroll select-all batch state without deleting saved payroll records.
function clearCreatePayrollCardSelectAllSelection({ hideReview = false } = {}) {
  if (state.dom.selectAllPayrollEmployeesFromCreateCard) {
    state.dom.selectAllPayrollEmployeesFromCreateCard.checked = false;
    state.dom.selectAllPayrollEmployeesFromCreateCard.indeterminate = false;
  }

  state.selectedEmployeesForPayroll.clear();
  state.batchPayrollPreparedRows = [];

  if (state.dom.batchPayrollReviewCount) {
    state.dom.batchPayrollReviewCount.textContent = "0 selected";
  }

  if (state.dom.batchPayrollReviewTableBody) {
    state.dom.batchPayrollReviewTableBody.innerHTML = `
      <tr>
        <td colspan="7" class="text-center text-secondary py-4">
          No employees selected for batch payroll.
        </td>
      </tr>
    `;
  }

  if (state.dom.batchPayrollSetupWarning) {
    state.dom.batchPayrollSetupWarning.classList.add("d-none");
    state.dom.batchPayrollSetupWarning.innerHTML = "";
  }

  if (hideReview) {
    state.dom.batchPayrollReviewPanel?.classList.add("d-none");
    setCreatePayrollManualModeUi();
  }

  syncSelectAllEmployeesForPayrollCheckbox();
  syncCreatePayrollCardSelectAllCheckboxState?.();
  updateSubmitBatchPayrollButtonState();
}

// HRP-84 - BATCH PAYROLL EMPLOYEE CHECKBOXES - STEP 1I FINAL
// Select All starts a batch payroll flow, populates the batch period,
// renders all employees for review, and hides the manual payroll form.
function handleCreatePayrollCardSelectAllEmployees(isChecked) {
  clearPageAlert();
  hideDashboardToast();

  if (!isChecked) {
    clearCreatePayrollCardSelectAllSelection({ hideReview: true });
    return;
  }

  const activeEmployeeIds = getActiveEmployeeIdsForCreatePayrollSelectAll();

  if (!activeEmployeeIds.length) {
    clearCreatePayrollCardSelectAllSelection({ hideReview: true });

    showPageAlert(
      "warning",
      "No active employees are available for payroll selection.",
    );

    return;
  }

  if (state.dom.payrollEmployeeId) {
    state.dom.payrollEmployeeId.value = "";
  }

  renderPayrollSelectedEmployeeReference("");

  state.isRunPayrollSelectionMode = true;
  state.selectedEmployeesForPayroll = new Set(activeEmployeeIds);

  populateBatchPayrollPayCycleOptions();
  updateBatchPayDateFromPayCycle();

  renderBatchPayrollReviewTable(activeEmployeeIds);

  // HRP-84 - STEP 1I FINAL
  // This must run after renderBatchPayrollReviewTable so the visible
  // batch review remains open while the manual payroll form is hidden.
  setCreatePayrollBatchModeUi();

  syncSelectAllEmployeesForPayrollCheckbox();
  syncCreatePayrollCardSelectAllCheckboxState?.();
  updateSubmitBatchPayrollButtonState();

  state.dom.batchPayrollReviewPanel?.scrollIntoView({
    behavior: "smooth",
    block: "start",
  });
}


// DESCRIPTION ITEM 5 - SYNC FOUNDATION STEP 3C
// Use the latest payroll master record as a fallback source for payroll-owned
// fields that may not yet be populated on the HR employee record.
function getLatestPayrollMasterProfileForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return null;

  const matchingRecords = (state.payrollMasterRecords || []).filter(
    (record) => String(record.employee_id || "").trim() === employeeKey,
  );

  if (!matchingRecords.length) return null;

  matchingRecords.sort((a, b) => {
    const aDate = new Date(
      a.salary_effective_date || a.updated_at || a.created_at || 0,
    ).getTime();
    const bDate = new Date(
      b.salary_effective_date || b.updated_at || b.created_at || 0,
    ).getTime();

    return bDate - aDate;
  });

  return matchingRecords[0];
}

// BATCH PAYROLL DEFAULT - STEP 3
// Returns the latest ACTIVE payroll master record for one employee.
// Batch payroll must not use inactive payroll master records for salary lookup.
// This helper is read-only for now; blocking inactive/missing records comes next.
function getLatestActivePayrollMasterProfileForEmployee(employeeId) {
  const employeeKey = String(employeeId || "").trim();
  if (!employeeKey) return null;

  const activeMatchingRecords = (state.payrollMasterRecords || []).filter(
    (record) =>
      String(record.employee_id || "").trim() === employeeKey &&
      normalizeText(record.payroll_status) === "active",
  );

  if (!activeMatchingRecords.length) return null;

  activeMatchingRecords.sort((a, b) => {
    const aDate = new Date(
      a.salary_effective_date || a.updated_at || a.created_at || 0,
    ).getTime();

    const bDate = new Date(
      b.salary_effective_date || b.updated_at || b.created_at || 0,
    ).getTime();

    return bDate - aDate;
  });

  return activeMatchingRecords[0];
}

// BATCH PAYROLL DEFAULT - STEP 4
// Shows a blocking setup warning for selected employees who do not have
// a valid active Payroll Master record.
// This does not save payroll yet; it only prevents HR from treating the
// batch as ready before the missing setup is corrected.
function renderBatchPayrollSetupWarning(selectedEmployees = []) {
  const warning = state.dom.batchPayrollSetupWarning;
  if (!warning) return;

  const affectedEmployees = selectedEmployees.filter((employee) => {
    // DESCRIPTION ITEM 4 - STEP 5 FIX
    // Use the Payroll Master record effective for the selected batch pay date.
    // This keeps the Run Payroll warning aligned with the actual batch preview
    // and prevents false "ready/missing setup" behaviour.
    const activePayrollMaster =
      getEffectivePayrollMasterRecordForEmployeeAtDate(
        employee.id,
        getCurrentBatchPayrollCalculationDate(),
      );

    const salaryValue = Number(activePayrollMaster?.basic_salary || 0);

    return !(
      activePayrollMaster &&
      Number.isFinite(salaryValue) &&
      salaryValue > 0
    );
  });

  if (!affectedEmployees.length) {
    warning.innerHTML = "";
    warning.classList.add("d-none");
    return;
  }

  const affectedNames = affectedEmployees.slice(0, 5).map((employee) => {
    return (
      `${employee.first_name || ""} ${employee.last_name || ""}`.trim() ||
      employee.work_email ||
      employee.employee_number ||
      "Unknown Employee"
    );
  });

  const extraCount = affectedEmployees.length - affectedNames.length;

  warning.innerHTML = `
    <!-- PAYROLL WORKFLOW UX REPAIR - STEP 5B
         Use the new Employee Salary Setup wording in batch readiness warnings. -->
    <div class="fw-semibold">Employee salary setup is incomplete.</div>
    <div class="small">
      ${affectedEmployees.length} selected employee(s) cannot be finalised yet because they do not have a valid active Employee Salary Setup.
      Affected: <strong>${escapeHtml(affectedNames.join(", "))}${extraCount > 0 ? `, and ${extraCount} more` : ""}</strong>.
      Update Employee Salary Setup before continuing this batch.
    </div>
  `;

  warning.classList.remove("d-none");
}

// HRP-84 - BATCH PAYROLL SUBMIT SUMMARY - STEP 2A
// Build clear batch counts for HR before submission.
// Ready = rows that will actually be inserted into Payroll Records.
// Selected = active employees currently checked for this batch.
// Need setup = selected active employees without valid Payroll Master setup.
// Excluded = inactive employees plus active employees HR unticked.
function getBatchPayrollSubmitSummaryCounts() {
  const employeesToReview = Array.isArray(state.employees)
    ? state.employees
    : [];

  const selectedIds = new Set(
    Array.from(state.selectedEmployeesForPayroll || [])
      .map((employeeId) => String(employeeId || "").trim())
      .filter(Boolean),
  );

  const readyCount = Array.isArray(state.batchPayrollPreparedRows)
    ? state.batchPayrollPreparedRows.length
    : 0;

  // CSV-import batch payroll may prepare rows without using the select-all set.
  // In that case, treat prepared rows as both selected and ready.
  if (!selectedIds.size && readyCount > 0) {
    return {
      readyCount,
      selectedCount: readyCount,
      needsSetupCount: 0,
      excludedCount: 0,
    };
  }

  const activeEmployees = employeesToReview.filter(
    (employee) => normalizeText(employee.status) === "active",
  );

  const inactiveEmployees = employeesToReview.filter(
    (employee) => normalizeText(employee.status) !== "active",
  );

  const selectedActiveEmployees = activeEmployees.filter((employee) =>
    selectedIds.has(String(employee.id || "").trim()),
  );

  const unselectedActiveEmployees = activeEmployees.filter(
    (employee) => !selectedIds.has(String(employee.id || "").trim()),
  );

  const selectedCount = selectedActiveEmployees.length;
  const needsSetupCount = Math.max(selectedCount - readyCount, 0);
  const excludedCount =
    inactiveEmployees.length + unselectedActiveEmployees.length;

  return {
    readyCount,
    selectedCount,
    needsSetupCount,
    excludedCount,
  };
}

// HRP-84 - BATCH PAYROLL SUBMIT SUMMARY - STEP 2A
// Keep the existing bottom helper text, but make it operationally useful.
function updateBatchPayrollSubmitSummary() {
  const button = state.dom.submitBatchPayrollBtn;
  if (!button) return;

  const actionRow = button.closest(".d-flex");
  if (!actionRow) return;

  let summary = document.getElementById("batchPayrollSubmitSummary");

  if (!summary) {
    summary =
      actionRow.querySelector(".small.text-secondary") ||
      document.createElement("div");

    summary.id = "batchPayrollSubmitSummary";
    summary.className = "small text-secondary";

    if (!summary.parentElement) {
      actionRow.insertBefore(summary, button);
    }
  }

  const {
    readyCount,
    selectedCount,
    needsSetupCount,
    excludedCount,
  } = getBatchPayrollSubmitSummaryCounts();

  const readyClass = readyCount > 0 ? "text-success" : "text-secondary";
  const setupClass = needsSetupCount > 0 ? "text-warning" : "text-secondary";

  summary.innerHTML = `
    <!-- HRP-84 - BATCH PAYROLL SUBMIT SUMMARY - STEP 2A
         Clear operational count before HR submits the payroll batch. -->
    <span class="fw-semibold">Batch submit summary:</span>
    <span class="${readyClass} fw-semibold">${readyCount} ready</span>
    <span class="mx-1">/</span>
    <span>${selectedCount} selected</span>
    <span class="mx-1">/</span>
    <span class="${setupClass}">${needsSetupCount} need setup</span>
    <span class="mx-1">/</span>
    <span>${excludedCount} excluded</span>
    <div class="mt-1">
      Only ready employees will be submitted into Payroll Records.
    </div>
  `;

  if (state.dom.batchPayrollReviewCount) {
    state.dom.batchPayrollReviewCount.textContent =
      `${readyCount} ready / ${selectedCount} selected`;
  }
}

// BATCH PAYROLL DEFAULT - STEP 7
// Enables Submit Batch Payroll only when the batch has:
// 1. at least one prepared payroll row,
// 2. a selected pay period,
// 3. a selected pay date.
// Missing Payroll Master setup is already handled by the prepared row count.
function updateSubmitBatchPayrollButtonState() {
  const button = state.dom.submitBatchPayrollBtn;
  if (!button) return;

  // HR DASHBOARD ROLE RESTRICTIONS - STEP 2E-1
  // Do not let batch review recalculation re-enable Submit Batch Payroll
  // for Auditor, QA, or custom read-only roles.
  if (!canCurrentUserMaintainPayrollOperationsData()) {
    button.disabled = true;
    updateBatchPayrollSubmitSummary();
    return;
  }

  const hasPreparedRows = (state.batchPayrollPreparedRows || []).length > 0;
  const hasPayCycle = Boolean(
    String(state.dom.batchPayrollPayCycle?.value || "").trim(),
  );
  const hasPayDate = Boolean(
    String(state.dom.batchPayrollPayDate?.value || "").trim(),
  );

  button.disabled = !(hasPreparedRows && hasPayCycle && hasPayDate);

  // HRP-84 - BATCH PAYROLL SUBMIT SUMMARY - STEP 2B
  // Refresh the visible ready/selected/excluded count every time
  // the Submit Batch Payroll button state is recalculated.
  updateBatchPayrollSubmitSummary();
}

// DESCRIPTION ITEM 3 - STEP 2E-2A
// Rebuild the Run Payroll batch review when the batch pay period/date changes.
// This is only for selected-employees batch mode. It does not touch CSV import rows.
function refreshRunPayrollBatchReviewForSelectedEmployees() {
  const selectedEmployeeIds = Array.from(state.selectedEmployeesForPayroll || [])
    .map((employeeId) => String(employeeId || "").trim())
    .filter(Boolean);

  if (!state.isRunPayrollSelectionMode || !selectedEmployeeIds.length) {
    updateSubmitBatchPayrollButtonState();
    return;
  }

  renderBatchPayrollReviewTable(selectedEmployeeIds);
}

// DESCRIPTION ITEM 3 - STEP 2E-2A
// Batch payroll uses its own pay date control. That date decides whether
// an active statutory deduction setup applies to each selected employee.
function getCurrentBatchPayrollCalculationDate() {
  return String(state.dom.batchPayrollPayDate?.value || "").trim() ||
    new Date().toISOString().slice(0, 10);
}

// DESCRIPTION ITEM 3 - STEP 2E-2A
// Return the latest active statutory deduction per type for one Payroll Master.
// A statutory deduction only applies when effective_date <= Batch Pay Date.
function getActiveStatutoryDeductionsForBatchPayrollMaster(
  payrollMasterRecordId = "",
  payrollDateValue = "",
) {
  const masterId = String(payrollMasterRecordId || "").trim();
  if (!masterId) return [];

  const payrollDateTime = parsePayrollEffectiveDateToTime(
    payrollDateValue || getCurrentBatchPayrollCalculationDate(),
  );

  if (!Number.isFinite(payrollDateTime)) return [];

  const validRows = (state.payrollStatutoryDeductions || []).filter((record) => {
    const isSamePayrollMaster =
      String(record.payroll_master_record_id || "").trim() === masterId;

    const isActive = normalizeText(record.status) === "active";
    const effectiveDateTime = parsePayrollEffectiveDateToTime(record.effective_date);

    return (
      isSamePayrollMaster &&
      isActive &&
      Number.isFinite(effectiveDateTime) &&
      effectiveDateTime <= payrollDateTime
    );
  });

  const latestByType = new Map();

  validRows.forEach((record) => {
    const type = String(record.deduction_type || "").trim();
    if (!type) return;

    const existing = latestByType.get(type);
    const recordTime = parsePayrollEffectiveDateToTime(record.effective_date);
    const existingTime = parsePayrollEffectiveDateToTime(existing?.effective_date);

    if (!existing || recordTime >= existingTime) {
      latestByType.set(type, record);
    }
  });

  return Array.from(latestByType.values());
}

// DESCRIPTION ITEM 3 - STEP 2E-2A
// Resolve a batch statutory deduction amount from its method.
// Rule Based uses the same standard payroll formula as manual payroll.
// Percentage and Amount use the saved statutory deduction configuration.
function calculateBatchStatutoryDeductionAmount(record = {}, context = {}) {
  const type = String(record.deduction_type || "").trim();
  const method = String(record.calculation_method || "").trim();
  const configuredValue = Number(record.deduction_value || 0);

  if (method === "AMOUNT") {
    return Number.isFinite(configuredValue) ? configuredValue : 0;
  }

  if (method === "PERCENTAGE") {
    let baseAmount = Number(context.grossPay || 0);

    if (type === "EMPLOYEE_PENSION" || type === "EMPLOYER_PENSION") {
      baseAmount = Number(context.bht || 0);
    }

    if (type === "NHF") {
      baseAmount = Number(context.basicPay || 0);
    }

    return Number.isFinite(configuredValue)
      ? baseAmount * (configuredValue / 100)
      : 0;
  }

  if (type === "PAYE") {
    return calculateNta2025MonthlyPayeTaxFromComponents({
      basicPay: context.basicPay,
      housingAllowance: context.housingAllowance,
      transportAllowance: context.transportAllowance,
      utilityAllowance: context.utilityAllowance,
      otherAllowance: context.otherAllowance,
      medicalAllowance: context.medicalAllowance,
      bonus: context.bonus,
      overtime: context.overtime,
      logisticsAllowance: context.logisticsAllowance,
      dataAirtimeAllowance: context.dataAirtimeAllowance,
    });
  }

  if (type === "EMPLOYEE_PENSION") {
    return Number(context.bht || 0) * 0.08;
  }

  if (type === "EMPLOYER_PENSION") {
    return Number(context.bht || 0) * 0.1;
  }

  if (type === "NHF") {
    return Number(context.basicPay || 0) * 0.025;
  }

  return 0;
}

// DESCRIPTION ITEM 4 - STEP 5 FIX
// Shared payroll date parser used by statutory deductions and Other Deductions.
// It supports the normal HTML date format YYYY-MM-DD and also DD/MM/YYYY.
// Keeping this helper here prevents payroll calculation from failing when
// checking deduction effective dates and deduction duration windows.
function parsePayrollEffectiveDateToTime(value = "") {
  const rawValue = String(value || "").trim();

  if (!rawValue) return NaN;

  if (/^\d{4}-\d{2}-\d{2}$/.test(rawValue)) {
    return new Date(`${rawValue}T00:00:00`).getTime();
  }

  const slashDateMatch = rawValue.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);

  if (slashDateMatch) {
    const [, day, month, year] = slashDateMatch;
    return new Date(`${year}-${month}-${day}T00:00:00`).getTime();
  }

  return new Date(rawValue).getTime();
}

// DESCRIPTION ITEM 4 - STEP 5 FIX
// Payroll Pay Date is the date used to decide whether a statutory or
// other deduction setup is active for the manual payroll preview.
function getCurrentPayrollCalculationDate() {
  return String(state.dom.payrollPayDate?.value || "").trim() ||
    new Date().toISOString().slice(0, 10);
}

// =========================================================
// DESCRIPTION ITEM 4 - STEP 5
// Other Deductions payroll calculation helpers.
//
// These helpers apply non-statutory deductions such as union dues,
// cooperative deductions, salary advance repayments, and other approved
// deductions during payroll calculation.
//
// Duration behaviour:
// If a deduction starts in May with duration 2, it applies for May and June.
// This follows monthly payroll-cycle behaviour rather than exact day counting.
// =========================================================

function getPayrollMonthIndexFromDateValue(dateValue = "") {
  const time = parsePayrollEffectiveDateToTime(dateValue);

  if (!Number.isFinite(time)) return null;

  const date = new Date(time);

  return (date.getFullYear() * 12) + date.getMonth();
}

function isPayrollOtherDeductionActiveForDate(record = {}, payrollDateValue = "") {
  const status = normalizeText(record.status || "");
  if (status !== "active") return false;

  const deductionAmount = Number(record.deduction_amount || 0);
  if (!Number.isFinite(deductionAmount) || deductionAmount <= 0) return false;

  const durationMonths = Number(record.duration_months || 0);
  if (!Number.isInteger(durationMonths) || durationMonths < 1) return false;

  const payrollMonthIndex = getPayrollMonthIndexFromDateValue(payrollDateValue);
  const startMonthIndex = getPayrollMonthIndexFromDateValue(record.start_date);

  if (payrollMonthIndex === null || startMonthIndex === null) return false;

  const monthsFromStart = payrollMonthIndex - startMonthIndex;

  return monthsFromStart >= 0 && monthsFromStart < durationMonths;
}

function getActivePayrollOtherDeductionsForMaster(
  payrollMasterRecordId = "",
  payrollDateValue = "",
) {
  const masterId = String(payrollMasterRecordId || "").trim();

  if (!masterId) return [];

  return (state.payrollOtherDeductions || []).filter((record) => {
    const isSamePayrollMaster =
      String(record.payroll_master_record_id || "").trim() === masterId;

    return (
      isSamePayrollMaster &&
      isPayrollOtherDeductionActiveForDate(record, payrollDateValue)
    );
  });
}

function calculateActivePayrollOtherDeductionTotalForMaster(
  payrollMasterRecordId = "",
  payrollDateValue = "",
) {
  return getActivePayrollOtherDeductionsForMaster(
    payrollMasterRecordId,
    payrollDateValue,
  ).reduce((total, record) => {
    const amount = Number(record.deduction_amount || 0);

    return total + (Number.isFinite(amount) && amount > 0 ? amount : 0);
  }, 0);
}

function getEffectivePayrollMasterRecordForEmployeeAtDate(
  employeeId = "",
  payrollDateValue = "",
) {
  const targetEmployeeId = String(employeeId || "").trim();
  const payrollDateTime = parsePayrollEffectiveDateToTime(payrollDateValue);

  if (!targetEmployeeId || !Number.isFinite(payrollDateTime)) {
    return null;
  }

  const matchingRecords = (state.payrollMasterRecords || [])
    .filter((record) => {
      const recordEmployeeId = String(record.employee_id || "").trim();

      const status = normalizeText(
        record.status ||
        record.salary_status ||
        record.payroll_status ||
        "active",
      );

      const effectiveDate =
        record.salary_effective_date ||
        record.effective_date ||
        record.created_at;

      const effectiveTime = parsePayrollEffectiveDateToTime(effectiveDate);

      return (
        recordEmployeeId === targetEmployeeId &&
        status === "active" &&
        Number.isFinite(effectiveTime) &&
        effectiveTime <= payrollDateTime
      );
    })
    .sort((a, b) => {
      const aTime = parsePayrollEffectiveDateToTime(
        a.salary_effective_date || a.effective_date || a.created_at,
      );

      const bTime = parsePayrollEffectiveDateToTime(
        b.salary_effective_date || b.effective_date || b.created_at,
      );

      return (bTime || 0) - (aTime || 0);
    });

  return matchingRecords[0] || null;
}

function calculateActivePayrollOtherDeductionTotalForCurrentPayroll() {
  const employeeId = String(state.dom.payrollEmployeeId?.value || "").trim();
  const payrollDate = String(state.dom.payrollPayDate?.value || "").trim();

  const activePayrollMaster = getEffectivePayrollMasterRecordForEmployeeAtDate(
    employeeId,
    payrollDate,
  );

  if (!activePayrollMaster?.id) return 0;

  return calculateActivePayrollOtherDeductionTotalForMaster(
    activePayrollMaster.id,
    payrollDate,
  );
}

function syncPayrollOtherDeductionsFieldFromSetup(systemAmount = 0) {
  const field = state.dom.payrollOtherDeductions;
  if (!field) return;

  const amount = Number(systemAmount || 0);
  const previousSystemAmount = Number(
    field.dataset.systemOtherDeductionAmount || 0,
  );

  const currentAmount = Number(field.value || 0);
  const userHasManualValue =
    Number.isFinite(currentAmount) &&
    currentAmount > 0 &&
    Math.abs(currentAmount - previousSystemAmount) > 0.01;

  if (Number.isFinite(amount) && amount > 0) {
    setNumericFieldValue(field, amount);
    field.dataset.systemOtherDeductionAmount = String(amount);
    return;
  }

  // If the previous value came from setup and the setup no longer applies,
  // clear it. If HR typed a manual value, leave it untouched.
  if (previousSystemAmount > 0 && !userHasManualValue) {
    setNumericFieldValue(field, 0);
    field.dataset.systemOtherDeductionAmount = "0";
  }
}

// DESCRIPTION ITEM 3 - STEP 2E-2A
// Calculate statutory-controlled deduction totals for one prepared batch row.
// If no active statutory deduction exists for the batch pay date, statutory
// values remain zero, matching the manual payroll behaviour from Step 2E-1.
function calculateBatchStatutoryDeductionTotals(context = {}) {
  const activeDeductions = getActiveStatutoryDeductionsForBatchPayrollMaster(
    context.payrollMasterRecordId,
    context.payrollDate,
  );

  let payeTax = 0;
  let employeePension = 0;
  let employerPension = 0;
  let otherDeductions = 0;

  activeDeductions.forEach((record) => {
    const type = String(record.deduction_type || "").trim();
    const amount = calculateBatchStatutoryDeductionAmount(record, context);

    if (!Number.isFinite(amount) || amount < 0) return;

    if (type === "PAYE") {
      payeTax = amount;
      return;
    }

    if (type === "EMPLOYEE_PENSION") {
      employeePension = amount;
      return;
    }

    if (type === "EMPLOYER_PENSION") {
      employerPension = amount;
      return;
    }

    // NHF and future statutory deductions without a dedicated payroll field
    // are grouped under Other Deductions, same as manual payroll.
    otherDeductions += amount;
  });

  const whtTax = 0;

  // DESCRIPTION ITEM 4 - STEP 5
  // Add active non-statutory Other Deductions into the same batch deduction
  // total used by Run Payroll and Batch Payroll CSV import.
  // This keeps manual payroll, Run Payroll, and CSV import aligned.
  const configuredOtherDeductions =
    calculateActivePayrollOtherDeductionTotalForMaster(
      context.payrollMasterRecordId,
      context.payrollDate,
    );

  const combinedOtherDeductions =
    otherDeductions + configuredOtherDeductions;

  const totalDeductions =
    payeTax + whtTax + employeePension + combinedOtherDeductions;

  const netPay = Number(context.grossPay || 0) - totalDeductions;

  return {
    payeTax,
    whtTax,
    employeePension,
    employerPension,
    otherDeductions: combinedOtherDeductions,
    totalDeductions,
    netPay,
  };
}

// BATCH PAYROLL CSV IMPORT - STEP 5C
// Prepare one batch payroll row directly from the latest HR/payroll setup.
// This route is used by Run Payroll selected employees, so it must also
// pull active Allowance Components before final payroll records are created.
function buildBatchPayrollPreparedRow(employee, activePayrollMaster) {
  const resolvedBaseSalary = resolveBatchPayrollBaseSalaryWithEmployeeOverride(
    activePayrollMaster?.id,
    getCurrentBatchPayrollCalculationDate(),
    Number(activePayrollMaster?.basic_salary || 0),
  );

  const baseSalary = resolvedBaseSalary.amount;

  const employeeOverrideAuditSummary =
    buildPayrollEmployeeOverrideAuditSummaryForMaster(
      activePayrollMaster?.id,
      getCurrentBatchPayrollCalculationDate(),
    );

  if (
    !employee?.id ||
    !activePayrollMaster?.id ||
    !Number.isFinite(baseSalary) ||
    baseSalary <= 0
  ) {
    return null;
  }

  const extras = getActiveBatchPayrollExtraComponentsForMaster(
    activePayrollMaster.id,
  );

  // BATCH PAYROLL CSV IMPORT - STEP 5C
  // No automatic salary increment. HR should only apply increments through
  // an approved CSV/manual salary review.
  const incrementAmount = 0;
  const newBaseSalary = baseSalary;

  const basicPay = newBaseSalary * 0.5;
  const housingAllowance = newBaseSalary * 0.1;
  const transportAllowance = newBaseSalary * 0.1;
  const utilityAllowance = newBaseSalary * 0.1;
  const otherAllowance = newBaseSalary * 0.2;

  const bonus = extras.bonus;
  const overtime = extras.overtime;
  const logisticsAllowance = extras.logisticsAllowance;
  const dataAirtimeAllowance = extras.dataAirtimeAllowance;
  const medicalAllowance = extras.medicalAllowance;

  const bht = basicPay + housingAllowance + transportAllowance;

  const grossPay =
    basicPay +
    housingAllowance +
    transportAllowance +
    utilityAllowance +
    otherAllowance +
    medicalAllowance +
    bonus +
    overtime +
    logisticsAllowance +
    dataAirtimeAllowance;

  // DESCRIPTION ITEM 3 - STEP 2E-2A
  // Batch payroll deductions now come from active statutory deduction setup,
  // using the selected Batch Pay Date as the effective-date cut-off.
  // Employer Pension is calculated/stored separately and is not part of
  // employee Total Deductions.
  const statutoryTotals = calculateBatchStatutoryDeductionTotals({
    payrollMasterRecordId: activePayrollMaster.id,
    payrollDate: getCurrentBatchPayrollCalculationDate(),

    basicPay,
    housingAllowance,
    transportAllowance,
    utilityAllowance,
    otherAllowance,
    medicalAllowance,
    bonus,
    overtime,
    logisticsAllowance,
    dataAirtimeAllowance,

    bht,
    grossPay,
  });

  const payeTax = statutoryTotals.payeTax;
  const whtTax = statutoryTotals.whtTax;
  const employeePension = statutoryTotals.employeePension;
  const employerPension = statutoryTotals.employerPension;
  const otherDeductions = statutoryTotals.otherDeductions;
  const totalDeductions = statutoryTotals.totalDeductions;
  const netPay = statutoryTotals.netPay;

  const preparedRow = {
    employee_id: employee.id,
    payroll_master_record_id: activePayrollMaster.id,
    pay_cycle: activePayrollMaster.pay_cycle || "",
    payroll_group: "REGULAR",
    payroll_model: "REGULAR",
    employee_override_applied: resolvedBaseSalary.overrideApplied,
    employee_override_audit_summary: employeeOverrideAuditSummary,

    base_salary: baseSalary,
    regular_increment_percent: 0,
    regular_increment_amount: incrementAmount,
    merit_increment: null,
    regular_new_base_salary: newBaseSalary,

    basic_pay: basicPay,
    housing_allowance: housingAllowance,
    transport_allowance: transportAllowance,
    utility_allowance: utilityAllowance,
    other_allowance: otherAllowance,

    medical_allowance: medicalAllowance || null,
    bonus: bonus || null,
    overtime: overtime || null,
    logistics_allowance: logisticsAllowance || null,
    data_airtime_allowance: dataAirtimeAllowance || null,
    monthly_salary_plus_logistics:
      logisticsAllowance > 0 ? netPay - dataAirtimeAllowance : null,

    bht,
    employee_pension: employeePension,
    employer_pension: employerPension,

    paye_tax: payeTax,
    wht_tax: whtTax,
    other_deductions: otherDeductions,

    gross_pay: grossPay,
    total_deductions: totalDeductions,
    net_pay: netPay,

    currency: "NGN",
  };

  return applyActivePayrollEmployeeOverridesToBatchPreparedRow(
    preparedRow,
    activePayrollMaster.id,
    getCurrentBatchPayrollCalculationDate(),
  );
}

// HRP-82 - PAYROLL ID WITH DATESTAMP - STEP 1G
// Creates a readable payroll ID using date + time.
// Example: PAY-2026-05-07-113453
// The hyphenated date is easier for HR/payroll users to read.
function buildDatestampedPayrollReference(prefix = "PAY") {
  const now = new Date();

  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, "0");
  const day = String(now.getDate()).padStart(2, "0");
  const hours = String(now.getHours()).padStart(2, "0");
  const minutes = String(now.getMinutes()).padStart(2, "0");
  const seconds = String(now.getSeconds()).padStart(2, "0");

  return `${prefix}-${year}-${month}-${day}-${hours}${minutes}${seconds}`;
}

// HRP-82 - PAYROLL ID WITH DATESTAMP - STEP 1G
// Displays older compact payroll IDs in the cleaner readable format.
// Example: PAY-20260507-113453 becomes PAY-2026-05-07-113453.
// This is display-only and does not rewrite existing database records.
function formatPayrollReferenceForDisplay(value) {
  const reference = String(value || "").trim();
  if (!reference) return "--";

  const compactMatch = reference.match(/^([A-Za-z]+)-(\d{4})(\d{2})(\d{2})-(\d{6})$/);

  if (!compactMatch) {
    return reference;
  }

  const [, prefix, year, month, day, time] = compactMatch;
  return `${prefix.toUpperCase()}-${year}-${month}-${day}-${time}`;
}

// BATCH PAYROLL DEFAULT - STEP 7
// Converts one prepared batch preview row into a payroll_records payload.
// This deliberately does not use the hidden individual payroll form fields.
function buildBatchPayrollRecordPayload(preparedRow, payrollReference = "") {
  const payCycle = String(state.dom.batchPayrollPayCycle?.value || "").trim();
  const payDate = String(state.dom.batchPayrollPayDate?.value || "").trim();

  // BATCH PAYROLL CSV IMPORT - STEP 5
  // Normalise increment percentage before saving.
  // CSV rows should save the actual increment supplied by the CSV.
  // If no increment exists, this saves 0 instead of forcing 5%.
  const rawIncrementPercent = Number(preparedRow.regular_increment_percent ?? 0);
  const normalizedIncrementPercent =
    rawIncrementPercent > 1 ? rawIncrementPercent / 100 : rawIncrementPercent;

  return {
    employee_id: preparedRow.employee_id,
    pay_cycle: payCycle,
    pay_date: payDate || null,

    // HRP-82 - PAYROLL ID WITH DATESTAMP - STEP 1B
    // Store one payroll ID/reference on each created payroll record.
    // Batch submit will pass the same ID to every employee in the run.
    payroll_reference: payrollReference || buildDatestampedPayrollReference("PAY"),

    employee_group: "REGULAR",
    payroll_model: "REGULAR",
    payroll_model_version: "rev2",
    structure_variant: "ALPATECH_REGULAR_REV2",
    payslip_layout: "ALPATECH_REGULAR_REV2",

    // BATCH PAYROLL CSV IMPORT - STEP 5
    // Save the actual increment from the prepared row.
    // No CSV/template increment means this stores 0 instead of forcing 5%.
    increment_percent: normalizedIncrementPercent,
    increment_amount: preparedRow.regular_increment_amount || 0,
    merit_increment: preparedRow.merit_increment ?? null,
    new_base_salary: preparedRow.regular_new_base_salary,

    basic_percent: 0.5,
    housing_percent: 0.1,
    transport_percent: 0.1,
    utility_percent: 0.1,
    other_allowance_percent: 0.2,

    base_salary: preparedRow.base_salary,
    basic_pay: preparedRow.basic_pay,
    housing_allowance: preparedRow.housing_allowance,
    transport_allowance: preparedRow.transport_allowance,
    utility_allowance: preparedRow.utility_allowance,
    // BATCH PAYROLL CSV IMPORT - STEP 5C
    // Save extra earnings that were pulled into the batch template or imported CSV.
    medical_allowance: preparedRow.medical_allowance ?? null,
    other_allowance: preparedRow.other_allowance,
    bonus: preparedRow.bonus ?? null,
    overtime: preparedRow.overtime ?? null,
    logistics_allowance: preparedRow.logistics_allowance ?? null,
    data_airtime_allowance: preparedRow.data_airtime_allowance ?? null,

    bht:
      preparedRow.bht ??
      Number(preparedRow.basic_pay || 0) +
      Number(preparedRow.housing_allowance || 0) +
      Number(preparedRow.transport_allowance || 0),

    // BATCH PAYROLL CSV IMPORT - STEP 5
    // Preserve the Alpatech "Monthly Salary + Logistics" value where available.
    monthly_salary_plus_logistics:
      preparedRow.monthly_salary_plus_logistics ?? null,

    employer_wht: null,
    gross_pay: preparedRow.gross_pay,

    paye_tax: preparedRow.paye_tax,
    wht_tax: preparedRow.wht_tax ?? 0,
    employee_pension: preparedRow.employee_pension,
    employer_pension: preparedRow.employer_pension,

    other_deductions: preparedRow.other_deductions ?? 0,
    total_deductions: preparedRow.total_deductions,
    net_pay: preparedRow.net_pay,

    currency: "NGN",
    status: "Authorised",
    is_finalised: true,

    // DESCRIPTION ITEM 5 - STEP 5C
    // Save the employee override audit summary on the final payroll snapshot.
    // This makes the submitted Payroll Record traceable after batch submission.
    notes: buildPayrollRecordNotesWithEmployeeOverrideAudit(
      preparedRow.source === "csv"
        ? "Created from Alpatech CSV batch payroll import."
        : "Created from batch payroll run.",
      preparedRow.employee_override_audit_summary,
    ),

    processed_by: state.currentUser?.id || null,
    approved_by: state.currentUser?.id || null,
    approved_at: new Date().toISOString(),
  };
}

// BATCH PAYROLL DEFAULT - STEP 8
// Checks whether selected employees already have payroll records
// for the selected batch pay period.
// This prevents accidental duplicate payroll records for the same
// employee and pay cycle when HR clicks Submit Batch Payroll again.
async function getExistingBatchPayrollRecordsForPeriod(payCycle, employeeIds = []) {
  const cleanPayCycle = String(payCycle || "").trim();

  const currentTenantEmployeeIds = getCurrentTenantEmployeeIdSet();

  // HRP-80 - PAYROLL TENANT SAFETY FIX
  // Duplicate payroll checks must only consider employees in the current
  // company workspace. Another company's payroll records must not block
  // or influence this tenant's payroll run.
  const cleanEmployeeIds = employeeIds
    .map((employeeId) => String(employeeId || "").trim())
    .filter((employeeId) => employeeId && currentTenantEmployeeIds.has(employeeId));

  if (!cleanPayCycle || !cleanEmployeeIds.length) {
    return [];
  }

  const supabase = getSupabaseClient();

  const { data, error } = await supabase
    .from("hr_payroll_overview")
    .select("id, employee_id, pay_cycle, first_name, last_name, work_email")
    .eq("pay_cycle", cleanPayCycle)
    .in("employee_id", cleanEmployeeIds);

  if (error) {
    throw new Error(error.message);
  }

  return (Array.isArray(data) ? data : [])
    .filter(isRecordForCurrentTenantEmployee);
}

function renderEmployeeSummary(employees) {
  const activeEmployees = employees.filter(
    (employee) => normalizeText(employee.status) === "active",
  ).length;

  const uniqueDepartments = new Set(
    employees
      .map((employee) => String(employee.department || "").trim())
      .filter(Boolean),
  );

  const missingEmployeeNumbers = employees.filter(
    (employee) => !String(employee.employee_number || "").trim(),
  ).length;

  if (state.dom.totalEmployeesValue) {
    state.dom.totalEmployeesValue.textContent = String(employees.length);
  }

  if (state.dom.activeEmployeesValue) {
    state.dom.activeEmployeesValue.textContent = String(activeEmployees);
  }

  if (state.dom.departmentsValue) {
    state.dom.departmentsValue.textContent = String(uniqueDepartments.size);
  }

  if (state.dom.missingEmployeeNumberValue) {
    state.dom.missingEmployeeNumberValue.textContent = String(
      missingEmployeeNumbers,
    );
  }
}

function renderEmployeeRecordsLoadingState() {
  if (!state.dom.employeeRecordsTableBody) return;

  if (state.dom.employeeRecordsEmptyState) {
    state.dom.employeeRecordsEmptyState.classList.add("d-none");
  }

  if (state.dom.employeeRecordsTableWrapper) {
    state.dom.employeeRecordsTableWrapper.classList.remove("d-none");
  }

  // DESCRIPTION ITEM 9 - STEP 2
  // Reset the master payroll checkbox while the employee list is loading.
  if (state.dom.selectAllEmployeesForPayroll) {
    state.dom.selectAllEmployeesForPayroll.checked = false;
    state.dom.selectAllEmployeesForPayroll.indeterminate = false;
    state.dom.selectAllEmployeesForPayroll.disabled = true;
  }

  // DESCRIPTION ITEM 9 - STEP 3
  // Reset the payroll selection summary while the employee list is loading.
  if (state.dom.employeePayrollSelectionSummary) {
    state.dom.employeePayrollSelectionSummary.textContent =
      "Loading payroll selection...";
  }

  state.dom.employeeRecordsTableBody.innerHTML = `
    <tr>
      <td colspan="10" class="text-center text-secondary py-4">
        Loading employee records.
      </td>
    </tr>
  `;
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 1A
// Build the full employee name from saved employee fields.
// This is display-only and does not change the employee record.
function getEmployeeFilledFormFullName(employee = {}) {
  return [
    employee.first_name,
    employee.middle_name,
    employee.last_name,
  ]
    .map((namePart) => String(namePart || "").trim())
    .filter(Boolean)
    .join(" ") || "Unnamed Employee";
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 1A
// Keep sensitive NIN readable enough for HR recognition without exposing
// the full value in the read-only filled-form view.
function maskEmployeeFilledFormNin(value = "") {
  const digits = String(value || "").replace(/\D/g, "");

  if (!digits) return "--";
  if (digits.length <= 4) return "*******" + digits;

  return `*******${digits.slice(-4)}`;
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 1A
// Standard read-only field renderer used by the employee filled-form modal.
function renderEmployeeFilledFormField(label, value, options = {}) {
  const { date = false, dateTime = false, sensitive = false } = options;

  let displayValue = value;

  if (sensitive) {
    displayValue = maskEmployeeFilledFormNin(value);
  } else if (dateTime) {
    displayValue = formatDateTime(value);
  } else if (date) {
    displayValue = formatDate(value);
  } else if (value === null || value === undefined || String(value).trim() === "") {
    displayValue = "--";
  }

  return `
    <div class="col-md-6 col-xl-4">
      <div class="small text-secondary mb-1">${escapeHtml(label)}</div>
      <div class="fw-semibold text-break">${escapeHtml(displayValue)}</div>
    </div>
  `;
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 1A
// Section wrapper for the read-only filled form.
function renderEmployeeFilledFormSection(title, fieldsHtml, helperText = "") {
  return `
    <section class="border rounded-4 p-3 p-lg-4 bg-light-subtle mb-4">
      <div class="mb-3">
        <h3 class="h6 fw-bold mb-1">${escapeHtml(title)}</h3>
        ${helperText
      ? `<p class="text-secondary small mb-0">${escapeHtml(helperText)}</p>`
      : ""
    }
      </div>

      <div class="row g-3">
        ${fieldsHtml}
      </div>
    </section>
  `;
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 1A
// Render child rows such as addresses, education, beneficiaries, and documents.
function renderEmployeeFilledFormList(records = [], emptyText = "", renderRecord) {
  if (!Array.isArray(records) || records.length === 0) {
    return `
      <div class="alert alert-light border mb-0">
        ${escapeHtml(emptyText || "No records available.")}
      </div>
    `;
  }

  return `
    <div class="list-group">
      ${records
      .map((record) => `
          <div class="list-group-item">
            ${renderRecord(record)}
          </div>
        `)
      .join("")}
    </div>
  `;
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 1A
// Load the same child HR records that edit mode uses, but for read-only review.
// This keeps the modal aligned with the actual saved employee profile.
async function loadEmployeeFilledFormRelatedData(employeeId) {
  const employeeKey = String(employeeId || "").trim();

  if (!employeeKey) {
    return {
      addresses: [],
      nextOfKin: [],
      education: [],
      dependants: [],
      documents: [],
    };
  }

  const supabase = getSupabaseClient();

  const [
    addressesResult,
    nextOfKinResult,
    educationResult,
    dependantsResult,
    documentsResult,
  ] = await Promise.all([
    supabase
      .from("employee_addresses")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("address_type", { ascending: true })
      .order("created_at", { ascending: true }),

    supabase
      .from("employee_next_of_kin")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("is_primary", { ascending: false })
      .order("created_at", { ascending: true }),

    supabase
      .from("employee_education_records")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("is_highest_qualification", { ascending: false })
      .order("created_at", { ascending: true }),

    supabase
      .from("employee_dependants")
      .select("*")
      .eq("employee_id", employeeKey)
      .order("created_at", { ascending: true }),

    applyCurrentTenantFilter(
      supabase
        .from("employee_documents")
        .select("*")
        .eq("employee_id", employeeKey),
    ).order("uploaded_at", { ascending: false }),
  ]);

  const firstError =
    addressesResult.error ||
    nextOfKinResult.error ||
    educationResult.error ||
    dependantsResult.error ||
    documentsResult.error;

  if (firstError) {
    throw new Error(firstError.message || "Employee filled form details could not be loaded.");
  }

  return {
    addresses: Array.isArray(addressesResult.data) ? addressesResult.data : [],
    nextOfKin: Array.isArray(nextOfKinResult.data) ? nextOfKinResult.data : [],
    education: Array.isArray(educationResult.data) ? educationResult.data : [],
    dependants: Array.isArray(dependantsResult.data) ? dependantsResult.data : [],
    documents: Array.isArray(documentsResult.data) ? documentsResult.data : [],
  };
}

// HR EMPLOYEE RECORDS VIEW & EXPORT - STEP 1A
